import { useState, useCallback, useMemo } from 'react';

/** Authentication type for custom data sources. */
export type AuthType = 'none' | 'api-key' | 'basic' | 'bearer' | 'custom-header';

/** Protocol for custom WebSocket sources. */
export type WsProtocol = 'wss' | 'ws';

/** Data format for file imports. */
export type FileFormat = 'csv' | 'json' | 'parquet';

/** Base configuration shared by all custom source types. */
interface CustomSourceBase {
  readonly id: string;
  readonly name: string;
  readonly createdAt: number;
}

/** Custom WebSocket data source configuration. */
export interface CustomWebSocketSource extends CustomSourceBase {
  readonly type: 'websocket';
  readonly url: string;
  readonly protocol: WsProtocol;
  readonly authType: AuthType;
  readonly credentials: Readonly<Record<string, string>>;
  readonly fieldMapping: {
    readonly pricePath: string;
    readonly volumePath: string;
    readonly timestampPath: string;
    readonly symbolPath: string;
  };
}

/** Custom REST API data source configuration. */
export interface CustomRestApiSource extends CustomSourceBase {
  readonly type: 'rest-api';
  readonly url: string;
  readonly authType: AuthType;
  readonly credentials: Readonly<Record<string, string>>;
  readonly pollingIntervalMs: number;
  readonly fieldMapping: {
    readonly pricePath: string;
    readonly volumePath: string;
    readonly timestampPath: string;
    readonly symbolPath: string;
  };
}

/** Custom file import data source configuration. */
export interface CustomFileSource extends CustomSourceBase {
  readonly type: 'file-import';
  readonly fileName: string;
  readonly format: FileFormat;
  readonly columnMapping: {
    readonly priceColumn: string;
    readonly volumeColumn: string;
    readonly timestampColumn: string;
    readonly symbolColumn: string;
  };
}

/** Union type for all custom source configurations. */
export type CustomSource = CustomWebSocketSource | CustomRestApiSource | CustomFileSource;

/** Distributive Omit that preserves discriminated union members. */
type DistributiveOmit<T, K extends keyof T> = T extends unknown ? Omit<T, K> : never;

/** Input type for adding a new custom source (without auto-generated fields). */
export type NewCustomSource = DistributiveOmit<CustomSource, 'id' | 'createdAt'>;

/** State returned by the useCustomSources hook. */
export interface CustomSourcesState {
  /** All configured custom sources. */
  readonly sources: ReadonlyArray<CustomSource>;
  /** Add a new custom source. Returns the generated ID. */
  readonly addSource: (source: NewCustomSource) => string;
  /** Remove a custom source by ID. */
  readonly removeSource: (id: string) => void;
  /** Update an existing custom source. */
  readonly updateSource: (id: string, updates: Partial<Omit<CustomSource, 'id' | 'createdAt' | 'type'>>) => void;
}

/** Generate a unique ID for custom sources. */
function generateId(): string {
  return `custom-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
}

/** LocalStorage key for persisting custom source configurations. */
const STORAGE_KEY = 'deskmodal.feeds.customSources';

/** Load custom sources from localStorage. */
function loadFromStorage(): CustomSource[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
      return JSON.parse(raw) as CustomSource[];
    }
  } catch {
    // Corrupted storage is non-critical; start fresh
  }
  return [];
}

/** Save custom sources to localStorage. */
function saveToStorage(sources: CustomSource[]): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(sources));
  } catch {
    // Storage quota exceeded is non-critical
  }
}

/**
 * Hook managing custom data source configurations.
 *
 * Persists configurations to localStorage so they survive page reloads.
 * Provides add, remove, and update operations on the source list.
 */
export function useCustomSources(): CustomSourcesState {
  const [sources, setSources] = useState<CustomSource[]>(() => loadFromStorage());

  const addSource = useCallback(
    (source: NewCustomSource): string => {
      const id = generateId();
      const newSource = { ...source, id, createdAt: Date.now() } as CustomSource;

      setSources((prev) => {
        const next = [...prev, newSource];
        saveToStorage(next);
        return next;
      });

      return id;
    },
    [],
  );

  const removeSource = useCallback((id: string): void => {
    setSources((prev) => {
      const next = prev.filter((s) => s.id !== id);
      saveToStorage(next);
      return next;
    });
  }, []);

  const updateSource = useCallback(
    (id: string, updates: Partial<Omit<CustomSource, 'id' | 'createdAt' | 'type'>>): void => {
      setSources((prev) => {
        const next = prev.map((s) => (s.id === id ? { ...s, ...updates } : s));
        saveToStorage(next);
        return next;
      });
    },
    [],
  );

  return useMemo(
    () => ({ sources, addSource, removeSource, updateSource }),
    [sources, addSource, removeSource, updateSource],
  );
}
