import { useCallback, useMemo, type CSSProperties } from 'react';
import { Panel, VirtualList, IconButton, Button, EmptyState, Skeleton } from '../../primitives';
import { Check, Eye, Trash2, History } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  AlertHistoryPanel                                                         */
/*  History list of triggered alerts with acknowledge and view actions.        */
/*  Composes Phase 0 Panel, VirtualList, IconButton, EmptyState, Skeleton.    */
/*  Uses --ts-panel-*, --ts-border-* tokens.                                  */
/* -------------------------------------------------------------------------- */

export interface AlertHistoryEntry {
  id: string;
  alertId: string;
  symbol: string;
  condition: string;
  price: number;
  triggeredAt: string;
  acknowledged: boolean;
}

export interface AlertHistoryPanelProps {
  /** History entries sorted by triggeredAt (newest first). */
  entries: AlertHistoryEntry[];
  /** Called when an entry is acknowledged/dismissed. */
  onAcknowledge: (entryId: string) => void;
  /** Called when "View Alert" is clicked on an entry. */
  onViewAlert: (alertId: string) => void;
  /** Called when "Clear All" is clicked. */
  onClearAll: () => void;
  /** Whether the panel is in loading state. */
  loading?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-alert-history-panel-styles';

function ensureAlertHistoryPanelStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-alert-history-entry]:hover {
      background: oklch(0.50 0.005 260 / 0.04);
    }
    [data-ts-alert-history-entry] [data-ts-history-actions] {
      opacity: 0;
      transition: opacity 150ms;
    }
    [data-ts-alert-history-entry]:hover [data-ts-history-actions],
    [data-ts-alert-history-entry]:focus-within [data-ts-history-actions] {
      opacity: 1;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureAlertHistoryPanelStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const listContainerStyle: CSSProperties = {
  height: 400,
};

const entryStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 48,
  padding: '0 var(--ts-space-3)',
  borderBottom: '1px solid var(--ts-border-subtle)',
  transition: 'background 100ms',
  boxSizing: 'border-box',
};

const unacknowledgedDotStyle: CSSProperties = {
  width: 6,
  height: 6,
  borderRadius: '50%',
  background: 'var(--ts-accent-default)',
  flexShrink: 0,
  marginRight: 'var(--ts-space-2)',
};

const acknowledgedDotStyle: CSSProperties = {
  ...unacknowledgedDotStyle,
  background: 'transparent',
};

const infoStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  flex: 1,
  minWidth: 0,
  overflow: 'hidden',
};

const symbolRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const symbolStyle: CSSProperties = {
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-primary)',
  fontFamily: 'inherit',
};

const conditionStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-secondary)',
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  fontFamily: 'inherit',
};

const timestampStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  fontFamily: 'inherit',
  flexShrink: 0,
};

const priceStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  fontVariantNumeric: 'tabular-nums',
  color: 'var(--ts-text-primary)',
  fontFamily: 'inherit',
  padding: '0 var(--ts-space-2)',
  flexShrink: 0,
};

const actionsStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
  flexShrink: 0,
};

const skeletonRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 48,
  padding: '0 var(--ts-space-3)',
  gap: 'var(--ts-space-3)',
  borderBottom: '1px solid var(--ts-border-subtle)',
};

/* ----- Helpers ----------------------------------------------------------- */

function formatRelativeTime(isoTimestamp: string): string {
  const now = Date.now();
  const then = new Date(isoTimestamp).getTime();
  const diffMs = now - then;

  if (Number.isNaN(diffMs)) return isoTimestamp;

  const seconds = Math.floor(diffMs / 1000);
  if (seconds < 60) return `${seconds}s ago`;
  const minutes = Math.floor(seconds / 60);
  if (minutes < 60) return `${minutes}m ago`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h ago`;
  const days = Math.floor(hours / 24);
  if (days < 7) return `${days}d ago`;

  return new Date(isoTimestamp).toLocaleDateString(undefined, {
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

/* ----- Component --------------------------------------------------------- */

export function AlertHistoryPanel({
  entries,
  onAcknowledge,
  onViewAlert,
  onClearAll,
  loading = false,
}: AlertHistoryPanelProps): React.JSX.Element {
  const clearAllAction = useMemo(
    () => (
      <Button
        variant="ghost"
        size="sm"
        onClick={onClearAll}
        data-testid="clear-all"
      >
        <Trash2 size={14} style={{ marginRight: 'var(--ts-space-1)' }} />
        Clear All
      </Button>
    ),
    [onClearAll],
  );

  const renderEntry = useCallback(
    (entry: AlertHistoryEntry) => (
      <div
        key={entry.id}
        data-ts-alert-history-entry=""
        style={{
          ...entryStyle,
          fontWeight: entry.acknowledged ? 'normal' : ('var(--ts-font-weight-medium)' as unknown as number),
        }}
        data-testid="history-entry"
      >
        <span
          style={entry.acknowledged ? acknowledgedDotStyle : unacknowledgedDotStyle}
          data-testid={entry.acknowledged ? 'dot-acknowledged' : 'dot-unacknowledged'}
          aria-hidden="true"
        />
        <div style={infoStyle}>
          <div style={symbolRowStyle}>
            <span style={symbolStyle}>{entry.symbol}</span>
            <span style={timestampStyle}>{formatRelativeTime(entry.triggeredAt)}</span>
          </div>
          <span style={conditionStyle} title={entry.condition}>{entry.condition}</span>
        </div>
        <span style={priceStyle}>{entry.price.toLocaleString()}</span>
        <div data-ts-history-actions="" style={actionsStyle}>
          <IconButton
            icon={<Eye size={14} />}
            label="View alert"
            size="sm"
            variant="ghost"
            onClick={() => onViewAlert(entry.alertId)}
          />
          {!entry.acknowledged ? (
            <IconButton
              icon={<Check size={14} />}
              label="Dismiss"
              size="sm"
              variant="ghost"
              onClick={() => onAcknowledge(entry.id)}
            />
          ) : null}
        </div>
      </div>
    ),
    [onViewAlert, onAcknowledge],
  );

  if (loading) {
    return (
      <Panel title="Alert History" actions={clearAllAction}>
        <div data-ts-alert-history-panel="">
          {Array.from({ length: 5 }, (_, i) => (
            <div key={i} style={skeletonRowStyle} data-testid="skeleton-row">
              <Skeleton width={6} height={6} circle />
              <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 4 }}>
                <Skeleton width="60%" height={14} />
                <Skeleton width="80%" height={12} />
              </div>
              <Skeleton width={60} height={14} />
            </div>
          ))}
        </div>
      </Panel>
    );
  }

  if (entries.length === 0) {
    return (
      <Panel title="Alert History" actions={clearAllAction}>
        <div data-ts-alert-history-panel="">
          <EmptyState
            icon={<History size={32} />}
            title="No alert history"
            description="Triggered alerts will appear here."
          />
        </div>
      </Panel>
    );
  }

  const VIRTUALIZE_THRESHOLD = 50;
  const useVirtualization = entries.length > VIRTUALIZE_THRESHOLD;

  return (
    <Panel title="Alert History" actions={clearAllAction}>
      <div data-ts-alert-history-panel="" style={listContainerStyle}>
        {useVirtualization ? (
          <VirtualList
            items={entries}
            itemHeight={48}
            overscan={5}
            renderItem={renderEntry}
          />
        ) : (
          <div style={{ overflowY: 'auto', height: '100%' }}>
            {entries.map((entry) => renderEntry(entry))}
          </div>
        )}
      </div>
    </Panel>
  );
}

AlertHistoryPanel.displayName = 'AlertHistoryPanel';
