import { useCallback, useMemo, type CSSProperties } from 'react';
import { Panel, Tabs } from '../primitives';
import { formatCompactNumber } from '../financial';
import { SparklineChart } from './SparklineChart';
import type { WatchlistSymbol } from './WatchlistPanel';

/* -------------------------------------------------------------------------- */
/*  HotlistPanel                                                               */
/*  Ranked list of top movers by category: gainers, losers, volume, new.       */
/*  Uses --ts-hotlist-* tokens.                                                */
/* -------------------------------------------------------------------------- */

export type HotlistCategory = 'gainers' | 'losers' | 'volume' | 'new';

export interface HotlistPanelProps {
  /** Active hotlist category. */
  activeCategory: HotlistCategory;
  /** Called when the category tab changes. */
  onCategoryChange: (category: HotlistCategory) => void;
  /** Symbols to display (pre-sorted by the parent based on active category). */
  symbols: WatchlistSymbol[];
  /** Maximum number of symbols to show. Default 20. */
  limit?: number;
  /** Called when a symbol is clicked. */
  onSymbolSelect: (symbolId: string) => void;
  /** Display density mode. */
  densityMode: 'compact' | 'expanded';
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-hotlist-styles';

function ensureHotlistStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-hotlist-row]:hover {
      background: var(--ts-data-row-bg-hover);
    }
    [data-ts-hotlist-row]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureHotlistStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-watchlist-row-height)',
  padding: '0 var(--ts-watchlist-row-padding-x)',
  borderBottom: '1px solid var(--ts-watchlist-row-border)',
  cursor: 'pointer',
  userSelect: 'none',
  transition: 'background 100ms',
  gap: 'var(--ts-space-2)',
  boxSizing: 'border-box',
};

const rankStyle: CSSProperties = {
  width: 'var(--ts-hotlist-rank-width)',
  fontSize: 'var(--ts-hotlist-rank-font-size)',
  color: 'var(--ts-hotlist-rank-text)',
  fontVariantNumeric: 'tabular-nums',
  textAlign: 'center',
  flexShrink: 0,
};

const symbolCellStyle: CSSProperties = {
  flex: 1,
  display: 'flex',
  flexDirection: 'column',
  minWidth: 0,
  overflow: 'hidden',
};

const symbolTextStyle: CSSProperties = {
  color: 'var(--ts-watchlist-symbol-text)',
  fontWeight: 'var(--ts-watchlist-symbol-font-weight)' as unknown as number,
  fontSize: 'var(--ts-font-sm)',
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  lineHeight: 1.2,
};

const exchangeTextStyle: CSSProperties = {
  color: 'var(--ts-watchlist-exchange-text)',
  fontSize: 'var(--ts-watchlist-exchange-font-size)',
  lineHeight: 1.2,
};

const metricStyle: CSSProperties = {
  fontFamily: 'var(--ts-watchlist-price-font)',
  fontSize: 'var(--ts-font-sm)',
  fontVariantNumeric: 'tabular-nums',
  textAlign: 'right',
  whiteSpace: 'nowrap',
  minWidth: '72px',
};

const sparklineCellStyle: CSSProperties = {
  flexShrink: 0,
};

/* ----- Constants --------------------------------------------------------- */

const CATEGORY_LABELS: Record<HotlistCategory, string> = {
  gainers: 'Gainers',
  losers: 'Losers',
  volume: 'Volume',
  new: 'New',
};

const CATEGORIES: HotlistCategory[] = ['gainers', 'losers', 'volume', 'new'];

/* ----- Component --------------------------------------------------------- */

export function HotlistPanel({
  activeCategory,
  onCategoryChange,
  symbols,
  limit = 20,
  onSymbolSelect,
  densityMode,
}: HotlistPanelProps): React.JSX.Element {
  const visibleSymbols = useMemo(
    () => symbols.slice(0, limit),
    [symbols, limit],
  );

  const showSparklines = densityMode === 'expanded';

  const getMetricValue = useCallback(
    (sym: WatchlistSymbol): string => {
      if (activeCategory === 'volume' && sym.volume !== undefined) {
        return formatCompactNumber(sym.volume);
      }
      if (sym.priceChangePercent == null) return '--';
      const sign = sym.priceChangePercent > 0 ? '+' : '';
      return `${sign}${sym.priceChangePercent.toFixed(2)}%`;
    },
    [activeCategory],
  );

  const getMetricColor = useCallback(
    (sym: WatchlistSymbol): string => {
      if (activeCategory === 'volume') return 'var(--ts-text-primary)';
      if ((sym.priceChangePercent ?? 0) > 0) return 'var(--ts-price-change-up-text)';
      if ((sym.priceChangePercent ?? 0) < 0) return 'var(--ts-price-change-down-text)';
      return 'var(--ts-price-neutral-text)';
    },
    [activeCategory],
  );

  return (
    <div data-ts-hotlist-panel="" data-testid="hotlist-panel">
      <Panel title="Hotlist">
        <Tabs
          value={activeCategory}
          onValueChange={(v: string) => onCategoryChange(v as HotlistCategory)}
        >
          <Tabs.List data-testid="hotlist-tabs">
            {CATEGORIES.map((cat) => (
              <Tabs.Trigger key={cat} value={cat} data-testid={`hotlist-tab-${cat}`}>
                {CATEGORY_LABELS[cat]}
              </Tabs.Trigger>
            ))}
          </Tabs.List>
          {CATEGORIES.map((cat) => (
            <Tabs.Content key={cat} value={cat}>
              {activeCategory === cat && (
                <div data-testid="hotlist-list">
                  {visibleSymbols.map((sym, index) => (
                    <div
                      key={sym.id}
                      data-ts-hotlist-row=""
                      style={rowStyle}
                      role="row"
                      tabIndex={0}
                      onClick={() => onSymbolSelect(sym.id)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' || e.key === ' ') {
                          e.preventDefault();
                          onSymbolSelect(sym.id);
                        }
                      }}
                      data-testid="hotlist-row"
                    >
                      <span style={rankStyle} data-testid="hotlist-rank">
                        {index + 1}
                      </span>
                      <div style={symbolCellStyle}>
                        <span style={symbolTextStyle}>{sym.symbol}</span>
                        <span style={exchangeTextStyle}>{sym.exchange}</span>
                      </div>
                      <span
                        style={{ ...metricStyle, color: getMetricColor(sym) }}
                        data-testid="hotlist-metric"
                      >
                        {getMetricValue(sym)}
                      </span>
                      {showSparklines && sym.sparklineData !== undefined && sym.sparklineData.length >= 2 && (
                        <div style={sparklineCellStyle}>
                          <SparklineChart data={sym.sparklineData} width={60} height={20} showFill={false} />
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </Tabs.Content>
          ))}
        </Tabs>
      </Panel>
    </div>
  );
}

HotlistPanel.displayName = 'HotlistPanel';
