import { TrendingUp, TrendingDown } from 'lucide-react';
import { formatPrice } from './format-number';
import type { CSSProperties } from 'react';

/* -------------------------------------------------------------------------- */
/*  PriceChange                                                               */
/*  Absolute + percentage change display with directional coloring.           */
/*  Uses --ts-price-change-* tokens.                                          */
/* -------------------------------------------------------------------------- */

type PriceChangeSize = 'sm' | 'md' | 'lg';

export interface PriceChangeProps {
  /** Absolute change value. */
  value: number;
  /** Percentage change value. */
  percentage: number;
  /** Whether to show absolute change. */
  showAbsolute?: boolean;
  /** Whether to show percentage change. */
  showPercentage?: boolean;
  /** Display size variant. */
  size?: PriceChangeSize;
}

/* ----- Size map ---------------------------------------------------------- */

const SIZE_FONT: Record<PriceChangeSize, string> = {
  sm: 'var(--ts-font-xs)',
  md: 'var(--ts-price-change-font-size)',
  lg: 'var(--ts-font-md)',
};

const SIZE_ICON: Record<PriceChangeSize, number> = {
  sm: 12,
  md: 14,
  lg: 16,
};

/* ----- Direction helpers ------------------------------------------------- */

type Direction = 'up' | 'down' | 'neutral';

function getDirection(value: number): Direction {
  if (value > 0) return 'up';
  if (value < 0) return 'down';
  return 'neutral';
}

const DIRECTION_COLOR: Record<Direction, string> = {
  up: 'var(--ts-price-change-up-text)',
  down: 'var(--ts-price-change-down-text)',
  neutral: 'var(--ts-price-neutral-text)',
};

const DIRECTION_BG: Record<Direction, string> = {
  up: 'var(--ts-price-change-up-bg)',
  down: 'var(--ts-price-change-down-bg)',
  neutral: 'transparent',
};

/* ----- Component --------------------------------------------------------- */

export function PriceChange({
  value,
  percentage,
  showAbsolute = true,
  showPercentage = true,
  size = 'md',
}: PriceChangeProps): React.JSX.Element {
  const direction = getDirection(value);
  const sign = value > 0 ? '+' : '';

  const containerStyle: CSSProperties = {
    display: 'inline-flex',
    alignItems: 'center',
    gap: '4px',
    fontFamily: 'var(--ts-price-font)',
    fontSize: SIZE_FONT[size],
    fontVariantNumeric: 'tabular-nums',
    color: DIRECTION_COLOR[direction],
    background: DIRECTION_BG[direction],
    padding: '2px 6px',
    borderRadius: 'var(--ts-radius-sm)',
    lineHeight: 1.4,
  };

  const ArrowIcon =
    direction === 'up' ? TrendingUp : direction === 'down' ? TrendingDown : null;

  return (
    <span
      className="ts-data-value"
      style={containerStyle}
      data-direction={direction}
      data-testid="price-change"
    >
      {ArrowIcon !== null && (
        <ArrowIcon size={SIZE_ICON[size]} aria-hidden="true" />
      )}
      {showAbsolute && (
        <span data-testid="price-change-absolute">
          {sign}{formatPrice(Math.abs(value))}
        </span>
      )}
      {showPercentage && (
        <span data-testid="price-change-percentage">
          ({sign}{percentage.toFixed(2)}%)
        </span>
      )}
    </span>
  );
}

PriceChange.displayName = 'PriceChange';
