import { forwardRef, useMemo, type CSSProperties } from 'react';

/* -------------------------------------------------------------------------- */
/*  ColorScaleLegend                                                          */
/*  CSS gradient bar with positioned labels for data visualization legends.   */
/*  Uses --ts-color-scale-* tokens.                                           */
/* -------------------------------------------------------------------------- */

export interface ColorStop {
  /** Numeric value at this stop (e.g., -3, -2, -1, 0, 1, 2, 3). */
  value: number;
  /** CSS color string (OKLCH or hex). */
  color: string;
}

export interface ColorScaleLegendProps {
  /** Color stops defining the gradient. Minimum 2. */
  stops: ColorStop[];
  /** Format function for stop labels (e.g., (v) => `${v}%`). */
  formatLabel?: (value: number) => string;
  /** Title text (e.g., "24h Change %"). */
  title?: string;
  /** Orientation. */
  orientation?: 'horizontal' | 'vertical';
  /** Width of the legend (for horizontal) or height (for vertical). */
  size?: number;
}

/* ----- Styles ------------------------------------------------------------ */

const titleStyle: CSSProperties = {
  color: 'var(--ts-color-scale-label-text)',
  fontSize: 'var(--ts-color-scale-label-font-size)',
  marginBottom: 'var(--ts-space-1)',
};

const labelsContainerStyle: CSSProperties = {
  display: 'flex',
  justifyContent: 'space-between',
  marginTop: 'var(--ts-space-1)',
};

const labelStyle: CSSProperties = {
  color: 'var(--ts-color-scale-label-text)',
  fontSize: 'var(--ts-color-scale-label-font-size)',
  fontVariantNumeric: 'tabular-nums slashed-zero',
  fontFeatureSettings: "'tnum' 1, 'zero' 1",
  whiteSpace: 'nowrap',
};

const verticalLabelsContainerStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  justifyContent: 'space-between',
  marginLeft: 'var(--ts-space-1)',
};

function defaultFormatLabel(value: number): string {
  return String(value);
}

export const ColorScaleLegend = forwardRef<HTMLDivElement, ColorScaleLegendProps>(
  function ColorScaleLegend(
    {
      stops,
      formatLabel = defaultFormatLabel,
      title,
      orientation = 'horizontal',
      size,
    },
    ref,
  ) {
    const isHorizontal = orientation === 'horizontal';

    const gradientCss = useMemo(() => {
      if (stops.length < 2) return 'transparent';
      const sorted = [...stops].sort((a, b) => a.value - b.value);
      const min = sorted[0]!.value;
      const max = sorted[sorted.length - 1]!.value;
      const range = max - min;

      const colorStops = sorted.map((stop) => {
        const percent = range === 0 ? 0 : ((stop.value - min) / range) * 100;
        return `${stop.color} ${percent.toFixed(1)}%`;
      });

      const direction = isHorizontal ? 'to right' : 'to bottom';
      return `linear-gradient(${direction}, ${colorStops.join(', ')})`;
    }, [stops, isHorizontal]);

    const sortedStops = useMemo(
      () => [...stops].sort((a, b) => a.value - b.value),
      [stops],
    );

    const barStyle: CSSProperties = isHorizontal
      ? {
          width: size !== undefined ? size : '100%',
          height: 'var(--ts-color-scale-height)',
          borderRadius: 'var(--ts-color-scale-radius)',
          background: gradientCss,
        }
      : {
          width: 'var(--ts-color-scale-height)',
          height: size !== undefined ? size : '100%',
          borderRadius: 'var(--ts-color-scale-radius)',
          background: gradientCss,
        };

    const rootContainerStyle: CSSProperties = isHorizontal
      ? { display: 'flex', flexDirection: 'column' }
      : { display: 'flex', flexDirection: 'row' };

    return (
      <div ref={ref} data-ts-color-scale-legend="" style={rootContainerStyle}>
        {isHorizontal ? (
          <>
            {title !== undefined && <div style={titleStyle}>{title}</div>}
            <div style={barStyle} role="img" aria-label={title ?? 'Color scale'} />
            <div style={labelsContainerStyle}>
              {sortedStops.map((stop) => (
                <span key={stop.value} style={labelStyle}>
                  {formatLabel(stop.value)}
                </span>
              ))}
            </div>
          </>
        ) : (
          <>
            <div style={{ display: 'flex', flexDirection: 'column' }}>
              {title !== undefined && <div style={titleStyle}>{title}</div>}
              <div style={barStyle} role="img" aria-label={title ?? 'Color scale'} />
            </div>
            <div style={verticalLabelsContainerStyle}>
              {sortedStops.map((stop) => (
                <span key={stop.value} style={labelStyle}>
                  {formatLabel(stop.value)}
                </span>
              ))}
            </div>
          </>
        )}
      </div>
    );
  },
);

ColorScaleLegend.displayName = 'ColorScaleLegend';
