import { forwardRef, type CSSProperties, type ReactNode } from 'react';
import { Panel } from '../../primitives';
import { MetricDashboard } from './MetricDashboard';

/* -------------------------------------------------------------------------- */
/*  OnChainMetricsPanel                                                       */
/*  Panel wrapping MetricDashboard for on-chain metrics display.              */
/*  Uses --ts-metric-card-* tokens via MetricDashboard/MetricCard.            */
/* -------------------------------------------------------------------------- */

export interface OnChainMetric {
  id: string;
  label: string;
  value: number;
  unit: string;
  changePercent: number;
  sparklineData?: number[];
  icon?: ReactNode;
}

export interface OnChainMetricsPanelProps {
  /** Panel title. */
  title?: string;
  /** Metrics to display. */
  metrics: OnChainMetric[];
  /** Called when a metric card is clicked. */
  onMetricClick?: (metricId: string) => void;
  /** Whether all metrics are loading. */
  loading?: boolean;
  /** Size variant. */
  size?: 'compact' | 'default';
  /** Instrument context (e.g., "BTC"). */
  instrument?: string;
}

/* ----- Styles ------------------------------------------------------------ */

const instrumentLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-tertiary)',
  marginLeft: 'var(--ts-space-2)',
};

export const OnChainMetricsPanel = forwardRef<HTMLDivElement, OnChainMetricsPanelProps>(
  function OnChainMetricsPanel(
    {
      title = 'On-Chain Metrics',
      metrics,
      onMetricClick,
      loading = false,
      size = 'default',
      instrument,
    },
    ref,
  ) {
    const dashboardMetrics = metrics.map((m) => ({
      id: m.id,
      label: m.label,
      value: m.value,
      changePercent: m.changePercent,
      unit: m.unit,
      sparklineData: m.sparklineData,
      icon: m.icon,
      onClick: onMetricClick !== undefined ? () => onMetricClick(m.id) : undefined,
    }));

    return (
      <div ref={ref} data-ts-on-chain-metrics-panel="">
        <Panel
          title={title}
          actions={
            instrument !== undefined ? (
              <span style={instrumentLabelStyle}>{instrument}</span>
            ) : undefined
          }
        >
          <MetricDashboard
            metrics={dashboardMetrics}
            loading={loading}
            size={size}
          />
        </Panel>
      </div>
    );
  },
);

OnChainMetricsPanel.displayName = 'OnChainMetricsPanel';
