import { type CSSProperties, type ReactNode, useCallback } from 'react';
import { X } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  Tag                                                                       */
/*  Removable label for filters and selections.                               */
/*  Uses --ts-tag-* tokens.                                                   */
/* -------------------------------------------------------------------------- */

/* ----- Style injection for hover X icon ---------------------------------- */

const TAG_STYLE_ID = 'ts-tag-styles';

function ensureTagStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(TAG_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = TAG_STYLE_ID;
  sheet.textContent = `
    [data-ts-tag-remove] {
      color: var(--ts-tag-remove-icon);
      opacity: 0;
      transition: opacity 150ms, color 150ms;
    }
    [data-ts-tag]:hover [data-ts-tag-remove] {
      opacity: 1;
    }
    [data-ts-tag-remove]:hover {
      color: var(--ts-tag-remove-icon-hover) !important;
    }
    [data-ts-tag-remove]:focus-visible {
      opacity: 1;
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -1px;
      border-radius: var(--ts-radius-sm);
    }
    [data-ts-tag-disabled] [data-ts-tag-remove] {
      display: none;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureTagStyles();
}

/* ----- Props ------------------------------------------------------------- */

interface TagProps {
  /** Tag content. */
  children: ReactNode;
  /** Callback when the remove button is clicked. Presence enables the remove button. */
  onRemove?: () => void;
  /** Disables the tag and hides the remove button. */
  disabled?: boolean;
}

const tagStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
  height: 'var(--ts-tag-height)',
  padding: `0 var(--ts-tag-padding-x)`,
  background: 'var(--ts-tag-bg)',
  color: 'var(--ts-tag-text)',
  border: '1px solid var(--ts-tag-border)',
  borderRadius: 'var(--ts-tag-radius)',
  fontSize: 'var(--ts-tag-font-size)',
  fontFamily: 'inherit',
  lineHeight: 1,
  whiteSpace: 'nowrap',
  userSelect: 'none',
  boxSizing: 'border-box',
};

const disabledTagStyle: CSSProperties = {
  ...tagStyle,
  opacity: 0.5,
  cursor: 'default',
};

const removeButtonStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  cursor: 'pointer',
  padding: 0,
  marginLeft: 'var(--ts-space-1)',
  flexShrink: 0,
};

export function Tag({ children, onRemove, disabled = false }: TagProps): React.JSX.Element {
  const handleRemove = useCallback(() => {
    if (!disabled && onRemove) {
      onRemove();
    }
  }, [disabled, onRemove]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLButtonElement>) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        handleRemove();
      }
    },
    [handleRemove],
  );

  return (
    <span
      data-ts-tag=""
      {...(disabled ? { 'data-ts-tag-disabled': '' } : {})}
      style={disabled ? disabledTagStyle : tagStyle}
    >
      <span>{children}</span>
      {onRemove !== undefined && (
        <button
          type="button"
          data-ts-tag-remove=""
          style={removeButtonStyle}
          onClick={handleRemove}
          onKeyDown={handleKeyDown}
          disabled={disabled}
          aria-label="Remove"
          tabIndex={disabled ? -1 : 0}
        >
          <X size={12} aria-hidden />
        </button>
      )}
    </span>
  );
}

Tag.displayName = 'Tag';
