import type { Context } from '@deskmodal/fdc3';
import {
  initPriceBridge,
  onPriceUpdate as sharedOnPriceUpdate,
  initStatusBridge,
  onStatusUpdate as sharedOnStatusUpdate,
  type PriceTick,
  type FeedStatus,
} from '@deskmodal/data-layer';
import { getFeedManager } from './feed-manager';

/* -------------------------------------------------------------------------- */
/*  Feed Service                                                               */
/*  Delegates to the shared price/status bridges in @deskmodal/data-layer.  */
/*  No direct FDC3 channel management — the bridges handle that.               */
/* -------------------------------------------------------------------------- */

/** Structured log helper — routes to DeskModal logging if available. */
function structuredLog(level: 'error' | 'warn' | 'info', message: string): void {
  const win = window as { deskmodal?: { log?: (level: string, msg: string) => void } };
  if (win.deskmodal?.log) {
    win.deskmodal.log(level, message);
  }
}

/** Whether initialization has already been triggered. */
let initStarted = false;

/** Status update callback registered by hooks. */
type StatusCallback = (status: FeedStatus) => void;
const statusCallbacks = new Set<StatusCallback>();

/** Price update callback registered by hooks (receives raw Context for legacy compat). */
type PriceCallback = (context: Context) => void;
const priceCallbacks = new Set<PriceCallback>();

/** Register a callback for feed status updates. Returns an unsubscribe function. */
export function onStatusUpdate(callback: StatusCallback): () => void {
  statusCallbacks.add(callback);
  return () => {
    statusCallbacks.delete(callback);
  };
}

/**
 * Register a callback for price tick updates. Returns an unsubscribe function.
 *
 * For backward compatibility, this still receives a Context-shaped object.
 * New code should prefer `onPriceUpdate` from `@deskmodal/data-layer`
 * which provides a parsed `PriceTick` directly.
 */
export function onPriceUpdate(callback: PriceCallback): () => void {
  priceCallbacks.add(callback);
  return () => {
    priceCallbacks.delete(callback);
  };
}

/**
 * Initialize the feed service. Idempotent.
 *
 * Delegates to the shared price and status bridges in data-layer,
 * then wires up feeds-app-specific logic (FeedManager status updates,
 * forwarding to local callbacks).
 */
export function initFeedService(): void {
  if (initStarted) return;
  initStarted = true;

  // Initialize shared bridges (each is idempotent)
  initPriceBridge();
  initStatusBridge();

  const manager = getFeedManager();

  // Wire status updates to the FeedManager and local callbacks
  sharedOnStatusUpdate((status: FeedStatus) => {
    manager.applyStatusUpdate(status);
    for (const cb of statusCallbacks) {
      try {
        cb(status);
      } catch (e) {
        structuredLog('error', `[feed-service] Status callback error: ${String(e)}`);
      }
    }
  });

  // Wire price updates to local callbacks (Context-shaped for legacy compat)
  sharedOnPriceUpdate((tick: PriceTick) => {
    // Reconstruct a Context-shaped object for legacy consumers in this app
    const context: Context = {
      type: 'deskmodal.quote',
      id: { ticker: tick.symbol },
      last: tick.last,
      bid: tick.bid,
      ask: tick.ask,
      spread: tick.spread,
      exchange: tick.exchangeId,
      timestamp: tick.timestamp,
      volume24h: tick.volume24h,
      changePercent24h: tick.changePercent24h,
      high24h: tick.high24h,
      low24h: tick.low24h,
      bestBidQty: tick.bestBidQty,
      bestAskQty: tick.bestAskQty,
      quoteVolume24h: tick.quoteVolume24h,
      sequence: tick.sequence,
    } as unknown as Context;

    for (const cb of priceCallbacks) {
      try {
        cb(context);
      } catch (e) {
        structuredLog('error', `[feed-service] Price callback error: ${String(e)}`);
      }
    }
  });
}

// Re-export getFeedManager for convenience
export { getFeedManager } from './feed-manager';
