import type { ExchangeId } from '../types/normalized';
import type { HealthMetrics } from '../types/adapter';
import type { DataQualityScore } from '../types/aggregation';

/** DQS weight factors summing to 1.0. */
export const DQS_WEIGHTS = {
  latency: 0.30,
  uptime: 0.25,
  priceAgreement: 0.20,
  completeness: 0.15,
  volumeLegitimacy: 0.10,
} as const;

/** Configuration for DQS scoring thresholds. */
export interface DQSConfig {
  /** Latency in ms considered "perfect" (score 100). Default: 10 */
  readonly perfectLatencyMs: number;
  /** Latency in ms considered "poor" (score 0). Default: 1000 */
  readonly poorLatencyMs: number;
  /** Volume ratio threshold below which legitimacy starts declining. Default: 0.05 */
  readonly minVolumeShareForLegitimacy: number;
}

const DEFAULT_DQS_CONFIG: DQSConfig = {
  perfectLatencyMs: 10,
  poorLatencyMs: 1000,
  minVolumeShareForLegitimacy: 0.05,
};

/** Input data for computing a DQS for one exchange. */
export interface DQSInput {
  /** Exchange identifier. */
  readonly exchangeId: ExchangeId;
  /** Health metrics from the adapter. */
  readonly health: HealthMetrics;
  /** Absolute deviation of this exchange's price from VWAP, as a percentage. */
  readonly priceDeviationPercent: number;
  /** Number of data types this exchange provides (out of 4: ticker, orderbook, trades, ohlcv). */
  readonly dataTypesProvided: number;
  /** Maximum possible data types (typically 4). */
  readonly maxDataTypes: number;
  /** This exchange's 24h volume share across all exchanges (0-1). */
  readonly volumeShare: number;
}

/**
 * Compute the Data Quality Score for a single exchange.
 *
 * DQS is a composite score (0-100) with weighted factors:
 * - Latency: 30% — lower is better (perfect ≤10ms, poor ≥1000ms)
 * - Uptime: 25% — percentage of time the exchange has been connected
 * - Price Agreement: 20% — how close the exchange's price is to VWAP
 * - Completeness: 15% — fraction of data types provided
 * - Volume Legitimacy: 10% — whether volume share is reasonable
 */
export function computeDQS(
  input: DQSInput,
  config: Partial<DQSConfig> = {},
): DataQualityScore {
  const cfg = { ...DEFAULT_DQS_CONFIG, ...config };

  const latency = scoreLatency(input.health.latencyMs, cfg);
  const uptime = Math.min(100, Math.max(0, input.health.uptimePercent));
  const priceAgreement = scorePriceAgreement(input.priceDeviationPercent);
  const completeness = input.maxDataTypes > 0
    ? (input.dataTypesProvided / input.maxDataTypes) * 100
    : 0;
  const volumeLegitimacy = scoreVolumeLegitimacy(input.volumeShare, cfg);

  const overall =
    latency * DQS_WEIGHTS.latency +
    uptime * DQS_WEIGHTS.uptime +
    priceAgreement * DQS_WEIGHTS.priceAgreement +
    completeness * DQS_WEIGHTS.completeness +
    volumeLegitimacy * DQS_WEIGHTS.volumeLegitimacy;

  return {
    overall: clamp(overall),
    latency: clamp(latency),
    uptime: clamp(uptime),
    priceAgreement: clamp(priceAgreement),
    completeness: clamp(completeness),
    volumeLegitimacy: clamp(volumeLegitimacy),
    computedAt: Date.now(),
  };
}

/**
 * Compute the aggregate DQS for a symbol across multiple exchanges,
 * using volume-weighted averaging of individual exchange scores.
 */
export function computeAggregatedDQS(
  scores: ReadonlyArray<{ score: DataQualityScore; volumeWeight: number }>,
): DataQualityScore | null {
  if (scores.length === 0) return null;

  const totalWeight = scores.reduce((sum, s) => sum + s.volumeWeight, 0);
  if (totalWeight === 0) {
    // Equal weight fallback
    const avg = (field: keyof Omit<DataQualityScore, 'computedAt'>) =>
      scores.reduce((sum, s) => sum + s.score[field], 0) / scores.length;

    return {
      overall: clamp(avg('overall')),
      latency: clamp(avg('latency')),
      uptime: clamp(avg('uptime')),
      priceAgreement: clamp(avg('priceAgreement')),
      completeness: clamp(avg('completeness')),
      volumeLegitimacy: clamp(avg('volumeLegitimacy')),
      computedAt: Date.now(),
    };
  }

  const weighted = (field: keyof Omit<DataQualityScore, 'computedAt'>) =>
    scores.reduce((sum, s) => sum + s.score[field] * s.volumeWeight, 0) / totalWeight;

  return {
    overall: clamp(weighted('overall')),
    latency: clamp(weighted('latency')),
    uptime: clamp(weighted('uptime')),
    priceAgreement: clamp(weighted('priceAgreement')),
    completeness: clamp(weighted('completeness')),
    volumeLegitimacy: clamp(weighted('volumeLegitimacy')),
    computedAt: Date.now(),
  };
}

/** Convert an overall DQS (0-100) to a star rating (1-5). */
export function dqsToStarRating(overall: number): number {
  if (overall >= 90) return 5;
  if (overall >= 75) return 4;
  if (overall >= 55) return 3;
  if (overall >= 35) return 2;
  return 1;
}

function scoreLatency(latencyMs: number, config: DQSConfig): number {
  if (latencyMs <= config.perfectLatencyMs) return 100;
  if (latencyMs >= config.poorLatencyMs) return 0;
  const range = config.poorLatencyMs - config.perfectLatencyMs;
  return ((config.poorLatencyMs - latencyMs) / range) * 100;
}

function scorePriceAgreement(deviationPercent: number): number {
  const absDeviation = Math.abs(deviationPercent);
  if (absDeviation <= 0.01) return 100;
  if (absDeviation >= 2.0) return 0;
  // Linear interpolation between 0.01% and 2.0%
  return ((2.0 - absDeviation) / (2.0 - 0.01)) * 100;
}

function scoreVolumeLegitimacy(volumeShare: number, config: DQSConfig): number {
  if (volumeShare >= config.minVolumeShareForLegitimacy) return 100;
  if (volumeShare <= 0) return 0;
  return (volumeShare / config.minVolumeShareForLegitimacy) * 100;
}

function clamp(value: number): number {
  return Math.round(Math.min(100, Math.max(0, value)) * 100) / 100;
}
