import {
  useState,
  useCallback,
  useEffect,
  useRef,
  type CSSProperties,
  type ReactNode,
  type KeyboardEvent,
} from 'react';
import { Dialog, Tabs, Input, Badge, ScrollArea } from '../primitives';
import { Search, Star } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  IndicatorBrowserDialog                                                    */
/*  Dialog for browsing, searching, and adding technical indicators.           */
/*  Uses --ts-dialog-*, --ts-command-*, --ts-settings-panel-* tokens.         */
/* -------------------------------------------------------------------------- */

export interface IndicatorDefinition {
  /** Unique indicator identifier. */
  id: string;
  /** Display name. */
  name: string;
  /** Category (e.g., "Trend", "Momentum", "Volume", "Volatility"). */
  category: string;
  /** Short description. */
  description?: string;
  /** Whether this indicator is favorited by the user. */
  favorited?: boolean;
  /** Tags for searching. */
  tags?: string[];
}

export interface IndicatorCategory {
  /** Category identifier. */
  id: string;
  /** Display label. */
  label: string;
  /** Icon element. */
  icon: ReactNode;
}

export interface IndicatorBrowserDialogProps {
  /** Whether the dialog is open. */
  open: boolean;
  /** Called when the open state changes. */
  onOpenChange: (open: boolean) => void;
  /** Called when an indicator is selected (added to chart). */
  onIndicatorSelect: (indicatorId: string) => void;
  /** Called when an indicator is toggled as favorite. */
  onFavoriteToggle?: (indicatorId: string) => void;
  /** All available indicators. */
  indicators: IndicatorDefinition[];
  /** Categories for the left sidebar. */
  categories: IndicatorCategory[];
  /** Active category filter. */
  activeCategory: string;
  /** Called when the active category changes. */
  onCategoryChange: (categoryId: string) => void;
  /** Search query. */
  query: string;
  /** Called when the search query changes. */
  onQueryChange: (query: string) => void;
  /** Active content tab ("indicators" | "strategies"). */
  activeTab?: 'indicators' | 'strategies';
  /** Called when the content tab changes. */
  onTabChange?: (tab: 'indicators' | 'strategies') => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-indicator-browser-styles';

function ensureIndicatorBrowserStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-indicator-browser-sidebar-item]:hover {
      background: var(--ts-command-item-bg-hover);
    }
    [data-ts-indicator-browser-sidebar-item]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-indicator-browser-sidebar-item][data-active] {
      background: var(--ts-command-item-bg-selected);
      color: var(--ts-accent-default);
      font-weight: var(--ts-font-weight-medium);
      border-left: 2px solid var(--ts-accent-default);
    }
    [data-ts-indicator-browser-item]:hover {
      background: var(--ts-command-item-bg-hover);
    }
    [data-ts-indicator-browser-item]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-indicator-browser-star]:hover {
      color: var(--ts-accent-default);
    }
    [data-ts-indicator-browser-star]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 1px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureIndicatorBrowserStyles();
}

