/* ----- Component --------------------------------------------------------- */

export function IndicatorBrowserDialog({
  open,
  onOpenChange,
  onIndicatorSelect,
  onFavoriteToggle,
  indicators,
  categories,
  activeCategory,
  onCategoryChange,
  query,
  onQueryChange,
  activeTab = 'indicators',
  onTabChange,
}: IndicatorBrowserDialogProps): React.JSX.Element {
  const inputRef = useRef<HTMLInputElement>(null);

  const filteredIndicators = indicators.filter((ind) => {
    if (activeCategory === 'favorites') return ind.favorited;
    if (activeCategory !== 'all' && ind.category !== activeCategory) return false;
    if (query.length > 0) {
      const q = query.toLowerCase();
      const matchesName = ind.name.toLowerCase().includes(q);
      const matchesTags = ind.tags?.some((t) => t.toLowerCase().includes(q));
      return matchesName || matchesTags;
    }
    return true;
  });

  useEffect(() => {
    if (open) {
      requestAnimationFrame(() => {
        inputRef.current?.focus();
      });
    }
  }, [open]);

  const handleStarClick = useCallback((e: React.MouseEvent, indicatorId: string) => {
    e.stopPropagation();
    onFavoriteToggle?.(indicatorId);
  }, [onFavoriteToggle]);

  const renderIndicatorItem = useCallback((item: IndicatorDefinition, _index: number) => (
    <div
      key={item.id}
      data-ts-indicator-browser-item=""
      role="option"
      tabIndex={-1}
      style={indicatorItemStyle}
      onClick={() => onIndicatorSelect(item.id)}
    >
      <span style={indicatorNameStyle}>{item.name}</span>
      {item.description ? (
        <span style={indicatorDescStyle}>{item.description}</span>
      ) : (
        <span style={{ flex: 1 }} />
      )}
      {onFavoriteToggle ? (
        <button
          type="button"
          data-ts-indicator-browser-star=""
          aria-label={item.favorited ? `Remove ${item.name} from favorites` : `Add ${item.name} to favorites`}
          style={{
            ...starButtonStyle,
            color: item.favorited ? 'var(--ts-accent-default)' : 'var(--ts-text-tertiary)',
          }}
          onClick={(e) => handleStarClick(e, item.id)}
        >
          <Star size={14} fill={item.favorited ? 'currentColor' : 'none'} />
        </button>
      ) : null}
    </div>
  ), [onIndicatorSelect, onFavoriteToggle, handleStarClick]);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <Dialog.Content
        data-ts-indicator-browser=""
        style={dialogContentStyle}
        showClose
        aria-describedby={undefined}
      >
        <Dialog.Title style={visuallyHiddenStyle}>Indicator Browser</Dialog.Title>
        {/* Search bar */}
        <div style={searchBarStyle}>
          <Search size={16} style={searchIconStyle} aria-hidden />
          <Input
            ref={inputRef}
            size="md"
            value={query}
            onChange={(e) => onQueryChange(e.target.value)}
            placeholder="Search indicators..."
            aria-label="Search indicators"
            style={{
              flex: 1,
              border: 'none',
              background: 'transparent',
              outline: 'none',
            }}
          />
        </div>

        {/* Body: sidebar + content */}
        <div style={bodyStyle}>
          {/* Sidebar */}
          <div style={sidebarStyle} data-ts-indicator-browser-sidebar="" role="navigation" aria-label="Indicator categories">
            <div style={sidebarScrollStyle}>
              {categories.map((cat) => (
                <button
                  key={cat.id}
                  type="button"
                  data-ts-indicator-browser-sidebar-item=""
                  {...(activeCategory === cat.id ? { 'data-active': '' } : {})}
                  aria-current={activeCategory === cat.id ? 'true' : undefined}
                  style={sidebarItemStyle}
                  onClick={() => onCategoryChange(cat.id)}
                >
                  <span style={sidebarIconStyle}>{cat.icon}</span>
                  {cat.label}
                </button>
              ))}
            </div>
          </div>

          {/* Content */}
          <div style={contentAreaStyle}>
            {/* Tab bar */}
            <div style={tabBarStyle}>
              <Tabs value={activeTab} onValueChange={(v) => onTabChange?.(v as 'indicators' | 'strategies')}>
                <Tabs.List>
                  <Tabs.Trigger value="indicators">Indicators</Tabs.Trigger>
                  <Tabs.Trigger value="strategies">Strategies</Tabs.Trigger>
                </Tabs.List>
              </Tabs>
            </div>

            {/* Indicator list */}
            <div style={listContainerStyle} role="listbox" aria-label="Indicator list">
              {filteredIndicators.length === 0 ? (
                <div style={emptyStateStyle}>
                  {query.length > 0 ? 'No indicators found' : 'No indicators in this category'}
                </div>
              ) : (
                <div style={scrollListStyle}>
                  <ScrollArea>
                    {filteredIndicators.map((item, index) => renderIndicatorItem(item, index))}
                  </ScrollArea>
                </div>
              )}
            </div>
          </div>
        </div>
      </Dialog.Content>
    </Dialog>
  );
}

IndicatorBrowserDialog.displayName = 'IndicatorBrowserDialog';
