import { useCallback, type CSSProperties, type KeyboardEvent } from 'react';
import { List, BarChart3, AlignLeft } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  OrderBookViewMode                                                          */
/*  Three-button toggle group for order book display modes.                    */
/*  Uses --ts-button-ghost-* tokens for toggle styling.                        */
/* -------------------------------------------------------------------------- */

export type ViewMode = 'default' | 'cumulative' | 'depth-bars';

export interface OrderBookViewModeProps {
  /** Current view mode. */
  value: ViewMode;
  /** Called when view mode changes. */
  onValueChange: (mode: ViewMode) => void;
}

/* ----- Style injection --------------------------------------------------- */

const VIEW_MODE_STYLE_ID = 'ts-ob-view-mode-styles';

function ensureViewModeStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(VIEW_MODE_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = VIEW_MODE_STYLE_ID;
  sheet.textContent = `
    [data-ts-ob-view-mode-btn]:not([data-active]):hover {
      background: var(--ts-button-ghost-bg-hover);
      color: var(--ts-button-ghost-text-hover);
    }
    [data-ts-ob-view-mode-btn]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureViewModeStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const groupStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '1px',
  borderRadius: 'var(--ts-radius-sm)',
  overflow: 'hidden',
};

const MODES: { mode: ViewMode; label: string; Icon: typeof List }[] = [
  { mode: 'default', label: 'Price and size', Icon: List },
  { mode: 'cumulative', label: 'Cumulative total', Icon: BarChart3 },
  { mode: 'depth-bars', label: 'Depth bars', Icon: AlignLeft },
];

function getButtonStyle(active: boolean): CSSProperties {
  return {
    all: 'unset',
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    width: 'var(--ts-icon-button-size-sm)',
    height: 'var(--ts-icon-button-size-sm)',
    borderRadius: 'var(--ts-button-radius)',
    background: active
      ? 'var(--ts-button-ghost-bg-active)'
      : 'var(--ts-button-ghost-bg)',
    color: active
      ? 'var(--ts-text-primary)'
      : 'var(--ts-text-secondary)',
    cursor: 'pointer',
    transition: 'background 100ms, color 100ms',
    boxSizing: 'border-box',
  };
}

/* ----- Component --------------------------------------------------------- */

export function OrderBookViewMode({
  value,
  onValueChange,
}: OrderBookViewModeProps): React.JSX.Element {
  const handleKeyDown = useCallback(
    (e: KeyboardEvent<HTMLDivElement>) => {
      const currentIdx = MODES.findIndex((m) => m.mode === value);
      if (e.key === 'ArrowRight' || e.key === 'ArrowDown') {
        e.preventDefault();
        const nextIdx = (currentIdx + 1) % MODES.length;
        onValueChange(MODES[nextIdx]!.mode);
      } else if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') {
        e.preventDefault();
        const prevIdx = (currentIdx - 1 + MODES.length) % MODES.length;
        onValueChange(MODES[prevIdx]!.mode);
      }
    },
    [value, onValueChange],
  );

  return (
    <div
      data-ts-ob-view-mode=""
      role="radiogroup"
      aria-label="Order book view mode"
      style={groupStyle}
      onKeyDown={handleKeyDown}
      data-testid="ob-view-mode"
    >
      {MODES.map(({ mode, label, Icon }) => {
        const active = value === mode;
        return (
          <button
            key={mode}
            type="button"
            role="radio"
            data-ts-ob-view-mode-btn=""
            {...(active ? { 'data-active': '' } : {})}
            aria-checked={active}
            aria-label={label}
            tabIndex={active ? 0 : -1}
            style={getButtonStyle(active)}
            onClick={() => onValueChange(mode)}
            data-testid={`ob-view-mode-${mode}`}
          >
            <Icon size={14} aria-hidden />
          </button>
        );
      })}
    </div>
  );
}

OrderBookViewMode.displayName = 'OrderBookViewMode';
