import type { CSSProperties, ReactNode } from 'react';

/* -------------------------------------------------------------------------- */
/*  EmptyState                                                                */
/*  Zero-data display with icon, title, description, and optional action.     */
/*  Uses --ts-empty-state-* tokens.                                           */
/* -------------------------------------------------------------------------- */

interface EmptyStateProps {
  /** Icon element displayed above the title. */
  icon: ReactNode;
  /** Primary heading text. */
  title: string;
  /** Descriptive text below the title. */
  description: string;
  /** Optional action slot (typically a button). */
  action?: ReactNode;
}

const containerStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  textAlign: 'center',
  padding: 'var(--ts-space-8)',
  gap: 'var(--ts-space-3)',
};

const iconWrapperStyle: CSSProperties = {
  color: 'var(--ts-empty-state-icon)',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  marginBottom: 'var(--ts-space-1)',
};

const titleStyle: CSSProperties = {
  margin: 0,
  fontSize: 'var(--ts-font-lg)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  color: 'var(--ts-empty-state-text)',
  fontFamily: 'inherit',
  lineHeight: 1.4,
};

const descriptionStyle: CSSProperties = {
  margin: 0,
  fontSize: 'var(--ts-font-md)',
  color: 'var(--ts-empty-state-subtext)',
  fontFamily: 'inherit',
  lineHeight: 1.5,
  maxWidth: 320,
};

const actionWrapperStyle: CSSProperties = {
  marginTop: 'var(--ts-space-2)',
};

export function EmptyState({ icon, title, description, action }: EmptyStateProps): React.JSX.Element {
  return (
    <div style={containerStyle} role="status">
      <div style={iconWrapperStyle} aria-hidden>
        {icon}
      </div>
      <h3 style={titleStyle}>{title}</h3>
      <p style={descriptionStyle}>{description}</p>
      {action !== undefined && <div style={actionWrapperStyle}>{action}</div>}
    </div>
  );
}

EmptyState.displayName = 'EmptyState';
