import type { DeskModalAPI } from "./desk-types";

/**
 * Check if the app is running inside a DeskModal Desktop Agent.
 * Returns true if `window.deskmodal` is available and has a version string.
 */
export function isDeskModalAgent(): boolean {
  return (
    typeof window !== "undefined" &&
    window.deskmodal !== undefined &&
    typeof window.deskmodal.version === "string"
  );
}

/**
 * Check if a specific DeskModal feature is available.
 * Uses property-based feature detection rather than version comparison,
 * so the code degrades gracefully as DeskModal evolves.
 */
export function hasDeskModalFeature(feature: keyof DeskModalAPI): boolean {
  if (!isDeskModalAgent()) {
    return false;
  }
  return feature in (window.deskmodal as DeskModalAPI);
}

/**
 * Get the DeskModal API with full type safety, or null if not running on DeskModal.
 * Use this over direct `window.deskmodal` access to get proper type narrowing.
 */
export function getDeskModalAPI(): DeskModalAPI | null {
  if (!isDeskModalAgent()) {
    return null;
  }
  return window.deskmodal as DeskModalAPI;
}
