import type { AdapterCapabilities, AdapterCategory, DataAdapter } from '../types/adapter';
import type { ExchangeId } from '../types/normalized';

/** Metadata and lazy loader for a registered adapter. */
export interface AdapterRegistryEntry {
  readonly exchangeId: ExchangeId;
  readonly displayName: string;
  readonly category: AdapterCategory;
  readonly capabilities: AdapterCapabilities;
  readonly loader: () => Promise<DataAdapter>;
}

/** Adapter metadata without the loader function, safe for synchronous UI access. */
export type AdapterMetadata = Omit<AdapterRegistryEntry, 'loader'>;

/**
 * Registry of exchange adapters with lazy loading.
 *
 * Metadata (displayName, category, capabilities) is available synchronously
 * for UI listing. Adapter instances are loaded on demand via dynamic import,
 * cached after first load so subsequent calls return the same instance.
 */
class AdapterRegistry {
  private readonly entries = new Map<ExchangeId, AdapterRegistryEntry>();
  private readonly loaded = new Map<ExchangeId, DataAdapter>();
  private readonly loading = new Map<ExchangeId, Promise<DataAdapter>>();

  /** Register an adapter with its metadata and lazy loader. */
  register(entry: AdapterRegistryEntry): void {
    this.entries.set(entry.exchangeId, entry);
  }

  /**
   * Get an adapter instance, loading it on first access.
   * Subsequent calls return the cached instance.
   * Concurrent calls during loading share the same promise (no double-load).
   */
  async get(exchangeId: ExchangeId): Promise<DataAdapter> {
    const cached = this.loaded.get(exchangeId);
    if (cached) return cached;

    const inflight = this.loading.get(exchangeId);
    if (inflight) return inflight;

    const entry = this.entries.get(exchangeId);
    if (!entry) {
      throw new Error(`No adapter registered for exchange: ${exchangeId}`);
    }

    const promise = entry.loader().then((adapter) => {
      this.loaded.set(exchangeId, adapter);
      this.loading.delete(exchangeId);
      return adapter;
    }).catch((err: unknown) => {
      this.loading.delete(exchangeId);
      throw err;
    });

    this.loading.set(exchangeId, promise);
    return promise;
  }

  /** Whether the adapter instance has been loaded into memory. */
  isLoaded(exchangeId: ExchangeId): boolean {
    return this.loaded.has(exchangeId);
  }

  /** Whether an adapter is registered (regardless of load state). */
  isRegistered(exchangeId: ExchangeId): boolean {
    return this.entries.has(exchangeId);
  }

  /** Get metadata for a single adapter. Available synchronously. */
  getMetadata(exchangeId: ExchangeId): AdapterMetadata | undefined {
    const entry = this.entries.get(exchangeId);
    if (!entry) return undefined;
    const { loader: _, ...metadata } = entry;
    return metadata;
  }

  /** List metadata for all registered adapters. Available synchronously. */
  listAll(): ReadonlyArray<AdapterMetadata> {
    return Array.from(this.entries.values()).map(({ loader: _, ...metadata }) => metadata);
  }

  /** List metadata for adapters in a specific category. Available synchronously. */
  listByCategory(category: AdapterCategory): ReadonlyArray<AdapterMetadata> {
    return this.listAll().filter((m) => m.category === category);
  }
}

/** Singleton adapter registry instance. */
export const adapterRegistry = new AdapterRegistry();

// ---------------------------------------------------------------------------
// Registration: all adapters with inline metadata and dynamic import loaders
// ---------------------------------------------------------------------------

adapterRegistry.register({
  exchangeId: 'binance',
  displayName: 'Binance',
  category: 'cex',
  capabilities: {
    realtime: true,
    historicalDepth: '7y',
    orderbook: true,
    trades: true,
    ohlcv: true,
    fundingRates: false,
    openInterest: false,
    liquidations: false,
    defiMetrics: false,
    onChainMetrics: false,
    authenticated: true,
  },
  loader: async () => {
    const { BinanceAdapter } = await import('./binance/binance-adapter');
    return new BinanceAdapter();
  },
});

