/**
 * Centralized reactive price store for cross-app tick data.
 *
 * Provides a singleton in-memory store of the latest PriceTick for each
 * symbol with LRU eviction to prevent unbounded memory growth during
 * 24/7 streaming sessions.
 *
 * Consumer apps subscribe via `onTickUpdate()` callbacks instead
 * of each independently setting up FDC3 channel listeners.
 *
 * The store is intentionally framework-agnostic (no Jotai/Zustand) so
 * that it works in any context -- React hooks, vanilla services, workers.
 * React hooks in consumer apps can wrap `onTickUpdate` in a `useEffect`.
 */


/* -------------------------------------------------------------------------- */
/*  PriceTick                                                                  */
/* -------------------------------------------------------------------------- */

/** Canonical tick type shared across all apps. */
export interface PriceTick {
  readonly symbol: string;
  readonly exchangeId: string;
  readonly last: number;
  readonly bid?: number;
  readonly ask?: number;
  readonly spread?: number;
  readonly high24h?: number;
  readonly low24h?: number;
  readonly volume24h?: number;
  readonly quoteVolume24h?: number;
  readonly changePercent24h?: number;
  readonly bestBidQty?: number;
  readonly bestAskQty?: number;
  readonly timestamp: number;
  readonly sequence?: number;
}

/* -------------------------------------------------------------------------- */
/*  LRU Configuration                                                          */
/* -------------------------------------------------------------------------- */

/** Maximum number of symbols retained in the price store before LRU eviction. */
const DEFAULT_MAX_SYMBOLS = 200;

/** Current configured maximum. Mutable for testing / runtime reconfiguration. */
let maxSymbols = DEFAULT_MAX_SYMBOLS;

/* -------------------------------------------------------------------------- */
/*  Internal state                                                             */
/* -------------------------------------------------------------------------- */

/**
 * Latest tick keyed by symbol (e.g. "BTCUSDT").
 * Map maintains insertion order — we exploit delete-and-re-add
 * to implement LRU: most-recently-used symbols are at the end,
 * least-recently-used at the front (first iterator position).
 */
const ticks = new Map<string, PriceTick>();

/** Timestamp of the last update (any symbol). */
let lastUpdateTs = 0;

/** Registered tick update callbacks. */
type TickCallback = (tick: PriceTick) => void;
const tickCallbacks = new Set<TickCallback>();

/** Callback fired when a symbol is evicted from the LRU cache. */
type EvictionCallback = (symbol: string, tick: PriceTick) => void;
const evictionCallbacks = new Set<EvictionCallback>();

/* -------------------------------------------------------------------------- */
/*  Structured logging                                                         */
/* -------------------------------------------------------------------------- */

function structuredLog(level: 'error' | 'warn' | 'info', message: string): void {
  if (typeof window === 'undefined') return;
  const win = window as { deskmodal?: { log?: (level: string, msg: string) => void } };
  if (win.deskmodal?.log) {
    win.deskmodal.log(level, message);
  }
}

/* -------------------------------------------------------------------------- */
/*  LRU helpers                                                                */
/* -------------------------------------------------------------------------- */

/**
 * Touch a symbol in the LRU map — delete and re-insert to move to the end.
 * Returns the existing tick if present.
 */
function lruTouch(symbol: string): PriceTick | undefined {
  const existing = ticks.get(symbol);
  if (existing !== undefined) {
    ticks.delete(symbol);
    ticks.set(symbol, existing);
  }
  return existing;
}

/**
 * Evict the least-recently-used symbols until size is within maxSymbols.
 */
function lruEvict(): void {
  while (ticks.size > maxSymbols) {
    const first = ticks.entries().next();
    if (first.done) break;
    const [symbol, tick] = first.value;
    ticks.delete(symbol);
    for (const cb of evictionCallbacks) {
      try {
        cb(symbol, tick);
      } catch (err) {
        structuredLog('error', `[price-store] Eviction callback error: ${String(err)}`);
      }
    }
  }
}

/* -------------------------------------------------------------------------- */
/*  Public API                                                                 */
/* -------------------------------------------------------------------------- */

/**
 * Update or insert a tick in the store and notify all subscribers.
 * Performs sequence-based dedup when the tick carries a sequence number.
 * Maintains LRU ordering — the updated symbol becomes most-recently-used.
 * If the store exceeds maxSymbols, the least-recently-used symbol is evicted.
 */
export function updateTick(tick: PriceTick): void {
  const existing = ticks.get(tick.symbol);

  // Sequence-based dedup: skip stale ticks when sequence is available
  if (
    existing !== undefined &&
    tick.sequence !== undefined &&
    existing.sequence !== undefined &&
    tick.sequence <= existing.sequence
  ) {
    return;
  }

  // LRU: delete then re-insert to move to end of iteration order
  if (existing !== undefined) {
    ticks.delete(tick.symbol);
  }
  ticks.set(tick.symbol, tick);
  lastUpdateTs = tick.timestamp;

  // Evict LRU entries if over capacity
  lruEvict();

  for (const cb of tickCallbacks) {
    try {
      cb(tick);
    } catch (err) {
      structuredLog('error', `[price-store] Tick callback error: ${String(err)}`);
    }
  }
}

/**
 * Retrieve the latest tick for a symbol, or undefined if never seen.
 * Touches the symbol in LRU ordering (moves it to most-recently-used).
 */
export function getLatestPrice(symbol: string): PriceTick | undefined {
  lruTouch(symbol);
  return ticks.get(symbol);
}

/** Get a readonly snapshot of all current ticks. Does not affect LRU ordering. */
export function getAllTicks(): ReadonlyMap<string, PriceTick> {
  return ticks;
}

/** Get the epoch-ms timestamp of the most recent update. */
export function getLastUpdateTimestamp(): number {
  return lastUpdateTs;
}

/** Group current ticks by exchangeId. Does not affect LRU ordering. */
export function getTicksByExchange(): ReadonlyMap<string, PriceTick[]> {
  const grouped = new Map<string, PriceTick[]>();
  for (const tick of ticks.values()) {
    const bucket = grouped.get(tick.exchangeId);
    if (bucket) {
      bucket.push(tick);
    } else {
      grouped.set(tick.exchangeId, [tick]);
    }
  }
  return grouped;
}

/**
 * Subscribe to tick updates. Returns an unsubscribe function.
 *
 * The callback fires once per `updateTick()` call with the new tick.
 */
export function onTickUpdate(callback: TickCallback): () => void {
  tickCallbacks.add(callback);
  return () => {
    tickCallbacks.delete(callback);
  };
}

/**
 * Subscribe to symbol eviction events. Returns an unsubscribe function.
 * Fires when a symbol is evicted from the LRU cache due to capacity.
 */
export function onEviction(callback: EvictionCallback): () => void {
  evictionCallbacks.add(callback);
  return () => {
    evictionCallbacks.delete(callback);
  };
}

/**
 * Configure the maximum number of symbols retained in the store.
 * Immediately evicts LRU entries if the new max is lower than current size.
 */
export function setMaxSymbols(max: number): void {
  maxSymbols = Math.max(1, max);
  lruEvict();
}

/** Get the current max symbols configuration. */
export function getMaxSymbols(): number {
  return maxSymbols;
}

/**
 * Clear all stored ticks, reset the last-update timestamp,
 * and restore default max-symbols configuration.
 * Primarily useful for testing.
 */
export function resetPriceStore(): void {
  ticks.clear();
  lastUpdateTs = 0;
  maxSymbols = DEFAULT_MAX_SYMBOLS;
  evictionCallbacks.clear();
}
