import { forwardRef, type CSSProperties, type ReactNode } from 'react';
import { IconButton, Tooltip } from '../primitives';
import { ChevronRight } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  ToolCategory                                                              */
/*  Single tool category in the LeftToolbar with primary icon + flyout arrow. */
/*  Uses --ts-button-ghost-* and --ts-accent-* tokens.                       */
/* -------------------------------------------------------------------------- */

export interface ToolConfig {
  /** Unique tool identifier. */
  value: string;
  /** Display label. */
  label: string;
  /** Icon element (from lucide-react or custom SVG). */
  icon: ReactNode;
}

export interface ToolCategoryProps {
  /** The currently active tool in this category. */
  activeTool: ToolConfig;
  /** Whether this category contains the globally active tool. */
  isActive: boolean;
  /** Called when the primary tool button is clicked. */
  onToolClick: (toolValue: string) => void;
  /** Called when the flyout arrow is clicked. */
  onFlyoutOpen: () => void;
  /** Accessible label for the category. */
  label: string;
  /** Number of tools in this category (show chevron only if > 1). */
  toolCount?: number;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-tool-category-styles';

function ensureToolCategoryStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-tool-category]:focus-within {
      border-radius: var(--ts-button-radius);
    }
    [data-ts-tool-category-arrow]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -1px;
    }
    [data-ts-tool-category-arrow]:hover {
      background: var(--ts-button-ghost-bg-hover);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureToolCategoryStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '0px',
  flexShrink: 0,
};

const arrowStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 12,
  height: 'var(--ts-icon-button-size-sm)',
  cursor: 'pointer',
  color: 'var(--ts-text-tertiary)',
  borderRadius: '0 var(--ts-button-radius) var(--ts-button-radius) 0',
  transition: 'background 150ms, color 150ms',
  boxSizing: 'border-box',
  flexShrink: 0,
};

/* ----- Component --------------------------------------------------------- */

export const ToolCategory = forwardRef<HTMLDivElement, ToolCategoryProps>(
  function ToolCategory(
    { activeTool, isActive, onToolClick, onFlyoutOpen, label, toolCount = 2 },
    ref,
  ) {
    const handleIconClick = () => {
      if (isActive) {
        // Already active — open flyout to let user switch tools
        onFlyoutOpen();
      } else {
        // Activate this tool
        onToolClick(activeTool.value);
      }
    };

    const handleContextMenu = (e: React.MouseEvent) => {
      e.preventDefault();
      onFlyoutOpen();
    };

    return (
      <div ref={ref} data-ts-tool-category="" style={containerStyle} onContextMenu={handleContextMenu}>
        <Tooltip content={`${label} (click: use, right-click: more tools)`} side="right" delayDuration={300}>
          <IconButton
            icon={activeTool.icon}
            label={label}
            variant="ghost"
            size="sm"
            active={isActive}
            onClick={handleIconClick}
          />
        </Tooltip>
        {toolCount > 1 && (
          <button
            type="button"
            data-ts-tool-category-arrow=""
            aria-label={`More ${label} tools`}
            style={arrowStyle}
            onClick={onFlyoutOpen}
          >
            <ChevronRight size={10} />
          </button>
        )}
      </div>
    );
  },
);

ToolCategory.displayName = 'ToolCategory';
