import { forwardRef, type CSSProperties } from 'react';
import { LayoutGrid } from 'lucide-react';
import { Panel, Toolbar, Select, EmptyState } from '../../primitives';
import { ColorScaleLegend, type ColorStop } from './ColorScaleLegend';

/* -------------------------------------------------------------------------- */
/*  TreemapHeatmapShell                                                       */
/*  Control surface for treemap/heatmap visualization.                        */
/*  Provides size-by, color-by, layout mode controls + EmptyState placeholder.*/
/*  Uses --ts-viz-shell-* tokens.                                             */
/* -------------------------------------------------------------------------- */

export type TreemapSizeBy = 'market-cap' | 'volume' | 'oi';
export type TreemapColorBy = 'change-24h' | 'change-1h' | 'change-7d' | 'change-30d' | 'volatility-1w' | 'volume-change';
export type TreemapLayoutMode = 'grouped' | 'flat' | 'mono-grouped' | 'mono-flat';

export interface TreemapHeatmapShellProps {
  /** Panel title. */
  title?: string;
  /** Current size-by metric. */
  sizeBy: TreemapSizeBy;
  /** Called when size-by changes. */
  onSizeByChange: (sizeBy: TreemapSizeBy) => void;
  /** Current color-by metric. */
  colorBy: TreemapColorBy;
  /** Called when color-by changes. */
  onColorByChange: (colorBy: TreemapColorBy) => void;
  /** Current layout mode. */
  layoutMode: TreemapLayoutMode;
  /** Called when layout mode changes. */
  onLayoutModeChange: (mode: TreemapLayoutMode) => void;
  /** Color scale for the legend. */
  colorScale: ColorStop[];
  /** Called when a cell is clicked (symbol selection). */
  onCellClick?: (symbol: string) => void;
  /** Whether zoom is enabled. */
  zoomEnabled?: boolean;
  /** Called when zoom state changes. */
  onZoomChange?: (zoomLevel: number) => void;
}

/* ----- Constants --------------------------------------------------------- */

const SIZE_BY_OPTIONS: Array<{ value: string; label: string }> = [
  { value: 'market-cap', label: 'Market Cap' },
  { value: 'volume', label: 'Volume' },
  { value: 'oi', label: 'Open Interest' },
];

const COLOR_BY_OPTIONS: Array<{ value: string; label: string }> = [
  { value: 'change-24h', label: '24h Change' },
  { value: 'change-1h', label: '1h Change' },
  { value: 'change-7d', label: '7d Change' },
  { value: 'change-30d', label: '30d Change' },
  { value: 'volatility-1w', label: '1w Volatility' },
  { value: 'volume-change', label: 'Volume Change' },
];

const LAYOUT_MODE_OPTIONS: Array<{ value: string; label: string }> = [
  { value: 'grouped', label: 'Grouped' },
  { value: 'flat', label: 'Flat' },
  { value: 'mono-grouped', label: 'Mono Grouped' },
  { value: 'mono-flat', label: 'Mono Flat' },
];

/* ----- Styles ------------------------------------------------------------ */

const shellStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  height: '100%',
};

const vizContainerStyle: CSSProperties = {
  flex: 1,
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  background: 'var(--ts-viz-shell-bg)',
  minHeight: 300,
  position: 'relative',
};

const legendContainerStyle: CSSProperties = {
  padding: 'var(--ts-space-2) var(--ts-space-3)',
};

export const TreemapHeatmapShell = forwardRef<HTMLDivElement, TreemapHeatmapShellProps>(
  function TreemapHeatmapShell(
    {
      title = 'Crypto Heatmap',
      sizeBy,
      onSizeByChange,
      colorBy,
      onColorByChange,
      layoutMode,
      onLayoutModeChange,
      colorScale,
    },
    ref,
  ) {
    return (
      <div ref={ref} data-ts-treemap-heatmap-shell="" style={shellStyle}>
        <Panel title={title}>
          {/* Controls row */}
          <Toolbar>
            <Toolbar.Group>
              <Select
                options={SIZE_BY_OPTIONS}
                value={sizeBy}
                onValueChange={(v) => onSizeByChange(v as TreemapSizeBy)}
                size="sm"
                label="Size by"
              />
            </Toolbar.Group>

            <Toolbar.Separator />

            <Toolbar.Group>
              <Select
                options={COLOR_BY_OPTIONS}
                value={colorBy}
                onValueChange={(v) => onColorByChange(v as TreemapColorBy)}
                size="sm"
                label="Color by"
              />
            </Toolbar.Group>

            <Toolbar.Separator />

            <Toolbar.Group>
              <Select
                options={LAYOUT_MODE_OPTIONS}
                value={layoutMode}
                onValueChange={(v) => onLayoutModeChange(v as TreemapLayoutMode)}
                size="sm"
                label="Layout mode"
              />
            </Toolbar.Group>
          </Toolbar>

          {/* Visualization area */}
          <div style={vizContainerStyle}>
            <div data-ts-viz-canvas="" style={{ width: '100%', height: '100%', position: 'absolute', top: 0, left: 0 }} />
            <EmptyState
              icon={<LayoutGrid size={40} />}
              title="Connect to data source"
              description="Treemap heatmap will render here when connected to market data."
            />
          </div>

          {/* Color scale legend */}
          <div style={legendContainerStyle}>
            <ColorScaleLegend
              stops={colorScale}
              formatLabel={(v) => `${v > 0 ? '+' : ''}${v}%`}
              title="Change %"
            />
          </div>
        </Panel>
      </div>
    );
  },
);

TreemapHeatmapShell.displayName = 'TreemapHeatmapShell';
