import { useState, useCallback, useMemo, useRef, useEffect } from 'react';
import type { ExchangeId } from '@deskmodal/data-layer';
import { priceFeedClient } from '../services/price-feed-client';

/* -------------------------------------------------------------------------- */
/*  useExchangeCredentials                                                     */
/*  Intent-based credential management — credentials are stored in the OS      */
/*  keychain by the native price-feed service.                                 */
/*  React state stores ONLY a boolean flag (Decision D5).                      */
/* -------------------------------------------------------------------------- */

/** Credential data for form submission only — never stored in React state. */
export interface ExchangeCredentials {
  readonly apiKey: string;
  readonly apiSecret: string;
  readonly passphrase?: string;
}

/** Credential status for UI display. */
export type CredentialStatus = 'none' | 'configured' | 'verified' | 'invalid';

/** State returned by the useExchangeCredentials hook. */
export interface ExchangeCredentialsState {
  /** Check if an exchange has credentials configured (boolean only). */
  readonly hasCredentials: (exchangeId: ExchangeId) => boolean;
  /** Get the credential status for display. */
  readonly getCredentialStatus: (exchangeId: ExchangeId) => CredentialStatus;
  /** Save credentials via the price-feed service (stores in OS keychain, NOT React state). */
  readonly saveCredentials: (exchangeId: ExchangeId, credentials: ExchangeCredentials) => Promise<boolean>;
  /** Remove credential flag for an exchange. */
  readonly removeCredentials: (exchangeId: ExchangeId) => void;
  /** Whether a save operation is in progress. */
  readonly isSaving: boolean;
}

/** Structured log helper — routes to DeskModal logging if available. */
function structuredLog(level: 'error' | 'warn' | 'info', message: string): void {
  const win = window as { deskmodal?: { log?: (level: string, msg: string) => void } };
  if (win.deskmodal?.log) {
    win.deskmodal.log(level, message);
  }
}

/**
 * Hook managing per-exchange API credentials.
 *
 * Credentials are sent to the native price-feed service via FDC3 intents
 * and stored securely in the OS keychain. Local state tracks ONLY boolean
 * flags indicating which exchanges have credentials set. Raw credential
 * values are NEVER stored in React state (Decision D5).
 */
export function useExchangeCredentials(): ExchangeCredentialsState {
  // Boolean-only flags: which exchanges have credentials configured.
  const [credentialFlags, setCredentialFlags] = useState<Map<string, CredentialStatus>>(
    new Map(),
  );
  const [isSaving, setIsSaving] = useState(false);

  const hasCredentials = useCallback(
    (exchangeId: ExchangeId): boolean => {
      const status = credentialFlags.get(exchangeId);
      return status !== undefined && status !== 'none';
    },
    [credentialFlags],
  );

  const getCredentialStatus = useCallback(
    (exchangeId: ExchangeId): CredentialStatus => {
      return credentialFlags.get(exchangeId) ?? 'none';
    },
    [credentialFlags],
  );

  const saveCredentials = useCallback(
    async (exchangeId: ExchangeId, credentials: ExchangeCredentials): Promise<boolean> => {
      setIsSaving(true);
      try {
        const result = await priceFeedClient.setCredentials(exchangeId, {
          exchange: exchangeId,
          apiKey: credentials.apiKey,
          apiSecret: credentials.apiSecret,
          passphrase: credentials.passphrase,
        });

        if (result.success) {
          setCredentialFlags((prev) => {
            const next = new Map(prev);
            next.set(exchangeId, 'configured');
            return next;
          });
          return true;
        }

        structuredLog('error', `[credentials] Failed to set credentials for ${exchangeId}: ${result.error ?? 'unknown error'}`);
        setCredentialFlags((prev) => {
          const next = new Map(prev);
          next.set(exchangeId, 'invalid');
          return next;
        });
        return false;
      } catch (err) {
        structuredLog('error', `[credentials] Failed to set credentials for ${exchangeId}: ${String(err)}`);
        return false;
      } finally {
        setIsSaving(false);
      }
    },
    [],
  );

  const removeCredentials = useCallback(
    (exchangeId: ExchangeId): void => {
      setCredentialFlags((prev) => {
        const next = new Map(prev);
        next.delete(exchangeId);
        return next;
      });
    },
    [],
  );

  return useMemo(
    () => ({ hasCredentials, getCredentialStatus, saveCredentials, removeCredentials, isSaving }),
    [hasCredentials, getCredentialStatus, saveCredentials, removeCredentials, isSaving],
  );
}
