import {
  forwardRef,
  useCallback,
  useMemo,
  useState,
  type CSSProperties,
  type DragEvent,
} from 'react';
import { ListPlus } from 'lucide-react';
import { ScrollArea, EmptyState } from '../primitives';
import { formatCompactNumber, formatPrice } from '../financial';
import { WatchlistHeader, type WatchlistColumn, type ViewModeOption } from './WatchlistHeader';
import { WatchlistSectionHeader } from './WatchlistSectionHeader';
import { WatchlistContextMenu } from './WatchlistContextMenu';
import { SparklineChart } from './SparklineChart';
import { getHeatColor, computeColumnRange, type HeatPalette } from './conditional-format';

/* -------------------------------------------------------------------------- */
/*  WatchlistPanel                                                             */
/*  Full watchlist panel with sections, virtualized rows, context menu,        */
/*  drag-reorder, and density modes.                                           */
/*  Uses --ts-watchlist-* tokens.                                              */
/* -------------------------------------------------------------------------- */

export interface WatchlistSection {
  /** Unique section identifier. */
  id: string;
  /** Section display label. */
  label: string;
  /** Whether the section is collapsed. */
  collapsed: boolean;
  /** Symbols in this section. */
  symbols: WatchlistSymbol[];
}

export interface WatchlistSymbol {
  /** Unique identifier (e.g., "BINANCE:BTCUSDT"). */
  id: string;
  /** Ticker symbol. */
  symbol: string;
  /** Exchange name. */
  exchange: string;
  /** Current price (null = not yet received). */
  price: number | null;
  /** Previous price for flash direction. */
  previousPrice?: number | null;
  /** Absolute price change (null = not yet received). */
  priceChange: number | null;
  /** Percentage price change (null = not yet received). */
  priceChangePercent: number | null;
  /** Price decimal precision. */
  precision?: number;
  /** 24h volume. */
  volume?: number;
  /** Market capitalization. */
  marketCap?: number;
  /** Sparkline data points. */
  sparklineData?: number[];
  /** Whether the symbol's data is stale. */
  stale?: boolean;
  /** Best bid price (top of book). */
  bid?: number;
  /** Best bid size (top of book). */
  bidSize?: number;
  /** Best offer/ask price (top of book). */
  offer?: number;
  /** Best offer/ask size (top of book). */
  offerSize?: number;
  /** Spread between offer and bid. */
  spread?: number;
  /** 24h open price. */
  open?: number;
  /** 24h high price. */
  high?: number;
  /** 24h low price. */
  low?: number;
  /** 1-hour percentage change. */
  change1h?: number;
  /** 7-day percentage change. */
  change7d?: number;
  /** 30-day percentage change. */
  change30d?: number;
  /** RSI (14-period). */
  rsi?: number;
  /** MACD signal line value. */
  macdSignal?: number;
  /** Bollinger Band percentage (where price sits within band). */
  bbPercent?: number;
  /** Funding rate (for perpetual contracts). */
  fundingRate?: number;
}

export interface WatchlistPanelProps {
  /** Watchlist sections with their symbols. */
  sections: WatchlistSection[];
  /** ID of the currently selected symbol. */
  selectedSymbolId?: string;
  /** Column configuration. */
  columns: WatchlistColumn[];
  /** Current sort state. */
  sortColumn: string | null;
  /** Sort direction. */
  sortDirection: 'asc' | 'desc';
  /** Display density mode. */
  densityMode: 'compact' | 'expanded';
  /** Called when a symbol row is clicked. */
  onSymbolSelect: (symbolId: string) => void;
  /** Called when sort changes. */
  onSortChange: (columnId: string) => void;
  /** Called when a section is toggled. */
  onSectionToggle: (sectionId: string) => void;
  /** Called when symbol is dragged to a new position. */
  onSymbolReorder: (symbolId: string, targetSectionId: string, targetIndex: number) => void;
  /** Called when column config changes. */
  onColumnsChange: (columns: WatchlistColumn[]) => void;
  /** Called when a column is resized by dragging. */
  onColumnResize?: (columnId: string, newWidth: number) => void;
  /** Called to open a chart for a symbol. */
  onViewChart: (symbolId: string) => void;
  /** Called to add an alert for a symbol. */
  onAddAlert: (symbolId: string) => void;
  /** Called to view depth for a symbol. */
  onViewDepth: (symbolId: string) => void;
  /** Called to remove a symbol. */
  onRemoveSymbol: (symbolId: string) => void;
  /** Called when add symbol is requested. */
  onAddSymbol: () => void;
  /** Called when search is requested. */
  onSearch: () => void;
  /** Currently active view mode ID. */
  viewMode?: string;
  /** Called when the user switches view mode. */
  onViewModeChange?: (mode: string) => void;
  /** Available view modes for the segmented control. */
  viewModes?: ViewModeOption[];
  /** Enable heat map conditional formatting on numeric cells. */
  enableHeatMap?: boolean;
  /** Called when a symbol row initiates a cross-app drag (mousedown + threshold). */
  onCrossAppDragStart?: (symbolId: string, event: React.MouseEvent) => void;
  /** Called to send symbol to analytics via FDC3 intent. */
  onSendToAnalytics?: (symbolId: string) => void;
  /** Called to send symbol to screener via FDC3 intent. */
  onSendToScreener?: (symbolId: string) => void;
  /** Container width in pixels — used to switch between table and compact card layout. */
  containerWidth?: number;
}

/** Width threshold below which the watchlist switches to compact card layout. */
const COMPACT_LAYOUT_THRESHOLD = 400;

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-watchlist-panel-styles';

function ensureWatchlistPanelStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-watchlist-panel] {
      display: flex;
      flex-direction: column;
      height: 100%;
    }
    [data-ts-watchlist-panel-body] {
      flex: 1;
      min-height: 0;
    }
    [data-ts-watchlist-row]:hover:not([data-selected]) {
      background: rgba(30,91,255,0.06);
    }
    [data-ts-watchlist-row]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-watchlist-row][data-selected] {
      background: rgba(30,91,255,0.08);
      border: 1px solid rgba(30,91,255,0.25);
      border-left: none;
      border-radius: 0 4px 4px 0;
      box-shadow: 0 0 20px rgba(30,91,255,0.06);
    }
    [data-ts-watchlist-row][data-selected] [data-ts-row-bar] {
      opacity: 1;
      box-shadow: 0 0 8px rgba(30,91,255,0.35);
    }
    [data-ts-watchlist-row]:hover [data-ts-action-dash] {
      opacity: 0.7;
    }
    [data-ts-watchlist-row][data-selected] [data-ts-action-dash] {
      opacity: 1;
      box-shadow: 0 0 4px rgba(30,91,255,0.35);
    }
    [data-ts-compact-row]:hover:not([data-selected]) {
      background: rgba(30,91,255,0.06);
    }
    [data-ts-compact-row]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-compact-row][data-selected] {
      background: rgba(30,91,255,0.08);
      border: 1px solid rgba(30,91,255,0.25);
      border-left: none;
      border-radius: 0 4px 4px 0;
      box-shadow: 0 0 20px rgba(30,91,255,0.06);
    }
    [data-ts-compact-row][data-selected] [data-ts-row-bar] {
      opacity: 1;
      box-shadow: 0 0 8px rgba(30,91,255,0.35);
    }
    [data-ts-compact-row]:hover [data-ts-action-dash] {
      opacity: 0.7;
    }
    [data-ts-compact-row][data-selected] [data-ts-action-dash] {
      opacity: 1;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureWatchlistPanelStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const panelStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  height: '100%',
  background: 'var(--ts-panel-bg)',
  border: '1px solid var(--ts-panel-border)',
  borderRadius: 'var(--ts-radius-sm)',
  overflow: 'hidden',
};

const bodyStyle: CSSProperties = {
  flex: 1,
  minHeight: 0,
};

const sparklineCellStyle: CSSProperties = {
  flexShrink: 0,
};

const volumeCellStyle: CSSProperties = {
  flexShrink: 0,
  width: '56px',
  fontSize: 'var(--ts-font-xs)',
  fontFamily: 'var(--ts-watchlist-price-font)',
  fontVariantNumeric: 'tabular-nums',
  color: 'var(--ts-text-secondary)',
  textAlign: 'right',
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
};

const numericCellStyle: CSSProperties = {
  flexShrink: 0,
  width: '72px',
  fontSize: 'var(--ts-font-xs)',
  fontFamily: 'var(--ts-watchlist-price-font)',
  fontVariantNumeric: 'tabular-nums',
  color: 'var(--ts-text-primary)',
  textAlign: 'right',
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
};

const bidCellStyle: CSSProperties = {
  ...numericCellStyle,
  color: 'var(--ts-color-bullish, var(--ts-price-change-up-text))',
};

const offerCellStyle: CSSProperties = {
  ...numericCellStyle,
  color: 'var(--ts-color-bearish, var(--ts-price-change-down-text))',
};

const sizeCellStyle: CSSProperties = {
  ...numericCellStyle,
  width: '56px',
  color: 'var(--ts-text-secondary)',
};

const spreadCellStyle: CSSProperties = {
  ...numericCellStyle,
  width: '68px',
  color: 'var(--ts-text-secondary)',
};

/** Build a cell style using the column's current width, enforcing minWidth. */
function cellStyle(columns: WatchlistColumn[], id: string, fallback: number, base: CSSProperties): CSSProperties {
  const col = columns.find((c) => c.id === id);
  if (!col) return { ...base, width: `${fallback}px`, flexShrink: 0, overflow: 'hidden', textOverflow: 'ellipsis' };
  const w = col.width === 'flex' ? fallback : (typeof col.width === 'number' ? col.width : fallback);
  const min = col.minWidth ?? 40;
  return { ...base, width: `${Math.max(w, min)}px`, minWidth: `${min}px`, flexShrink: 0, overflow: 'hidden', textOverflow: 'ellipsis' };
}

/* ----- Flattened list item types ----------------------------------------- */

interface SectionHeaderItem {
  type: 'section';
  sectionId: string;
  label: string;
  count: number;
  collapsed: boolean;
}

interface SymbolRowItem {
  type: 'symbol';
  sectionId: string;
  symbol: WatchlistSymbol;
}

type FlatItem = SectionHeaderItem | SymbolRowItem;

/* ----- Component --------------------------------------------------------- */

export const WatchlistPanel = forwardRef<HTMLDivElement, WatchlistPanelProps>(function WatchlistPanel({
  sections,
  selectedSymbolId,
  columns,
  sortColumn,
  sortDirection,
  densityMode,
  onSymbolSelect,
  onSortChange,
  onSectionToggle,
  onSymbolReorder,
  onColumnsChange,
  onColumnResize,
  onViewChart,
  onAddAlert,
  onViewDepth,
  onRemoveSymbol,
  onAddSymbol,
  onSearch,
  viewMode,
  onViewModeChange,
  viewModes,
  enableHeatMap = true,
  onCrossAppDragStart,
  onSendToAnalytics,
  onSendToScreener,
  containerWidth = 800,
}, ref) {
  const [columnConfigOpen, setColumnConfigOpen] = useState(false);
  const [dragOverSectionId, setDragOverSectionId] = useState<string | null>(null);

  const sectionLabels = useMemo(
    () => sections.map((s) => s.label),
    [sections],
  );

  const flatItems: FlatItem[] = useMemo(() => {
    const items: FlatItem[] = [];
    for (const section of sections) {
      for (const sym of section.symbols) {
        items.push({ type: 'symbol', sectionId: section.id, symbol: sym });
      }
    }
    return items;
  }, [sections]);

  // Heat map column ranges — computed once per render across all visible symbols
  const heatMapRanges = useMemo(() => {
    if (!enableHeatMap) return null;
    const allSymbols = sections.flatMap((s) => s.symbols);
    const changeRange = computeColumnRange(allSymbols.map((s) => s.priceChangePercent));
    const spreadRange = computeColumnRange(allSymbols.map((s) => s.spread));
    const volumeRange = computeColumnRange(allSymbols.map((s) => s.volume));
    return { change: changeRange, spread: spreadRange, volume: volumeRange };
  }, [enableHeatMap, sections]);

  const rowHeight = densityMode === 'compact' ? 36 : 48;
  const sectionHeight = 28;

  const handleDragStart = useCallback(
    (e: DragEvent<HTMLDivElement>, symbolId: string) => {
      e.dataTransfer.setData('text/plain', symbolId);
      e.dataTransfer.effectAllowed = 'move';
    },
    [],
  );

  const handleDragOver = useCallback(
    (e: DragEvent<HTMLDivElement>, sectionId: string) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      setDragOverSectionId(sectionId);
    },
    [],
  );

  const handleDragLeave = useCallback(() => {
    setDragOverSectionId(null);
  }, []);

  const handleDrop = useCallback(
    (e: DragEvent<HTMLDivElement>, targetSectionId: string, targetIndex: number) => {
      e.preventDefault();
      const symbolId = e.dataTransfer.getData('text/plain');
      if (symbolId) {
        onSymbolReorder(symbolId, targetSectionId, targetIndex);
      }
      setDragOverSectionId(null);
    },
    [onSymbolReorder],
  );

  const handleCopySymbol = useCallback((symbol: string) => {
    if (typeof navigator !== 'undefined' && navigator.clipboard) {
      void navigator.clipboard.writeText(symbol);
    }
  }, []);

  const handleColumnConfigClick = useCallback(() => {
    setColumnConfigOpen(!columnConfigOpen);
  }, [columnConfigOpen]);

  const isCompact = containerWidth < COMPACT_LAYOUT_THRESHOLD;

  const hasVolumeColumn = columns.some((c) => c.id === 'volume');
  const hasSparklineColumn = columns.some((c) => c.id === 'sparkline');
  const showSparklines = hasSparklineColumn || densityMode === 'expanded';
  const hasBidColumn = columns.some((c) => c.id === 'bid');
  const hasBidSizeColumn = columns.some((c) => c.id === 'bidSize');
  const hasOfferColumn = columns.some((c) => c.id === 'offer');
  const hasOfferSizeColumn = columns.some((c) => c.id === 'offerSize');
  const hasSpreadColumn = columns.some((c) => c.id === 'spread');
  const hasOpenColumn = columns.some((c) => c.id === 'open');
  const hasHighColumn = columns.some((c) => c.id === 'high');
  const hasLowColumn = columns.some((c) => c.id === 'low');
  const hasChange1hColumn = columns.some((c) => c.id === 'change1h');
  const hasChange7dColumn = columns.some((c) => c.id === 'change7d');
  const hasChange30dColumn = columns.some((c) => c.id === 'change30d');
  const hasRsiColumn = columns.some((c) => c.id === 'rsi');
  const hasMacdColumn = columns.some((c) => c.id === 'macdSignal');
  const hasBbPercentColumn = columns.some((c) => c.id === 'bbPercent');
  const hasFundingRateColumn = columns.some((c) => c.id === 'fundingRate');

  const renderItem = useCallback(
    (item: FlatItem, _index: number) => {
      if (item.type === 'section') {
        return null;
      }

      const sym = item.symbol;
      const isSelected = selectedSymbolId === sym.id;

      return (
        <WatchlistContextMenu
          symbol={sym.id}
          sections={sectionLabels}
          onViewChart={onViewChart}
          onAddAlert={onAddAlert}
          onViewDepth={onViewDepth}
          onRemove={onRemoveSymbol}
          onMoveToSection={(symbolId, section) => {
            const targetSection = sections.find((s) => s.label === section);
            if (targetSection) {
              onSymbolReorder(symbolId, targetSection.id, 0);
            }
          }}
          onCopySymbol={handleCopySymbol}
          onSendToAnalytics={onSendToAnalytics}
          onSendToScreener={onSendToScreener}
        >
          <div
            data-ts-watchlist-row=""
            {...(isSelected ? { 'data-selected': '' } : {})}
            draggable
            onDragStart={(e) => handleDragStart(e, sym.id)}
            onDragOver={(e) => handleDragOver(e, item.sectionId)}
            onDrop={(e) => handleDrop(e, item.sectionId, 0)}
            onDoubleClick={() => onViewChart(sym.id)}
            onMouseDown={onCrossAppDragStart ? (e) => { if (e.button === 0) onCrossAppDragStart(sym.id, e); } : undefined}
            onClick={() => onSymbolSelect(sym.id)}
            style={{
              display: 'flex',
              alignItems: 'stretch',
              padding: 0,
              borderBottom: '1px solid var(--ts-watchlist-row-border, #141414)',
              cursor: onCrossAppDragStart ? 'grab' : 'pointer',
              userSelect: 'none',
              transition: 'background 120ms',
              boxSizing: 'border-box' as const,
              position: 'relative' as const,
            }}
          >
            {/* Left colored bar */}
            <div
              data-ts-row-bar=""
              style={{
                width: 3,
                flexShrink: 0,
                borderRadius: '0 2px 2px 0',
                opacity: 0.3,
                background: (sym.priceChange ?? 0) < 0
                  ? 'var(--ts-price-change-down-text, #FF6A00)'
                  : 'var(--ts-accent-default, #0D3791)',
              }}
            />
            {/* Row body */}
            <div style={{ flex: 1, display: 'flex', alignItems: 'center', padding: '10px 12px 10px 10px', gap: 8, minWidth: 0 }}>
            {/* Symbol cell */}
            <div
              style={{
                ...cellStyle(columns, 'symbol', 100, {
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  overflow: 'hidden',
                }),
              }}
            >
              <span style={{
                color: 'var(--ts-watchlist-symbol-text)',
                fontWeight: 600,
                fontSize: 'var(--ts-font-sm)',
                lineHeight: 1.2,
                whiteSpace: 'nowrap',
                overflow: 'hidden',
                textOverflow: 'ellipsis',
              }}>{sym.symbol}</span>
              <span style={{
                color: 'var(--ts-watchlist-exchange-text, var(--ts-text-muted))',
                fontSize: '10px',
                lineHeight: 1.2,
              }}>{sym.exchange}</span>
            </div>
            {/* Last price cell — no heat map, price is neutral data */}
            {columns.some((c) => c.id === 'price') && (
              <div
                style={cellStyle(columns, 'price', 90, numericCellStyle)}
                data-testid="watchlist-price"
              >
                {sym.price != null ? formatPrice(sym.price, sym.precision ?? 2) : '--'}
              </div>
            )}
            {/* Change % cell */}
            {columns.some((c) => c.id === 'change') && (
              <div
                style={{
                  ...cellStyle(columns, 'change', 64, numericCellStyle),
                  color: (sym.priceChangePercent ?? 0) > 0 ? 'var(--ts-color-bullish, var(--ts-price-change-up-text))' : (sym.priceChangePercent ?? 0) < 0 ? 'var(--ts-color-bearish, var(--ts-price-change-down-text))' : 'var(--ts-text-secondary)',
                  background: heatMapRanges
                    ? getHeatColor(sym.priceChangePercent, heatMapRanges.change.min, heatMapRanges.change.max, 'diverging')
                    : undefined,
                }}
                data-direction={(sym.priceChangePercent ?? 0) > 0 ? 'up' : (sym.priceChangePercent ?? 0) < 0 ? 'down' : 'neutral'}
                data-testid="watchlist-change"
              >
                {sym.priceChangePercent != null ? `${sym.priceChangePercent >= 0 ? '+' : ''}${sym.priceChangePercent.toFixed(2)}%` : '--'}
              </div>
            )}
            {hasBidColumn && (
              <div style={cellStyle(columns, 'bid', 72, bidCellStyle)} data-testid="watchlist-bid">
                {sym.bid ? formatPrice(sym.bid, sym.precision ?? 2) : '--'}
              </div>
            )}
            {hasBidSizeColumn && (
              <div style={cellStyle(columns, 'bidSize', 56, sizeCellStyle)} data-testid="watchlist-bid-size">
                {sym.bidSize ? formatCompactNumber(sym.bidSize, 2) : '--'}
              </div>
            )}
            {hasOfferColumn && (
              <div style={cellStyle(columns, 'offer', 72, offerCellStyle)} data-testid="watchlist-offer">
                {sym.offer ? formatPrice(sym.offer, sym.precision ?? 2) : '--'}
              </div>
            )}
            {hasOfferSizeColumn && (
              <div style={cellStyle(columns, 'offerSize', 56, sizeCellStyle)} data-testid="watchlist-offer-size">
                {sym.offerSize ? formatCompactNumber(sym.offerSize, 2) : '--'}
              </div>
            )}
            {hasSpreadColumn && (
              <div
                style={{
                  ...cellStyle(columns, 'spread', 56, spreadCellStyle),
                  background: heatMapRanges
                    ? getHeatColor(sym.spread, heatMapRanges.spread.min, heatMapRanges.spread.max, 'sequential')
                    : undefined,
                }}
                data-testid="watchlist-spread"
              >
                {sym.spread != null ? formatPrice(sym.spread, sym.precision ?? 2) : '--'}
              </div>
            )}
            {hasOpenColumn && (
              <div style={cellStyle(columns, 'open', 72, numericCellStyle)} data-testid="watchlist-open">
                {sym.open ? formatPrice(sym.open, sym.precision ?? 2) : '--'}
              </div>
            )}
            {hasHighColumn && (
              <div style={cellStyle(columns, 'high', 72, numericCellStyle)} data-testid="watchlist-high">
                {sym.high ? formatPrice(sym.high, sym.precision ?? 2) : '--'}
              </div>
            )}
            {hasLowColumn && (
              <div style={cellStyle(columns, 'low', 72, numericCellStyle)} data-testid="watchlist-low">
                {sym.low ? formatPrice(sym.low, sym.precision ?? 2) : '--'}
              </div>
            )}
            {hasChange1hColumn && (
              <div
                style={{
                  ...cellStyle(columns, 'change1h', 56, numericCellStyle),
                  color: (sym.change1h ?? 0) > 0 ? 'var(--ts-color-bullish)' : (sym.change1h ?? 0) < 0 ? 'var(--ts-color-bearish)' : 'var(--ts-text-secondary)',
                }}
                data-testid="watchlist-change1h"
              >
                {sym.change1h != null ? `${sym.change1h >= 0 ? '+' : ''}${sym.change1h.toFixed(2)}%` : '--'}
              </div>
            )}
            {hasChange7dColumn && (
              <div
                style={{
                  ...cellStyle(columns, 'change7d', 56, numericCellStyle),
                  color: (sym.change7d ?? 0) > 0 ? 'var(--ts-color-bullish)' : (sym.change7d ?? 0) < 0 ? 'var(--ts-color-bearish)' : 'var(--ts-text-secondary)',
                }}
                data-testid="watchlist-change7d"
              >
                {sym.change7d != null ? `${sym.change7d >= 0 ? '+' : ''}${sym.change7d.toFixed(2)}%` : '--'}
              </div>
            )}
            {hasChange30dColumn && (
              <div
                style={{
                  ...cellStyle(columns, 'change30d', 56, numericCellStyle),
                  color: (sym.change30d ?? 0) > 0 ? 'var(--ts-color-bullish)' : (sym.change30d ?? 0) < 0 ? 'var(--ts-color-bearish)' : 'var(--ts-text-secondary)',
                }}
                data-testid="watchlist-change30d"
              >
                {sym.change30d != null ? `${sym.change30d >= 0 ? '+' : ''}${sym.change30d.toFixed(2)}%` : '--'}
              </div>
            )}
            {hasRsiColumn && (
              <div style={cellStyle(columns, 'rsi', 48, numericCellStyle)} data-testid="watchlist-rsi">
                {sym.rsi != null ? sym.rsi.toFixed(1) : '--'}
              </div>
            )}
            {hasMacdColumn && (
              <div style={cellStyle(columns, 'macdSignal', 56, numericCellStyle)} data-testid="watchlist-macd">
                {sym.macdSignal != null ? sym.macdSignal.toFixed(2) : '--'}
              </div>
            )}
            {hasBbPercentColumn && (
              <div style={cellStyle(columns, 'bbPercent', 48, numericCellStyle)} data-testid="watchlist-bb">
                {sym.bbPercent != null ? `${(sym.bbPercent * 100).toFixed(0)}%` : '--'}
              </div>
            )}
            {hasFundingRateColumn && (
              <div
                style={{
                  ...cellStyle(columns, 'fundingRate', 56, numericCellStyle),
                  color: (sym.fundingRate ?? 0) > 0 ? 'var(--ts-color-bullish)' : (sym.fundingRate ?? 0) < 0 ? 'var(--ts-color-bearish)' : 'var(--ts-text-secondary)',
                }}
                data-testid="watchlist-funding"
              >
                {sym.fundingRate != null ? `${(sym.fundingRate * 100).toFixed(4)}%` : '--'}
              </div>
            )}
            {hasVolumeColumn && sym.volume !== undefined && (
              <div
                style={{
                  ...cellStyle(columns, 'volume', 56, volumeCellStyle),
                  background: heatMapRanges
                    ? getHeatColor(sym.volume, heatMapRanges.volume.min, heatMapRanges.volume.max, 'sequential')
                    : undefined,
                }}
                data-testid="watchlist-volume"
              >
                {formatCompactNumber(sym.volume, 1)}
              </div>
            )}
            {showSparklines && sym.sparklineData !== undefined && sym.sparklineData.length >= 2 && (
              <div style={sparklineCellStyle} data-testid="watchlist-sparkline">
                <SparklineChart data={sym.sparklineData} width={60} height={20} showFill={false} />
              </div>
            )}
            </div>
            {/* Action dash */}
            <div style={{ display: 'flex', alignItems: 'center', paddingRight: 10, paddingLeft: 4 }}>
              <span data-ts-action-dash="" style={{ display: 'inline-block', width: 16, height: 2, background: 'var(--ts-accent-default, #0D3791)', borderRadius: 1, opacity: 0.4 }} />
            </div>
          </div>
        </WatchlistContextMenu>
      );
    },
    [
      selectedSymbolId,
      sectionLabels,
      sections,
      columns,
      showSparklines,
      hasVolumeColumn,
      hasBidColumn,
      hasBidSizeColumn,
      hasOfferColumn,
      hasOfferSizeColumn,
      hasSpreadColumn,
      hasOpenColumn,
      hasHighColumn,
      hasLowColumn,
      hasChange1hColumn,
      hasChange7dColumn,
      hasChange30dColumn,
      hasRsiColumn,
      hasMacdColumn,
      hasBbPercentColumn,
      hasFundingRateColumn,
      dragOverSectionId,
      onSymbolSelect,
      onSectionToggle,
      onViewChart,
      onAddAlert,
      onViewDepth,
      onRemoveSymbol,
      onSymbolReorder,
      handleCopySymbol,
      handleDragStart,
      handleDragOver,
      handleDragLeave,
      handleDrop,
      heatMapRanges,
      onCrossAppDragStart,
      onSendToAnalytics,
      onSendToScreener,
    ],
  );

  /* --- Compact card row renderer (narrow layout) --- */
  const renderCompactItem = useCallback(
    (item: FlatItem) => {
      if (item.type === 'section') return null;

      const sym = item.symbol;
      const isSelected = selectedSymbolId === sym.id;
      const changeColor = (sym.priceChangePercent ?? 0) > 0
        ? 'var(--ts-color-bullish, #22c55e)'
        : (sym.priceChangePercent ?? 0) < 0
          ? 'var(--ts-color-bearish, #ef4444)'
          : 'var(--ts-text-secondary)';
      const barColor = (sym.priceChange ?? 0) < 0
        ? 'var(--ts-price-change-down-text, #FF6A00)'
        : 'var(--ts-accent-default, #0D3791)';

      return (
        <WatchlistContextMenu
          symbol={sym.id}
          sections={sectionLabels}
          onViewChart={onViewChart}
          onAddAlert={onAddAlert}
          onViewDepth={onViewDepth}
          onRemove={onRemoveSymbol}
          onMoveToSection={(symbolId, section) => {
            const targetSection = sections.find((s) => s.label === section);
            if (targetSection) {
              onSymbolReorder(symbolId, targetSection.id, 0);
            }
          }}
          onCopySymbol={handleCopySymbol}
          onSendToAnalytics={onSendToAnalytics}
          onSendToScreener={onSendToScreener}
        >
          <div
            data-ts-compact-row=""
            {...(isSelected ? { 'data-selected': '' } : {})}
            onClick={() => onSymbolSelect(sym.id)}
            onDoubleClick={() => onViewChart(sym.id)}
            onMouseDown={onCrossAppDragStart ? (e) => { if (e.button === 0) onCrossAppDragStart(sym.id, e); } : undefined}
            style={{
              display: 'flex',
              alignItems: 'stretch',
              padding: 0,
              borderBottom: '1px solid var(--ts-watchlist-row-border, #141414)',
              cursor: onCrossAppDragStart ? 'grab' : 'pointer',
              userSelect: 'none',
              transition: 'background 120ms',
              boxSizing: 'border-box',
              position: 'relative',
            }}
          >
            {/* Left colored bar */}
            <div
              data-ts-row-bar=""
              style={{
                width: 3,
                flexShrink: 0,
                borderRadius: '0 2px 2px 0',
                opacity: 0.3,
                background: barColor,
              }}
            />
            {/* Card body — two-line layout */}
            <div style={{ flex: 1, display: 'flex', flexDirection: 'column', padding: '8px 10px 8px 10px', gap: 2, minWidth: 0 }}>
              {/* Line 1: Symbol + Price + Sparkline */}
              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <span style={{
                  flex: 1,
                  color: 'var(--ts-watchlist-symbol-text, var(--ts-text-primary))',
                  fontWeight: 600,
                  fontSize: 'var(--ts-font-sm)',
                  lineHeight: 1.3,
                  whiteSpace: 'nowrap',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                }}>
                  {sym.symbol}
                </span>
                <span style={{
                  flexShrink: 0,
                  fontFamily: 'var(--ts-watchlist-price-font, var(--ts-font-data))',
                  fontVariantNumeric: 'tabular-nums',
                  fontSize: 'var(--ts-font-sm)',
                  fontWeight: 500,
                  color: 'var(--ts-text-primary)',
                  whiteSpace: 'nowrap',
                }}>
                  {sym.price != null ? formatPrice(sym.price, sym.precision ?? 2) : '--'}
                </span>
                {sym.sparklineData !== undefined && sym.sparklineData.length >= 2 && (
                  <div style={{ flexShrink: 0 }}>
                    <SparklineChart data={sym.sparklineData} width={48} height={18} showFill={false} />
                  </div>
                )}
              </div>
              {/* Line 2: Exchange + Change% badge + action */}
              <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                <span style={{
                  flex: 1,
                  color: 'var(--ts-watchlist-exchange-text, var(--ts-text-tertiary))',
                  fontSize: '10px',
                  lineHeight: 1.3,
                  whiteSpace: 'nowrap',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  textTransform: 'uppercase',
                  letterSpacing: '0.03em',
                }}>
                  {sym.exchange}
                </span>
                <span style={{
                  flexShrink: 0,
                  padding: '1px 6px',
                  borderRadius: '3px',
                  fontSize: '10px',
                  fontWeight: 600,
                  fontFamily: 'var(--ts-font-data)',
                  fontVariantNumeric: 'tabular-nums',
                  color: changeColor,
                  background: (sym.priceChangePercent ?? 0) > 0
                    ? 'var(--ts-color-bullish-subtle, rgba(34,197,94,0.12))'
                    : (sym.priceChangePercent ?? 0) < 0
                      ? 'var(--ts-color-bearish-subtle, rgba(239,68,68,0.12))'
                      : 'transparent',
                  whiteSpace: 'nowrap',
                }}>
                  {sym.priceChangePercent != null
                    ? `${sym.priceChangePercent >= 0 ? '+' : ''}${sym.priceChangePercent.toFixed(2)}%`
                    : '--'}
                </span>
                <span
                  data-ts-action-dash=""
                  style={{
                    display: 'inline-block',
                    width: 16,
                    height: 2,
                    background: 'var(--ts-accent-default, #0D3791)',
                    borderRadius: 1,
                    opacity: 0.4,
                    flexShrink: 0,
                  }}
                />
              </div>
            </div>
          </div>
        </WatchlistContextMenu>
      );
    },
    [
      selectedSymbolId,
      sectionLabels,
      sections,
      onSymbolSelect,
      onViewChart,
      onAddAlert,
      onViewDepth,
      onRemoveSymbol,
      onSymbolReorder,
      handleCopySymbol,
      onCrossAppDragStart,
      onSendToAnalytics,
      onSendToScreener,
    ],
  );

  const totalSymbols = sections.reduce((sum, s) => sum + s.symbols.length, 0);
  const compactRowHeight = 52;

  return (
    <div
      ref={ref}
      data-ts-watchlist-panel=""
      data-density={densityMode}
      data-layout={isCompact ? 'compact' : 'table'}
      style={panelStyle}
      data-testid="watchlist-panel"
    >
      <WatchlistHeader
        columns={columns}
        sortColumn={sortColumn}
        sortDirection={sortDirection}
        onSort={onSortChange}
        onSearchClick={onSearch}
        onAddSymbolClick={onAddSymbol}
        onColumnConfigClick={handleColumnConfigClick}
        onColumnResize={onColumnResize}
        viewMode={viewMode}
        onViewModeChange={onViewModeChange}
        viewModes={viewModes}
      />
      <div style={bodyStyle} data-ts-watchlist-panel-body="">
        {totalSymbols === 0 ? (
          <EmptyState
            icon={<ListPlus size={32} />}
            title="No symbols"
            description="Add symbols to your watchlist to start tracking."
          />
        ) : (
          <ScrollArea>
            <div>
              {flatItems.map((item, index) => (
                <div
                  key={item.type === 'section' ? `section-${item.sectionId}` : `symbol-${item.symbol.id}`}
                  style={{
                    height: item.type === 'symbol'
                      ? `${isCompact ? compactRowHeight : rowHeight}px`
                      : undefined,
                  }}
                >
                  {isCompact ? renderCompactItem(item) : renderItem(item, index)}
                </div>
              ))}
            </div>
          </ScrollArea>
        )}
      </div>
    </div>
  );
});
