/**
 * useTheme — React hook for theme management.
 *
 * Manages light/dark/system preference with:
 * - Synchronous localStorage persistence (no FOUC)
 * - prefers-color-scheme listener with 300ms debounce
 * - Chart-specific dark override (Bloomberg pattern)
 * - data-ts-theme attribute on document.documentElement
 */

import { useCallback, useEffect, useSyncExternalStore } from 'react';
import {
  THEME_STORAGE_KEY,
  CHART_THEME_STORAGE_KEY,
  THEME_ATTRIBUTE,
  CHART_THEME_ATTRIBUTE,
  resolveTheme,
  readStoredTheme,
  readStoredChartTheme,
  type ThemePreference,
  type ResolvedTheme,
  type ChartThemePreference,
} from './theme-init';

type ThemeSnapshot = {
  theme: ThemePreference;
  resolvedTheme: ResolvedTheme;
  chartTheme: ChartThemePreference;
};

/** Current cached snapshot */
let currentSnapshot: ThemeSnapshot = {
  theme: readStoredTheme(),
  resolvedTheme: resolveTheme(readStoredTheme()),
  chartTheme: readStoredChartTheme(),
};

/** Subscribers for useSyncExternalStore */
const listeners = new Set<() => void>();

function subscribe(listener: () => void): () => void {
  listeners.add(listener);
  return () => listeners.delete(listener);
}

function getSnapshot(): ThemeSnapshot {
  return currentSnapshot;
}

function emitChange(): void {
  for (const listener of listeners) {
    listener();
  }
}

/**
 * Apply the resolved theme to the DOM and update the snapshot.
 */
function applyTheme(preference: ThemePreference): void {
  const resolved = resolveTheme(preference);
  document.documentElement.setAttribute(THEME_ATTRIBUTE, resolved);

  try {
    localStorage.setItem(THEME_STORAGE_KEY, preference);
  } catch {
    // localStorage unavailable
  }

  currentSnapshot = {
    ...currentSnapshot,
    theme: preference,
    resolvedTheme: resolved,
  };
  emitChange();
}

/**
 * Apply chart theme to the DOM and update the snapshot.
 */
function applyChartTheme(chartTheme: ChartThemePreference): void {
  if (chartTheme === 'inherit') {
    document.documentElement.removeAttribute(CHART_THEME_ATTRIBUTE);
  } else {
    document.documentElement.setAttribute(CHART_THEME_ATTRIBUTE, chartTheme);
  }

  try {
    localStorage.setItem(CHART_THEME_STORAGE_KEY, chartTheme);
  } catch {
    // localStorage unavailable
  }

  currentSnapshot = {
    ...currentSnapshot,
    chartTheme,
  };
  emitChange();
}

/**
 * Listen for prefers-color-scheme changes with 300ms debounce.
 * Only matters when theme is set to 'system'.
 */
let systemListenerInitialized = false;

function initSystemListener(): void {
  if (systemListenerInitialized) return;
  systemListenerInitialized = true;

  const mql = window.matchMedia('(prefers-color-scheme: dark)');
  let debounceTimer: ReturnType<typeof setTimeout> | null = null;

  const handler = (): void => {
    if (debounceTimer !== null) {
      clearTimeout(debounceTimer);
    }
    debounceTimer = setTimeout(() => {
      debounceTimer = null;
      if (currentSnapshot.theme === 'system') {
        const resolved = resolveTheme('system');
        document.documentElement.setAttribute(THEME_ATTRIBUTE, resolved);
        currentSnapshot = {
          ...currentSnapshot,
          resolvedTheme: resolved,
        };
        emitChange();
      }
    }, 300);
  };

  mql.addEventListener('change', handler);
}

export type UseThemeReturn = {
  /** User-selected preference: 'light' | 'dark' | 'system' */
  theme: ThemePreference;
  /** Actual applied theme after resolving 'system' */
  resolvedTheme: ResolvedTheme;
  /** Chart-specific theme override */
  chartTheme: ChartThemePreference;
  /** Set the theme preference */
  setTheme: (theme: ThemePreference) => void;
  /** Set the chart-specific theme override */
  setChartTheme: (chartTheme: ChartThemePreference) => void;
};

/**
 * React hook for theme management.
 *
 * Uses useSyncExternalStore for tear-free reads.
 * The underlying state is a singleton shared across all hook instances.
 */
export function useTheme(): UseThemeReturn {
  useEffect(() => {
    initSystemListener();
  }, []);

  const snapshot = useSyncExternalStore(subscribe, getSnapshot, getSnapshot);

  const setTheme = useCallback((theme: ThemePreference) => {
    applyTheme(theme);
  }, []);

  const setChartTheme = useCallback((chartTheme: ChartThemePreference) => {
    applyChartTheme(chartTheme);
  }, []);

  return {
    theme: snapshot.theme,
    resolvedTheme: snapshot.resolvedTheme,
    chartTheme: snapshot.chartTheme,
    setTheme,
    setChartTheme,
  };
}
