import type { CSSProperties, MouseEventHandler } from 'react';
import { formatPrice } from './format-number';

/* -------------------------------------------------------------------------- */
/*  OrderBookRow                                                              */
/*  Single row in an order book showing price, size, total, and depth bar.    */
/*  Uses --ts-depth-* tokens.                                                 */
/* -------------------------------------------------------------------------- */

type OrderBookSide = 'bid' | 'ask';

export interface OrderBookRowProps {
  /** Price level. */
  price: number;
  /** Size at this price level. */
  size: number;
  /** Cumulative total up to this level. */
  total: number;
  /** Maximum cumulative total in the visible book (for depth bar width). */
  maxTotal: number;
  /** Bid or ask side. */
  side: OrderBookSide;
  /** Decimal places for price display. */
  precision?: number;
  /** Decimal places for size/quantity display. Defaults to 4. */
  sizePrecision?: number;
  /** Whether this is the best (top-of-book) level. */
  isBest?: boolean;
  /** Click handler, e.g., to fill price into order form. */
  onClick?: MouseEventHandler<HTMLDivElement>;
}

/* ----- Style injection for hover ----------------------------------------- */

const DEPTH_STYLE_ID = 'ts-depth-row-styles';

function ensureDepthStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(DEPTH_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = DEPTH_STYLE_ID;
  sheet.textContent = `
    [data-ts-depth-row]:hover {
      background-color: var(--ts-depth-row-bg-hover);
    }
    [data-ts-depth-row] .ts-data-value {
      transition: color 0.15s ease-out;
    }
    [data-ts-depth-bar] {
      transition: width 0.2s ease-out, opacity 0.15s ease-out;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureDepthStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rowStyle: CSSProperties = {
  display: 'grid',
  gridTemplateColumns: '1.5fr 1fr 1fr',
  alignItems: 'center',
  height: 'var(--ts-depth-row-height)',
  fontFamily: 'var(--ts-depth-row-font)',
  fontSize: 'var(--ts-depth-row-font-size)',
  fontVariantNumeric: 'tabular-nums',
  position: 'relative',
  cursor: 'pointer',
  userSelect: 'none',
  padding: '0 var(--ts-space-2)',
  boxSizing: 'border-box',
};

const depthBarBaseStyle: CSSProperties = {
  position: 'absolute',
  top: 0,
  bottom: 0,
  pointerEvents: 'none',
};

const cellStyle: CSSProperties = {
  position: 'relative',
  zIndex: 1,
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
};

const SIDE_CONFIG: Record<OrderBookSide, {
  priceColor: string;
  barBg: string;
  barOpacity: string;
  barSide: 'left' | 'right';
}> = {
  bid: {
    priceColor: 'var(--ts-depth-bid-text)',
    barBg: 'var(--ts-depth-bid-bar)',
    barOpacity: 'var(--ts-depth-bid-bar-opacity)',
    barSide: 'right',
  },
  ask: {
    priceColor: 'var(--ts-depth-ask-text)',
    barBg: 'var(--ts-depth-ask-bar)',
    barOpacity: 'var(--ts-depth-ask-bar-opacity)',
    barSide: 'right',
  },
};

/* ----- Component --------------------------------------------------------- */

export function OrderBookRow({
  price,
  size,
  total,
  maxTotal,
  side,
  precision = 2,
  sizePrecision = 4,
  isBest = false,
  onClick,
}: OrderBookRowProps): React.JSX.Element {
  const config = SIDE_CONFIG[side];
  const depthPercent = maxTotal > 0 ? (total / maxTotal) * 100 : 0;

  const depthBarStyle: CSSProperties = {
    ...depthBarBaseStyle,
    [config.barSide]: 0,
    width: `${depthPercent.toFixed(2)}%`,
    background: config.barBg,
    opacity: config.barOpacity,
  };

  const priceCellStyle: CSSProperties = {
    ...cellStyle,
    color: config.priceColor,
    fontWeight: isBest ? 'var(--ts-font-weight-medium)' as unknown as number : undefined,
  };

  const sizeCellStyle: CSSProperties = {
    ...cellStyle,
    textAlign: 'right',
    color: 'var(--ts-text-primary)',
  };

  const totalCellStyle: CSSProperties = {
    ...cellStyle,
    textAlign: 'right',
    color: 'var(--ts-text-secondary)',
  };

  const bestRowStyle: CSSProperties = isBest
    ? { ...rowStyle, background: 'var(--ts-depth-best-row-bg)' }
    : rowStyle;

  return (
    <div
      data-ts-depth-row=""
      data-side={side}
      {...(isBest ? { 'data-best': '' } : {})}
      style={bestRowStyle}
      onClick={onClick}
      role="row"
      data-testid="order-book-row"
    >
      <div style={depthBarStyle} aria-hidden="true" data-testid="depth-bar" data-ts-depth-bar="" />
      <span className="ts-data-value" style={priceCellStyle} role="cell" data-testid="ob-price">
        {formatPrice(price, precision)}
      </span>
      <span className="ts-data-value" style={sizeCellStyle} role="cell" data-testid="ob-size">
        {formatPrice(size, sizePrecision)}
      </span>
      <span className="ts-data-value" style={totalCellStyle} role="cell" data-testid="ob-total">
        {formatPrice(total, precision)}
      </span>
    </div>
  );
}

OrderBookRow.displayName = 'OrderBookRow';
