import { useState, useCallback, useRef, type CSSProperties } from 'react';
import { Select, Button, Dialog, Input } from '@deskmodal/ui-components';
import type { FileFormat, CustomFileSource } from '../hooks/use-custom-sources';

/* -------------------------------------------------------------------------- */
/*  FileImportForm                                                            */
/*  Form for importing data from CSV, JSON, or Parquet files.                 */
/* -------------------------------------------------------------------------- */

export interface FileImportFormProps {
  /** Whether the dialog is open. */
  readonly open: boolean;
  /** Close the dialog. */
  readonly onOpenChange: (open: boolean) => void;
  /** Called with the completed source config when saved. */
  readonly onSave: (source: Omit<CustomFileSource, 'id' | 'createdAt'>) => void;
}

/* ----- Styles ------------------------------------------------------------ */

const formStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-3)',
  marginTop: 'var(--ts-space-3)',
};

const fieldGroupStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-1)',
};

const labelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  fontWeight: 500,
  color: 'var(--ts-text-secondary)',
};

const rowStyle: CSSProperties = {
  display: 'flex',
  gap: 'var(--ts-space-2)',
};

const sectionLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  textTransform: 'uppercase',
  letterSpacing: '0.03em',
  marginTop: 'var(--ts-space-2)',
};

const actionsStyle: CSSProperties = {
  display: 'flex',
  justifyContent: 'flex-end',
  gap: 'var(--ts-space-2)',
  marginTop: 'var(--ts-space-2)',
};

const dropZoneStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  gap: 'var(--ts-space-2)',
  padding: 'var(--ts-space-4)',
  border: '2px dashed var(--ts-panel-border)',
  borderRadius: 'var(--ts-radius-sm)',
  background: 'var(--ts-panel-bg)',
  cursor: 'pointer',
  transition: 'border-color 150ms',
};

const dropZoneTextStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-secondary)',
};

const fileNameStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  fontWeight: 500,
  color: 'var(--ts-text-primary)',
};

const previewContainerStyle: CSSProperties = {
  maxHeight: 120,
  overflow: 'auto',
  padding: 'var(--ts-space-2)',
  background: 'var(--ts-panel-bg)',
  border: '1px solid var(--ts-panel-border)',
  borderRadius: 'var(--ts-radius-sm)',
  fontFamily: 'monospace',
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-secondary)',
  whiteSpace: 'pre',
  lineHeight: 1.5,
};

/* ----- Select options ---------------------------------------------------- */

const FORMAT_OPTIONS = [
  { value: 'csv', label: 'CSV' },
  { value: 'json', label: 'JSON' },
  { value: 'parquet', label: 'Parquet' },
];

/** Detect file format from file extension. */
function detectFormat(fileName: string): FileFormat {
  const ext = fileName.split('.').pop()?.toLowerCase();
  if (ext === 'json' || ext === 'jsonl') return 'json';
  if (ext === 'parquet') return 'parquet';
  return 'csv';
}

/** Parse the first few lines of a CSV to detect columns. */
function detectCsvColumns(content: string): string[] {
  const firstLine = content.split('\n')[0];
  if (!firstLine) return [];
  return firstLine.split(',').map((col) => col.trim().replace(/^["']|["']$/g, ''));
}

/** Parse JSON content to detect top-level keys. */
function detectJsonColumns(content: string): string[] {
  try {
    const parsed = JSON.parse(content);
    const firstItem = Array.isArray(parsed) ? parsed[0] : parsed;
    if (firstItem && typeof firstItem === 'object') {
      return Object.keys(firstItem);
    }
  } catch {
    // Invalid JSON
  }
  return [];
}

export function FileImportForm({
  open,
  onOpenChange,
  onSave,
}: FileImportFormProps): React.JSX.Element {
  const [fileName, setFileName] = useState('');
  const [format, setFormat] = useState<FileFormat>('csv');
  const [preview, setPreview] = useState('');
  const [detectedColumns, setDetectedColumns] = useState<string[]>([]);
  const [priceColumn, setPriceColumn] = useState('');
  const [volumeColumn, setVolumeColumn] = useState('');
  const [timestampColumn, setTimestampColumn] = useState('');
  const [symbolColumn, setSymbolColumn] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isValid = fileName.length > 0 && priceColumn.length > 0;

  const handleFileSelect = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    const detectedFormat = detectFormat(file.name);
    setFormat(detectedFormat);

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      const previewText = content.slice(0, 500);
      setPreview(previewText);

      let columns: string[] = [];
      if (detectedFormat === 'csv') {
        columns = detectCsvColumns(content);
      } else if (detectedFormat === 'json') {
        columns = detectJsonColumns(content);
      }
      setDetectedColumns(columns);

      // Auto-detect common column names
      for (const col of columns) {
        const lower = col.toLowerCase();
        if (lower.includes('price') || lower === 'close' || lower === 'last') {
          setPriceColumn(col);
        } else if (lower.includes('volume') || lower === 'vol') {
          setVolumeColumn(col);
        } else if (lower.includes('time') || lower.includes('date') || lower === 'ts') {
          setTimestampColumn(col);
        } else if (lower.includes('symbol') || lower.includes('pair') || lower.includes('ticker')) {
          setSymbolColumn(col);
        }
      }
    };
    reader.readAsText(file.slice(0, 10_000));
  }, []);

  const handleDropZoneClick = useCallback(() => {
    fileInputRef.current?.click();
  }, []);

  const handleSave = useCallback(() => {
    onSave({
      type: 'file-import',
      name: fileName.replace(/\.[^.]+$/, ''),
      fileName,
      format,
      columnMapping: {
        priceColumn,
        volumeColumn,
        timestampColumn,
        symbolColumn,
      },
    });

    onOpenChange(false);
  }, [fileName, format, priceColumn, volumeColumn, timestampColumn, symbolColumn, onSave, onOpenChange]);

  const columnOptions = detectedColumns.map((col) => ({ value: col, label: col }));

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <Dialog.Content>
        <Dialog.Title>File Import</Dialog.Title>
        <Dialog.Description>
          Import market data from a local file. Supported formats: CSV, JSON, Parquet.
        </Dialog.Description>

        <div style={formStyle}>
          {/* File picker */}
          <input
            ref={fileInputRef}
            type="file"
            accept=".csv,.json,.jsonl,.parquet"
            onChange={handleFileSelect}
            style={{ display: 'none' }}
          />

          <div
            style={dropZoneStyle}
            onClick={handleDropZoneClick}
            onKeyDown={(e) => {
              if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                handleDropZoneClick();
              }
            }}
            role="button"
            tabIndex={0}
          >
            {fileName ? (
              <span style={fileNameStyle}>{fileName}</span>
            ) : (
              <span style={dropZoneTextStyle}>Click to select a file</span>
            )}
            <span style={{ fontSize: 'var(--ts-font-xs)', color: 'var(--ts-text-tertiary)' }}>
              CSV, JSON, or Parquet
            </span>
          </div>

          {/* Format selector */}
          <div style={fieldGroupStyle}>
            <label style={labelStyle}>Format</label>
            <Select
              options={FORMAT_OPTIONS}
              value={format}
              onValueChange={(v) => setFormat(v as FileFormat)}
              size="sm"
            />
          </div>

          {/* Preview */}
          {preview.length > 0 && (
            <div style={fieldGroupStyle}>
              <label style={labelStyle}>Preview</label>
              <div style={previewContainerStyle}>{preview}</div>
            </div>
          )}

          {/* Column mapping */}
          {detectedColumns.length > 0 && (
            <>
              <span style={sectionLabelStyle}>Column Mapping</span>

              <div style={rowStyle}>
                <div style={{ ...fieldGroupStyle, flex: 1 }}>
                  <label style={labelStyle}>Price Column</label>
                  {columnOptions.length > 0 ? (
                    <Select
                      options={columnOptions}
                      value={priceColumn}
                      onValueChange={setPriceColumn}
                      size="sm"
                      placeholder="Select..."
                    />
                  ) : (
                    <Input
                      value={priceColumn}
                      onChange={(e) => setPriceColumn(e.target.value)}
                      size="sm"
                      style={{ width: '100%' }}
                    />
                  )}
                </div>
                <div style={{ ...fieldGroupStyle, flex: 1 }}>
                  <label style={labelStyle}>Volume Column</label>
                  {columnOptions.length > 0 ? (
                    <Select
                      options={columnOptions}
                      value={volumeColumn}
                      onValueChange={setVolumeColumn}
                      size="sm"
                      placeholder="Select..."
                    />
                  ) : (
                    <Input
                      value={volumeColumn}
                      onChange={(e) => setVolumeColumn(e.target.value)}
                      size="sm"
                      style={{ width: '100%' }}
                    />
                  )}
                </div>
              </div>

              <div style={rowStyle}>
                <div style={{ ...fieldGroupStyle, flex: 1 }}>
                  <label style={labelStyle}>Timestamp Column</label>
                  {columnOptions.length > 0 ? (
                    <Select
                      options={columnOptions}
                      value={timestampColumn}
                      onValueChange={setTimestampColumn}
                      size="sm"
                      placeholder="Select..."
                    />
                  ) : (
                    <Input
                      value={timestampColumn}
                      onChange={(e) => setTimestampColumn(e.target.value)}
                      size="sm"
                      style={{ width: '100%' }}
                    />
                  )}
                </div>
                <div style={{ ...fieldGroupStyle, flex: 1 }}>
                  <label style={labelStyle}>Symbol Column</label>
                  {columnOptions.length > 0 ? (
                    <Select
                      options={columnOptions}
                      value={symbolColumn}
                      onValueChange={setSymbolColumn}
                      size="sm"
                      placeholder="Select..."
                    />
                  ) : (
                    <Input
                      value={symbolColumn}
                      onChange={(e) => setSymbolColumn(e.target.value)}
                      size="sm"
                      style={{ width: '100%' }}
                    />
                  )}
                </div>
              </div>
            </>
          )}

          <div style={actionsStyle}>
            <Dialog.Close>
              <Button variant="ghost" size="sm">
                Cancel
              </Button>
            </Dialog.Close>
            <Button
              variant="primary"
              size="sm"
              onClick={handleSave}
              disabled={!isValid}
            >
              Import
            </Button>
          </div>
        </div>
      </Dialog.Content>
    </Dialog>
  );
}

FileImportForm.displayName = 'FileImportForm';
