import type {
  NormalizedOHLCV,
  NormalizedOrderbook,
  NormalizedTick,
  NormalizedTrade,
} from '../types/normalized';

/**
 * Generic message normalizer interface for exchange-specific raw messages.
 *
 * Each exchange adapter implements this interface to convert raw WebSocket
 * messages into normalized Deskmodal data types.
 *
 * Normalization guarantees:
 * 1. All timestamps are milliseconds since Unix epoch (UTC)
 * 2. All prices and volumes are JavaScript numbers (not strings)
 * 3. Symbols are in "BASE/QUOTE" format
 * 4. Order book bids sorted descending, asks ascending
 * 5. Trade side is always 'buy' or 'sell'
 */
export interface MessageNormalizer<TRaw> {
  /** Parse a raw WebSocket message string into the exchange-specific type. Returns undefined for unrecognized messages. */
  parseMessage(raw: string): TRaw | undefined;
  /** Normalize a raw message into a ticker update. Returns undefined if the message is not a ticker. */
  normalizeTicker(raw: TRaw): NormalizedTick | undefined;
  /** Normalize a raw message into a trade execution. Returns undefined if the message is not a trade. */
  normalizeTrade(raw: TRaw): NormalizedTrade | undefined;
  /** Normalize a raw message into an OHLCV candle. Returns undefined if the message is not a kline/candle. */
  normalizeOHLCV(raw: TRaw): NormalizedOHLCV | undefined;
  /** Normalize a raw message into an order book snapshot or delta. Returns undefined if not an orderbook message. */
  normalizeOrderbook(raw: TRaw): NormalizedOrderbook | undefined;
}

/** Convert an exchange-native symbol to the canonical BASE/QUOTE format. */
export function toNormalizedSymbol(exchangeSymbol: string, exchangeId: string): string {
  switch (exchangeId) {
    case 'coinbase':
    case 'okx':
      // BTC-USD or BTC-USDT -> BTC/USD or BTC/USDT
      return exchangeSymbol.replace('-', '/');
    case 'binance':
    case 'bybit':
      // BTCUSDT -> requires known quote currencies
      return splitConcatenatedSymbol(exchangeSymbol);
    case 'uniswap-v3':
    case 'raydium':
      // Already normalized or pool addresses
      return exchangeSymbol.includes('/') ? exchangeSymbol : exchangeSymbol;
    default:
      return exchangeSymbol;
  }
}

const KNOWN_QUOTE_CURRENCIES = [
  'USDT', 'USDC', 'BUSD', 'TUSD', 'FDUSD', 'USD',
  'BTC', 'ETH', 'BNB', 'SOL', 'EUR', 'GBP', 'TRY',
  'DAI', 'USDD', 'XRP', 'DOGE', 'DOT', 'AUD', 'BRL',
] as const;

/**
 * Split a concatenated symbol (e.g., "BTCUSDT") into BASE/QUOTE format.
 * Tries known quote currencies from longest to shortest to avoid ambiguity.
 */
export function splitConcatenatedSymbol(symbol: string): string {
  const upper = symbol.toUpperCase();
  // Sort by length descending to match longest quote first (e.g., FDUSD before USD)
  const sorted = [...KNOWN_QUOTE_CURRENCIES].sort((a, b) => b.length - a.length);
  for (const quote of sorted) {
    if (upper.endsWith(quote) && upper.length > quote.length) {
      const base = upper.slice(0, upper.length - quote.length);
      return `${base}/${quote}`;
    }
  }
  return upper;
}

/** Parse a numeric string to a number, returning 0 for invalid values. */
export function parseNumeric(value: string | number | undefined): number {
  if (value === undefined) return 0;
  if (typeof value === 'number') return value;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : 0;
}

/** Convert an RFC 3339 timestamp string to milliseconds since epoch. */
export function rfc3339ToMs(timestamp: string): number {
  const ms = Date.parse(timestamp);
  return Number.isFinite(ms) ? ms : 0;
}

/** Convert seconds since epoch to milliseconds. */
export function secondsToMs(seconds: number): number {
  return Math.floor(seconds * 1000);
}

/** Generate a unique subscription ID. */
export function createSubscriptionId(exchangeId: string, type: string, symbol: string): string {
  return `${exchangeId}:${type}:${symbol}:${Date.now()}:${Math.random().toString(36).slice(2, 8)}`;
}
