import type { Context } from '@deskmodal/fdc3';
import { CUSTOM_INTENTS } from '@deskmodal/fdc3';
import type { DeskmodalCredentialPayload } from '@deskmodal/fdc3';

/* -------------------------------------------------------------------------- */
/*  Price Feed Client                                                          */
/*  Type-safe FDC3 intent client for the native price-feed service.            */
/* -------------------------------------------------------------------------- */

/** Result of a command intent (connect, disconnect, subscribe, etc.). */
export interface CommandResult {
  readonly success: boolean;
  readonly error?: string;
}

/** Status of a single exchange as reported by the price-feed service. */
export interface FeedStatusExchange {
  readonly exchangeId: string;
  readonly connected: boolean;
  readonly tickCount: number;
  readonly errorCount: number;
  readonly lastTickTime?: number;
  readonly uptimeStart?: number;
  readonly circuitBreakerState: string;
  /** Number of symbols currently subscribed on this exchange. */
  readonly subscribedCount?: number;
}

/** Aggregate feed status across all exchanges. */
export interface FeedStatus {
  readonly exchanges: FeedStatusExchange[];
}

/** Price tick received on the prices channel. */
export interface PriceTick {
  readonly exchangeId: string;
  readonly symbol: string;
  readonly price: number;
  readonly volume24h?: number;
  readonly priceChangePercent?: number;
  readonly bestBid?: number;
  readonly bestAsk?: number;
  readonly spread?: number;
  readonly timestamp: number;
}

/** Structured log helper — routes to DeskModal logging if available. */
function structuredLog(level: 'error' | 'warn' | 'info', message: string): void {
  const win = window as { deskmodal?: { log?: (level: string, msg: string) => void } };
  if (win.deskmodal?.log) {
    win.deskmodal.log(level, message);
  }
}

/** Options for the withRetry utility. */
export interface RetryOptions {
  /** Maximum number of attempts (including the initial call). Default: 3. */
  readonly maxAttempts?: number;
  /** Base delay in milliseconds before the first retry. Default: 1000. */
  readonly baseDelayMs?: number;
  /** Maximum delay in milliseconds (caps exponential growth). Default: 10000. */
  readonly maxDelayMs?: number;
}

/** Default retry configuration. */
const DEFAULT_RETRY_OPTIONS: Required<RetryOptions> = {
  maxAttempts: 3,
  baseDelayMs: 1000,
  maxDelayMs: 10_000,
};

/**
 * Returns true if the error should NOT be retried.
 * Non-retryable: user cancellation (AbortError) or invalid argument errors.
 */
function isNonRetryable(err: unknown): boolean {
  if (!(err instanceof Error)) return false;
  const name = err.name.toLowerCase();
  const msg = err.message.toLowerCase();
  // AbortError from AbortController / user cancellation
  if (name === 'aborterror' || msg.includes('aborted') || msg.includes('cancelled') || msg.includes('canceled')) return true;
  // Invalid argument / bad request errors
  if (msg.includes('invalid argument') || msg.includes('bad request') || msg.includes('validation failed')) return true;
  return false;
}

/**
 * Retry a function with exponential backoff and jitter.
 * Delay formula: min(maxDelayMs, baseDelayMs * 2^attempt) + random(0, baseDelayMs * 0.5)
 * Does NOT retry on user cancellation or invalid argument errors.
 * Throws the last error if all attempts fail.
 */
export async function withRetry<T>(
  fn: () => Promise<T>,
  options?: RetryOptions,
): Promise<T> {
  const { maxAttempts, baseDelayMs, maxDelayMs } = { ...DEFAULT_RETRY_OPTIONS, ...options };
  let lastError: unknown;
  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (err) {
      lastError = err;
      // Don't retry non-retryable errors
      if (isNonRetryable(err)) {
        throw err;
      }
      if (attempt < maxAttempts - 1) {
        const exponentialDelay = baseDelayMs * Math.pow(2, attempt);
        const jitter = Math.random() * baseDelayMs * 0.5;
        const delayMs = Math.min(maxDelayMs, exponentialDelay) + jitter;
        structuredLog('warn', `[price-feed-client] Retry ${attempt + 1}/${maxAttempts} after ${Math.round(delayMs)}ms: ${String(err)}`);
        await new Promise<void>((resolve) => {
          setTimeout(resolve, delayMs);
        });
      }
    }
  }
  throw lastError;
}

/**
 * Resolve the result context from an IntentResolution.
 * Returns the resolved context cast to the expected type, or a default
 * success result if the intent resolved without a context payload.
 */
async function resolveIntent<T>(
  intent: string,
  context: Context,
): Promise<T> {
  const fdc3 = window.fdc3;
  if (!fdc3) {
    throw new Error('FDC3 Desktop Agent not available');
  }

  const resolution = await fdc3.raiseIntent(intent, context);
  const result = await resolution.getResult();

  // Intent handlers return a Context; cast to expected shape.
  // If no result (void), return a default success.
  if (!result) {
    return { success: true } as unknown as T;
  }

  return result as unknown as T;
}

/**
 * Type-safe client for communicating with the native price-feed service
 * via FDC3 intents. All exchange connectivity is handled by the service;
 * this client sends commands and receives results.
 */
export class PriceFeedClient {
  /** Request the service to connect to an exchange (with retry). */
  async connect(exchangeId: string): Promise<CommandResult> {
    return withRetry(
      () => resolveIntent<CommandResult>(CUSTOM_INTENTS.ConnectExchange, {
        type: 'deskmodal.command',
        id: { action: 'connect' },
        exchangeId,
      } as Context),
      { maxAttempts: 2, baseDelayMs: 500 },
    );
  }

  /** Request the service to disconnect from an exchange (with retry). */
  async disconnect(exchangeId: string): Promise<CommandResult> {
    return withRetry(
      () => resolveIntent<CommandResult>(CUSTOM_INTENTS.DisconnectExchange, {
        type: 'deskmodal.command',
        id: { action: 'disconnect' },
        exchangeId,
      } as Context),
      { maxAttempts: 2, baseDelayMs: 500 },
    );
  }

  /** Request the service to subscribe to a symbol on an exchange (with retry). */
  async subscribe(exchangeId: string, symbol: string): Promise<CommandResult> {
    return withRetry(
      () => resolveIntent<CommandResult>(CUSTOM_INTENTS.SubscribePrices, {
        type: 'deskmodal.command',
        id: { action: 'subscribe' },
        exchangeId,
        symbol,
      } as Context),
      { maxAttempts: 3, baseDelayMs: 1000 },
    );
  }

  /** Request the service to unsubscribe from a symbol on an exchange (with retry). */
  async unsubscribe(exchangeId: string, symbol: string): Promise<CommandResult> {
    return withRetry(
      () => resolveIntent<CommandResult>(CUSTOM_INTENTS.UnsubscribePrices, {
        type: 'deskmodal.command',
        id: { action: 'unsubscribe' },
        exchangeId,
        symbol,
      } as Context),
      { maxAttempts: 3, baseDelayMs: 1000 },
    );
  }

  /** Query the current status of all exchanges (or a specific one), with retry. */
  async getStatus(exchangeId?: string): Promise<FeedStatus> {
    return withRetry(
      () => {
        const context: Record<string, unknown> = {
          type: 'deskmodal.command',
          id: { action: 'getStatus' },
        };
        if (exchangeId) {
          context['exchangeId'] = exchangeId;
        }
        return resolveIntent<FeedStatus>(CUSTOM_INTENTS.GetStatus, context as unknown as Context);
      },
      { maxAttempts: 3, baseDelayMs: 1000 },
    );
  }

  /**
   * Store credentials for an exchange in the OS keychain via DeskModal extension API.
   * SECURITY: Credentials never transit FDC3 channels.
   * Retry covers the reconnect step, not the keychain writes (those are local).
   */
  async setCredentials(
    exchangeId: string,
    credentials: DeskmodalCredentialPayload,
  ): Promise<CommandResult> {
    const win = window as { deskmodal?: { secretSet: (key: string, value: string) => Promise<void> } };
    if (!win.deskmodal?.secretSet) {
      throw new Error('DeskModal secretSet API not available');
    }
    const prefix = `price-feed.${exchangeId}`;
    await win.deskmodal.secretSet(`${prefix}.api_key`, credentials.apiKey);
    await win.deskmodal.secretSet(`${prefix}.api_secret`, credentials.apiSecret);
    if (credentials.passphrase) {
      await win.deskmodal.secretSet(`${prefix}.passphrase`, credentials.passphrase);
    }
    // Trigger reconnect to pick up new credentials
    return this.connect(exchangeId);
  }

  /** Request historical candle data from the service (with retry). */
  async getHistory(
    exchangeId: string,
    symbol: string,
    interval: string,
    limit: number,
    startTime?: number,
    endTime?: number,
  ): Promise<{ candles: Array<{ timestamp: number; open: number; high: number; low: number; close: number; volume: number }> }> {
    const context: Record<string, unknown> = {
      type: 'deskmodal.command',
      id: { action: 'getHistory' },
      exchangeId,
      symbol,
      interval,
      limit,
    };

    if (startTime !== undefined) {
      context['startTime'] = startTime;
    }
    if (endTime !== undefined) {
      context['endTime'] = endTime;
    }

    return withRetry(
      () => resolveIntent<{ candles: Array<{ timestamp: number; open: number; high: number; low: number; close: number; volume: number }> }>(
        CUSTOM_INTENTS.GetHistory,
        context as unknown as Context,
      ),
      { maxAttempts: 3, baseDelayMs: 1000 },
    );
  }

  /**
   * Lightweight health check ping. Returns true if the service responds.
   * Used by the active health check polling to detect crashes quickly.
   */
  async healthCheck(): Promise<boolean> {
    try {
      await resolveIntent<CommandResult>(CUSTOM_INTENTS.HealthCheck, {
        type: 'deskmodal.command',
        id: { action: 'healthCheck' },
      } as Context);
      return true;
    } catch {
      return false;
    }
  }
}

/** Singleton client instance shared across the app. */
export const priceFeedClient = new PriceFeedClient();
