import { useCallback, type CSSProperties, type KeyboardEvent } from 'react';
import { Pause, Play } from 'lucide-react';
import { Badge } from '../primitives';
import type { TradeSide } from './TradeRow';

/* -------------------------------------------------------------------------- */
/*  TradeHistoryControls                                                       */
/*  Compact toolbar for filtering and pausing the trade history feed.          */
/*  Uses --ts-toolbar-* and --ts-trade-* tokens.                               */
/* -------------------------------------------------------------------------- */

export interface TradeHistoryControlsProps {
  /** Minimum trade size to display (filter threshold). 0 = show all. */
  sizeFilter: number;
  /** Called when size filter changes. */
  onSizeFilterChange: (size: number) => void;
  /** Filter by trade side. null = show both. */
  sideFilter: TradeSide | null;
  /** Called when side filter changes. */
  onSideFilterChange: (side: TradeSide | null) => void;
  /** Whether the trade feed is paused. */
  paused: boolean;
  /** Called when pause state changes. */
  onPausedChange: (paused: boolean) => void;
  /** Total number of trades (displayed as info). */
  tradeCount: number;
}

/* ----- Style injection --------------------------------------------------- */

const TRADE_CONTROLS_STYLE_ID = 'ts-trade-controls-styles';

function ensureTradeControlsStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(TRADE_CONTROLS_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = TRADE_CONTROLS_STYLE_ID;
  sheet.textContent = `
    [data-ts-trade-controls] input:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-side-filter-btn]:hover:not([data-active]) {
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-side-filter-btn]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-trade-pause-btn]:hover {
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-trade-pause-btn]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureTradeControlsStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rootStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  padding: 'var(--ts-space-1) var(--ts-space-2)',
  borderBottom: '1px solid var(--ts-toolbar-border)',
  background: 'var(--ts-toolbar-bg)',
  flexWrap: 'wrap',
  flexShrink: 0,
};

const sizeInputStyle: CSSProperties = {
  all: 'unset',
  width: 56,
  height: 'var(--ts-input-height-sm)',
  padding: '0 var(--ts-space-1)',
  fontSize: 'var(--ts-font-sm)',
  fontFamily: 'var(--ts-font-data)',
  fontVariantNumeric: 'tabular-nums',
  color: 'var(--ts-input-text)',
  background: 'var(--ts-input-bg)',
  border: '1px solid var(--ts-input-border)',
  borderRadius: 'var(--ts-input-radius)',
  boxSizing: 'border-box',
};

const labelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  whiteSpace: 'nowrap',
  userSelect: 'none',
};

const segmentGroupStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '1px',
  borderRadius: 'var(--ts-radius-sm)',
  overflow: 'hidden',
};

function segmentBtnStyle(active: boolean): CSSProperties {
  return {
    all: 'unset',
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    height: 'var(--ts-input-height-sm)',
    padding: '0 var(--ts-space-2)',
    fontSize: 'var(--ts-font-xs)',
    fontFamily: 'inherit',
    color: active ? 'var(--ts-text-primary)' : 'var(--ts-text-secondary)',
    background: active ? 'var(--ts-button-ghost-bg-active)' : 'var(--ts-button-ghost-bg)',
    cursor: 'pointer',
    userSelect: 'none',
    boxSizing: 'border-box',
    borderRadius: 'var(--ts-radius-sm)',
  };
}

const pauseBtnStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-icon-button-size-sm)',
  height: 'var(--ts-icon-button-size-sm)',
  borderRadius: 'var(--ts-button-radius)',
  color: 'var(--ts-text-secondary)',
  cursor: 'pointer',
  boxSizing: 'border-box',
};

const spacerStyle: CSSProperties = {
  flex: '1 1 auto',
};

const countStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  fontVariantNumeric: 'tabular-nums',
  whiteSpace: 'nowrap',
};

/* ----- Component --------------------------------------------------------- */

const SIDE_OPTIONS: Array<{ value: TradeSide | null; label: string }> = [
  { value: null, label: 'All' },
  { value: 'buy', label: 'Buy' },
  { value: 'sell', label: 'Sell' },
];

export function TradeHistoryControls({
  sizeFilter,
  onSizeFilterChange,
  sideFilter,
  onSideFilterChange,
  paused,
  onPausedChange,
  tradeCount,
}: TradeHistoryControlsProps): React.JSX.Element {
  const handleSizeChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const val = parseFloat(e.target.value);
      onSizeFilterChange(Number.isNaN(val) ? 0 : val);
    },
    [onSizeFilterChange],
  );

  const handlePauseKeyDown = useCallback(
    (e: KeyboardEvent<HTMLButtonElement>) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        onPausedChange(!paused);
      }
    },
    [paused, onPausedChange],
  );

  const formattedCount = tradeCount.toLocaleString();

  return (
    <div data-ts-trade-controls="" style={rootStyle} data-testid="trade-controls">
      <span style={labelStyle}>Min Size</span>
      <input
        type="number"
        value={sizeFilter || ''}
        onChange={handleSizeChange}
        placeholder="0"
        style={sizeInputStyle}
        aria-label="Minimum trade size"
        data-testid="trade-size-filter"
        min={0}
        step="any"
      />

      <div style={segmentGroupStyle} role="radiogroup" aria-label="Side filter">
        {SIDE_OPTIONS.map(({ value, label }) => {
          const active = sideFilter === value;
          return (
            <button
              key={label}
              type="button"
              role="radio"
              data-ts-side-filter-btn=""
              {...(active ? { 'data-active': '' } : {})}
              aria-checked={active}
              aria-label={`Show ${label.toLowerCase()} trades`}
              style={segmentBtnStyle(active)}
              onClick={() => onSideFilterChange(value)}
              data-testid={`side-filter-${label.toLowerCase()}`}
            >
              {label}
            </button>
          );
        })}
      </div>

      <button
        type="button"
        data-ts-trade-pause-btn=""
        style={pauseBtnStyle}
        onClick={() => onPausedChange(!paused)}
        onKeyDown={handlePauseKeyDown}
        aria-label={paused ? 'Resume feed' : 'Pause feed'}
        data-testid="trade-pause-btn"
      >
        {paused ? <Play size={14} aria-hidden /> : <Pause size={14} aria-hidden />}
      </button>

      <div style={spacerStyle} />

      <span style={countStyle} data-testid="trade-count">
        {formattedCount} trades
      </span>
    </div>
  );
}

TradeHistoryControls.displayName = 'TradeHistoryControls';
