import { useCallback, type CSSProperties } from 'react';
import { Select, NumberInput, IconButton } from '../../primitives';
import { X } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  ConditionRow                                                              */
/*  Single condition row: Source Select | Operator Select | Value Input |     */
/*  Remove button. Used by ConditionBuilder for AND/OR chaining.              */
/*  Uses --ts-input-* tokens.                                                 */
/* -------------------------------------------------------------------------- */

export interface ConditionRowProps {
  /** Unique condition ID. */
  id: string;
  /** Row index (1-based, for aria-label). */
  index: number;
  /** Current source value. */
  source: string;
  /** Current operator value. */
  operator: string;
  /** Current value. */
  value: number | string;
  /** Available sources. */
  sources: Array<{ value: string; label: string; group: string }>;
  /** Available operators. */
  operators: Array<{ value: string; label: string }>;
  /** Called when any field changes. */
  onChange: (id: string, field: 'source' | 'operator' | 'value', newValue: string | number) => void;
  /** Called when the remove button is clicked. */
  onRemove: (id: string) => void;
  /** Whether the remove button is visible (hidden when only 1 condition). */
  showRemove: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-condition-row-styles';

function ensureConditionRowStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-condition-row]:hover {
      background: oklch(0.50 0.005 260 / 0.04);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureConditionRowStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  padding: 'var(--ts-space-2) 0',
  borderRadius: 'var(--ts-radius-sm)',
  transition: 'background 100ms',
};

const sourceStyle: CSSProperties = {
  flex: '0 0 40%',
  minWidth: 0,
};

const operatorStyle: CSSProperties = {
  flex: '0 0 30%',
  minWidth: 0,
};

const valueStyle: CSSProperties = {
  flex: '0 0 calc(25% - 32px)',
  minWidth: 0,
};

const removeStyle: CSSProperties = {
  flexShrink: 0,
  width: 28,
  visibility: 'visible',
};

const removeHiddenStyle: CSSProperties = {
  ...removeStyle,
  visibility: 'hidden',
};

/* ----- Component --------------------------------------------------------- */

export function ConditionRow({
  id,
  index,
  source,
  operator,
  value,
  sources,
  operators,
  onChange,
  onRemove,
  showRemove,
}: ConditionRowProps): React.JSX.Element {
  const handleSourceChange = useCallback(
    (v: string) => onChange(id, 'source', v),
    [id, onChange],
  );

  const handleOperatorChange = useCallback(
    (v: string) => onChange(id, 'operator', v),
    [id, onChange],
  );

  const handleValueChange = useCallback(
    (v: number) => onChange(id, 'value', v),
    [id, onChange],
  );

  const handleValueStringChange = useCallback(
    (v: string) => onChange(id, 'value', v),
    [id, onChange],
  );

  const handleRemove = useCallback(
    () => onRemove(id),
    [id, onRemove],
  );

  const sourceOptions = sources.map((s) => ({
    value: s.value,
    label: s.label,
  }));

  const isNumericValue = typeof value === 'number';

  return (
    <div
      data-ts-condition-row=""
      style={rowStyle}
      role="group"
      aria-label={`Condition ${index}`}
    >
      <div style={sourceStyle}>
        <Select
          options={sourceOptions}
          value={source}
          onValueChange={handleSourceChange}
          size="sm"
          label={`Condition ${index} source`}
          placeholder="Source..."
        />
      </div>
      <div style={operatorStyle}>
        <Select
          options={operators}
          value={operator}
          onValueChange={handleOperatorChange}
          size="sm"
          label={`Condition ${index} operator`}
          placeholder="Operator..."
        />
      </div>
      <div style={valueStyle}>
        {isNumericValue ? (
          <NumberInput
            value={value}
            onChange={handleValueChange}
            size="sm"
            label={`Condition ${index} value`}
          />
        ) : (
          <Select
            options={sources.map((s) => ({ value: s.value, label: s.label }))}
            value={value as string}
            onValueChange={handleValueStringChange}
            size="sm"
            label={`Condition ${index} value`}
            placeholder="Value..."
          />
        )}
      </div>
      <div style={showRemove ? removeStyle : removeHiddenStyle}>
        <IconButton
          icon={<X size={14} />}
          label={`Remove condition ${index}`}
          size="sm"
          variant="ghost"
          onClick={handleRemove}
          disabled={!showRemove}
        />
      </div>
    </div>
  );
}

ConditionRow.displayName = 'ConditionRow';
