/**
 * Theme Initialization (FOUC Prevention)
 *
 * Runs synchronously before React hydration to set the correct theme
 * attribute on <html> immediately. Must be called in each app's main.tsx
 * BEFORE ReactDOM.createRoot().
 *
 * Reads from localStorage synchronously so the first paint uses the
 * correct theme. No async, no React, no hooks.
 */

const THEME_STORAGE_KEY = 'deskmodal:theme';
const CHART_THEME_STORAGE_KEY = 'deskmodal:chart-theme';
const THEME_ATTRIBUTE = 'data-ts-theme';
const CHART_THEME_ATTRIBUTE = 'data-ts-chart-theme';

export type ThemePreference = 'light' | 'dark' | 'system';
export type ResolvedTheme = 'light' | 'dark';
export type ChartThemePreference = 'inherit' | 'dark' | 'light';

/**
 * Resolve a theme preference to a concrete light/dark value.
 * When 'system', uses prefers-color-scheme media query.
 */
function resolveTheme(preference: ThemePreference): ResolvedTheme {
  if (preference === 'light' || preference === 'dark') {
    return preference;
  }
  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
}

/**
 * Read stored theme preference from localStorage.
 * Returns 'dark' if nothing stored (dark is the default).
 */
function readStoredTheme(): ThemePreference {
  try {
    const stored = localStorage.getItem(THEME_STORAGE_KEY);
    if (stored === 'light' || stored === 'dark' || stored === 'system') {
      return stored;
    }
  } catch {
    // localStorage may be unavailable in sandboxed contexts
  }
  return 'dark';
}

/**
 * Read stored chart theme preference from localStorage.
 */
function readStoredChartTheme(): ChartThemePreference {
  try {
    const stored = localStorage.getItem(CHART_THEME_STORAGE_KEY);
    if (stored === 'inherit' || stored === 'dark' || stored === 'light') {
      return stored;
    }
  } catch {
    // localStorage may be unavailable in sandboxed contexts
  }
  return 'inherit';
}

/**
 * Apply theme to the document element immediately (synchronous).
 * Must be called before first React render to prevent FOUC.
 */
export function initTheme(): void {
  const preference = readStoredTheme();
  const resolved = resolveTheme(preference);
  document.documentElement.setAttribute(THEME_ATTRIBUTE, resolved);

  const chartTheme = readStoredChartTheme();
  if (chartTheme !== 'inherit') {
    document.documentElement.setAttribute(CHART_THEME_ATTRIBUTE, chartTheme);
  }
}

export {
  THEME_STORAGE_KEY,
  CHART_THEME_STORAGE_KEY,
  THEME_ATTRIBUTE,
  CHART_THEME_ATTRIBUTE,
  resolveTheme,
  readStoredTheme,
  readStoredChartTheme,
};
