import { useCallback, type CSSProperties } from 'react';
import { Badge } from '@deskmodal/ui-components';
import type { ExchangeConnectionStatus } from '@deskmodal/ui-components';

/* -------------------------------------------------------------------------- */
/*  DockPanel                                                                 */
/*  32px minimized dock bar showing exchange status dots, msg/s, VWAP badge.  */
/* -------------------------------------------------------------------------- */

export interface DockPanelProps {
  /** Exchange connection statuses. */
  readonly connections: ReadonlyArray<ExchangeConnectionStatus>;
  /** Aggregate messages per second. */
  readonly totalMessagesPerSecond: number;
  /** Whether VWAP aggregation is active. */
  readonly vwapActive: boolean;
  /** Whether the panel is currently expanded. */
  readonly expanded: boolean;
  /** Toggle expand/collapse. */
  readonly onToggle: () => void;
  /** Whether any data quality degradation has been detected. */
  readonly qualityDegraded?: boolean;
}

/* ----- Styles ------------------------------------------------------------ */

const barStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 32,
  padding: '0 var(--ts-space-3)',
  gap: 'var(--ts-space-3)',
  background: 'var(--ts-connection-bar-bg, var(--ts-panel-bg))',
  borderTop: '1px solid var(--ts-panel-border)',
  cursor: 'pointer',
  userSelect: 'none',
  boxSizing: 'border-box',
  flexShrink: 0,
};

const dotsContainerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
};

const rateStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-secondary)',
  fontVariantNumeric: 'tabular-nums',
  whiteSpace: 'nowrap',
  lineHeight: 1,
};

const spacerStyle: CSSProperties = {
  flex: 1,
};

const STATUS_COLORS: Record<string, string> = {
  connected: 'var(--ts-connection-dot-connected)',
  disconnected: 'var(--ts-connection-dot-disconnected)',
  degraded: 'var(--ts-connection-dot-degraded)',
  connecting: 'var(--ts-connection-dot-connecting)',
};

function dotStyle(status: string): CSSProperties {
  return {
    width: 8,
    height: 8,
    borderRadius: '50%',
    background: STATUS_COLORS[status] ?? 'var(--ts-connection-dot-connecting)',
    flexShrink: 0,
  };
}

function formatRate(rate: number): string {
  if (rate >= 1000) return `${(rate / 1000).toFixed(1)}k msg/s`;
  return `${Math.round(rate)} msg/s`;
}

export function DockPanel({
  connections,
  totalMessagesPerSecond,
  vwapActive,
  expanded,
  onToggle,
  qualityDegraded = false,
}: DockPanelProps): React.JSX.Element {
  const handleClick = useCallback(() => {
    onToggle();
  }, [onToggle]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        onToggle();
      }
    },
    [onToggle],
  );

  return (
    <div
      style={barStyle}
      onClick={handleClick}
      onKeyDown={handleKeyDown}
      role="button"
      tabIndex={0}
      aria-expanded={expanded}
      aria-label="Toggle feeds panel"
    >
      <div style={dotsContainerStyle}>
        {connections.map((conn) => (
          <span
            key={conn.id}
            style={dotStyle(conn.status)}
            title={`${conn.name}: ${conn.status}`}
          />
        ))}
      </div>

      <span style={rateStyle}>{formatRate(totalMessagesPerSecond)}</span>

      {vwapActive && (
        <Badge variant={qualityDegraded ? 'warning' : 'info'}>VWAP</Badge>
      )}

      <span style={spacerStyle} />

      <span
        style={{
          fontSize: 'var(--ts-font-xs)',
          color: 'var(--ts-text-tertiary)',
        }}
      >
        {expanded ? 'Collapse' : 'Expand'}
      </span>
    </div>
  );
}

DockPanel.displayName = 'DockPanel';
