import type { CSSProperties } from 'react';
import type { DataQualityScore } from '@deskmodal/data-layer';
import { DQS_WEIGHTS } from '@deskmodal/data-layer';

/* -------------------------------------------------------------------------- */
/*  DqsBreakdown                                                              */
/*  Visual breakdown of 5 DQS factors as labeled progress bars.               */
/* -------------------------------------------------------------------------- */

export interface DqsBreakdownProps {
  /** Data quality score containing all 5 factor scores (0-100). */
  readonly score: DataQualityScore;
  /** Whether to show the weight percentages next to labels. */
  readonly showWeights?: boolean;
}

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-2)',
};

const factorRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const factorLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-secondary)',
  width: 110,
  flexShrink: 0,
  textTransform: 'capitalize',
};

const barTrackStyle: CSSProperties = {
  flex: 1,
  height: 6,
  background: 'var(--ts-panel-border)',
  borderRadius: 'var(--ts-radius-full, 9999px)',
  overflow: 'hidden',
};

const factorValueStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  width: 36,
  textAlign: 'right',
  fontVariantNumeric: 'tabular-nums',
  flexShrink: 0,
};

/* ----- Factor definitions ------------------------------------------------ */

interface FactorDef {
  key: keyof Omit<DataQualityScore, 'computedAt' | 'overall'>;
  label: string;
  weight: number;
}

const FACTORS: FactorDef[] = [
  { key: 'latency', label: 'Latency', weight: DQS_WEIGHTS.latency },
  { key: 'uptime', label: 'Uptime', weight: DQS_WEIGHTS.uptime },
  { key: 'priceAgreement', label: 'Price Agreement', weight: DQS_WEIGHTS.priceAgreement },
  { key: 'completeness', label: 'Completeness', weight: DQS_WEIGHTS.completeness },
  { key: 'volumeLegitimacy', label: 'Volume Legit.', weight: DQS_WEIGHTS.volumeLegitimacy },
];

/**
 * Determine bar color based on score value.
 * >=80 = green, 50-79 = yellow, <50 = red.
 */
function scoreColor(value: number): string {
  if (value >= 80) return 'var(--ts-status-success, #22c55e)';
  if (value >= 50) return 'var(--ts-status-warning, #eab308)';
  return 'var(--ts-status-error, #ef4444)';
}

export function DqsBreakdown({ score, showWeights = false }: DqsBreakdownProps): React.JSX.Element {
  return (
    <div style={containerStyle}>
      {FACTORS.map((factor) => {
        const value = score[factor.key];
        const color = scoreColor(value);
        const label = showWeights
          ? `${factor.label} (${Math.round(factor.weight * 100)}%)`
          : factor.label;

        return (
          <div key={factor.key} style={factorRowStyle}>
            <span style={factorLabelStyle}>{label}</span>
            <div style={barTrackStyle}>
              <div
                style={{
                  height: '100%',
                  width: `${Math.min(100, Math.max(0, value))}%`,
                  background: color,
                  borderRadius: 'inherit',
                  transition: 'width 300ms ease',
                }}
              />
            </div>
            <span style={factorValueStyle}>{Math.round(value)}</span>
          </div>
        );
      })}
    </div>
  );
}

DqsBreakdown.displayName = 'DqsBreakdown';
