import { memo, type CSSProperties, type MouseEventHandler } from 'react';
import { formatPrice } from '../financial/format-number';

/* -------------------------------------------------------------------------- */
/*  TradeRow                                                                   */
/*  Single row in a trade history feed showing time, price, and size.          */
/*  Uses --ts-trade-row-* tokens. Price colored by side (buy/sell).            */
/* -------------------------------------------------------------------------- */

export type TradeSide = 'buy' | 'sell';

export interface TradeRowProps {
  /** Trade timestamp (ISO string or epoch ms). */
  time: string;
  /** Trade price. */
  price: number;
  /** Trade size/quantity. */
  size: number;
  /** Trade side (buyer or seller initiated). */
  side: TradeSide;
  /** Price decimal precision. */
  precision?: number;
  /** Size decimal precision. */
  sizePrecision?: number;
  /** Whether this is a significant/large trade (whale trade). */
  significant?: boolean;
  /** Click handler. */
  onClick?: MouseEventHandler<HTMLDivElement>;
}

/* ----- Style injection for hover ----------------------------------------- */

const TRADE_ROW_STYLE_ID = 'ts-trade-row-styles';

function ensureTradeRowStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(TRADE_ROW_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = TRADE_ROW_STYLE_ID;
  sheet.textContent = `
    [data-ts-trade-row]:hover {
      background-color: var(--ts-depth-row-bg-hover);
    }
    [data-ts-trade-row][data-significant] {
      background-color: var(--ts-trade-row-significant-bg);
      font-weight: var(--ts-trade-row-significant-font-weight);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureTradeRowStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-trade-row-height)',
  fontFamily: 'var(--ts-trade-row-font)',
  fontSize: 'var(--ts-trade-row-font-size)',
  fontVariantNumeric: 'tabular-nums',
  padding: '0 var(--ts-space-2)',
  boxSizing: 'border-box',
  cursor: 'pointer',
  userSelect: 'none',
};

const cellStyle: CSSProperties = {
  flex: 1,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const SIDE_COLOR: Record<TradeSide, string> = {
  buy: 'var(--ts-trade-row-buy-text)',
  sell: 'var(--ts-trade-row-sell-text)',
};

function formatTime(time: string): string {
  const date = new Date(time);
  if (Number.isNaN(date.getTime())) return time;
  const h = String(date.getHours()).padStart(2, '0');
  const m = String(date.getMinutes()).padStart(2, '0');
  const s = String(date.getSeconds()).padStart(2, '0');
  return `${h}:${m}:${s}`;
}

/* ----- Component --------------------------------------------------------- */

function TradeRowInner({
  time,
  price,
  size,
  side,
  precision = 2,
  sizePrecision = 4,
  significant = false,
  onClick,
}: TradeRowProps): React.JSX.Element {
  const timeCellStyle: CSSProperties = {
    ...cellStyle,
    color: 'var(--ts-trade-row-time-text)',
  };

  const priceCellStyle: CSSProperties = {
    ...cellStyle,
    textAlign: 'right',
    color: SIDE_COLOR[side],
  };

  const sizeCellStyle: CSSProperties = {
    ...cellStyle,
    textAlign: 'right',
    color: 'var(--ts-trade-row-size-text)',
  };

  return (
    <div
      data-ts-trade-row=""
      data-side={side}
      {...(significant ? { 'data-significant': '' } : {})}
      style={rowStyle}
      onClick={onClick}
      role="row"
      data-testid="trade-row"
    >
      <span style={timeCellStyle} role="cell" data-testid="trade-time">
        {formatTime(time)}
      </span>
      <span className="ts-data-value" style={priceCellStyle} role="cell" data-testid="trade-price">
        {formatPrice(price, precision)}
      </span>
      <span className="ts-data-value" style={sizeCellStyle} role="cell" data-testid="trade-size">
        {formatPrice(size, sizePrecision)}
      </span>
    </div>
  );
}

export const TradeRow = memo(TradeRowInner);

TradeRow.displayName = 'TradeRow';
