/**
 * FDC3 context representing a real-time price quote from a single exchange.
 *
 * Required fields (type, id, last, timestamp) are always present.
 * Optional fields are set to undefined when the exchange adapter does not
 * provide the data -- never fabricated.
 */
export interface DeskmodalQuote {
  /** FDC3 context type discriminator. Always 'deskmodal.quote'. */
  readonly type: 'deskmodal.quote';
  /** FDC3-required id field. `ticker` is the canonical symbol (e.g., 'BTCUSDT'). */
  readonly id: { readonly ticker: string };
  /** Human-readable instrument name (e.g., 'Bitcoin/USDT'). */
  readonly name?: string;
  // -- Price fields --------------------------------------------------------
  // Explicit naming -- never ambiguous "price" (P2-10, F-P1-6).
  // Maps from Rust NormalizedTick.price in exchange.rs.
  /** Last traded price. Always present -- this is NormalizedTick.price. */
  readonly last: number;
  /** Best bid price. Parsed from exchange: Binance @ticker 'b', Bybit bid1Price, OKX bidPx, Coinbase best_bid. */
  readonly bid?: number;
  /** Best ask price. Parsed from exchange: Binance @ticker 'a', Bybit ask1Price, OKX askPx, Coinbase best_ask. */
  readonly ask?: number;
  /** Midpoint: (bid + ask) / 2. Only set when both bid and ask are real. */
  readonly mid?: number;
  /** Spread: ask - bid. Only set when both bid and ask are real. */
  readonly spread?: number;
  // -- 24h stats -----------------------------------------------------------
  /** 24h high. Set when exchange provides it. */
  readonly high24h?: number;
  /** 24h low. Set when exchange provides it. */
  readonly low24h?: number;
  /** 24h open price. Set when exchange provides it. */
  readonly open24h?: number;
  /**
   * 24h price change percent. Sources:
   *   Binance: field 'P' in 24hrTicker stream
   *   Bybit: field 'price24hPcnt' in tickers topic (multiply by 100)
   *   OKX: computed as (last - open24h) / open24h * 100
   *   Coinbase: computed from 'open_24h' and current price
   */
  readonly changePercent24h?: number;
  /** 24h trading volume in base currency. Maps from NormalizedTick.volume_24h. */
  readonly volume24h?: number;
  // -- Order book depth (P0-SME-1) -----------------------------------------
  /** Best bid quantity. */
  readonly bidSize?: number;
  /** Best ask quantity. */
  readonly askSize?: number;
  /** Best bid quantity (from exchange L1 data). */
  readonly bestBidQty?: number;
  /** Best ask quantity (from exchange L1 data). */
  readonly bestAskQty?: number;
  /** 24h volume in quote currency (notional volume). */
  readonly quoteVolume24h?: number;
  // -- Data quality --------------------------------------------------------
  /** Exchange timestamp in epoch milliseconds. Maps from NormalizedTick.timestamp. */
  readonly timestamp: number;
  /** Source exchange ID (e.g., 'binance'). Maps from NormalizedTick.exchange. */
  readonly exchange?: string;
  /** Exchange-assigned sequence number for ordering. */
  readonly sequence?: number;
  /** Open interest for derivatives. */
  readonly openInterest?: number;
  // -- Instrument metadata (P1-UX-3) --------------------------------------
  /** Minimum price increment for this instrument. */
  readonly tickSize?: number;
  /** Which price this quote primarily represents. */
  readonly priceType?: 'last' | 'vwap' | 'mid';
}

/** Runtime type guard for DeskmodalQuote context objects. */
export function isDeskmodalQuote(ctx: unknown): ctx is DeskmodalQuote {
  if (ctx === null || ctx === undefined || typeof ctx !== 'object') return false;
  const obj = ctx as Record<string, unknown>;
  return (
    obj['type'] === 'deskmodal.quote' &&
    typeof obj['last'] === 'number' &&
    typeof obj['timestamp'] === 'number' &&
    obj['id'] !== null &&
    obj['id'] !== undefined &&
    typeof obj['id'] === 'object' &&
    typeof (obj['id'] as Record<string, unknown>)['ticker'] === 'string'
  );
}

/** Factory function for creating DeskmodalQuote context objects. */
export function createDeskmodalQuote(
  ticker: string,
  last: number,
  timestamp: number,
  fields?: Partial<Omit<DeskmodalQuote, 'type' | 'id' | 'last' | 'timestamp'>>,
): DeskmodalQuote {
  return {
    type: 'deskmodal.quote',
    id: { ticker },
    last,
    timestamp,
    ...fields,
  };
}

/** Union type for all Deskmodal FDC3 context types. */
export type DeskmodalContext = DeskmodalQuote;
