import { useCallback, type CSSProperties } from 'react';
import { DropdownMenu, IconButton } from '../primitives';
import { Star } from 'lucide-react';
import { ChartTypeIcon, type ChartType } from './ChartTypeIcon';

/* -------------------------------------------------------------------------- */
/*  ChartTypeSelector                                                         */
/*  Dropdown picker for chart type with grouped list and favorites.           */
/*  Uses DropdownMenu + ChartTypeIcon, --ts-selector-* tokens.               */
/* -------------------------------------------------------------------------- */

export interface ChartTypeSelectorProps {
  /** Currently selected chart type. */
  value: ChartType;
  /** Called when a chart type is selected. */
  onValueChange: (type: ChartType) => void;
  /** Chart types to show as favorites (shown at top of dropdown). */
  favorites?: ChartType[];
  /** Called when a chart type is toggled as favorite. */
  onFavoriteToggle?: (type: ChartType) => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-chart-type-selector-styles';

function ensureChartTypeSelectorStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-chart-type-option][data-selected] {
      background: var(--ts-selector-active-bg);
      color: var(--ts-selector-active-text);
    }
    [data-ts-chart-type-star] {
      opacity: 0.3;
      transition: opacity 100ms;
      cursor: pointer;
    }
    [data-ts-chart-type-star]:hover {
      opacity: 1;
    }
    [data-ts-chart-type-star][data-favorite] {
      opacity: 1;
      color: var(--ts-accent-default);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureChartTypeSelectorStyles();
}

/* ----- Constants --------------------------------------------------------- */

interface ChartTypeEntry {
  type: ChartType;
  label: string;
}

interface ChartTypeGroupDef {
  label: string;
  items: ChartTypeEntry[];
}

const CHART_TYPE_GROUPS: ChartTypeGroupDef[] = [
  {
    label: 'Candlestick',
    items: [
      { type: 'candles', label: 'Candles' },
      { type: 'hollow-candles', label: 'Hollow Candles' },
      { type: 'heikin-ashi', label: 'Heikin Ashi' },
      { type: 'volume-candles', label: 'Volume Candles' },
    ],
  },
  {
    label: 'Line Charts',
    items: [
      { type: 'line', label: 'Line' },
      { type: 'line-markers', label: 'Line with Markers' },
      { type: 'step-line', label: 'Step Line' },
    ],
  },
  {
    label: 'Area Charts',
    items: [
      { type: 'area', label: 'Area' },
      { type: 'hlc-area', label: 'HLC Area' },
      { type: 'baseline', label: 'Baseline' },
    ],
  },
  {
    label: 'Bar / Column Charts',
    items: [
      { type: 'bars', label: 'Bars (OHLC)' },
      { type: 'columns', label: 'Columns' },
      { type: 'high-low', label: 'High-Low' },
    ],
  },
  {
    label: 'Japanese / Alternative',
    items: [
      { type: 'renko', label: 'Renko' },
      { type: 'line-break', label: 'Line Break' },
      { type: 'kagi', label: 'Kagi' },
      { type: 'point-figure', label: 'Point & Figure' },
      { type: 'range', label: 'Range' },
    ],
  },
];

/* ----- Styles ------------------------------------------------------------ */

const itemContentStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  width: '100%',
};

const itemLabelStyle: CSSProperties = {
  flex: 1,
  fontSize: 'var(--ts-font-md)',
  fontFamily: 'inherit',
};

/* ----- Component --------------------------------------------------------- */

export function ChartTypeSelector({
  value,
  onValueChange,
  favorites,
  onFavoriteToggle,
}: ChartTypeSelectorProps): React.JSX.Element {
  const handleSelect = useCallback(
    (type: ChartType) => {
      onValueChange(type);
    },
    [onValueChange],
  );

  const handleFavoriteClick = useCallback(
    (e: React.MouseEvent, type: ChartType) => {
      e.stopPropagation();
      e.preventDefault();
      onFavoriteToggle?.(type);
    },
    [onFavoriteToggle],
  );

  const isFavorite = (type: ChartType): boolean =>
    favorites !== undefined && favorites.includes(type);

  const favoriteEntries: ChartTypeEntry[] =
    favorites !== undefined
      ? favorites
          .map((f) => {
            for (const group of CHART_TYPE_GROUPS) {
              const entry = group.items.find((item) => item.type === f);
              if (entry !== undefined) return entry;
            }
            return undefined;
          })
          .filter((e): e is ChartTypeEntry => e !== undefined)
      : [];

  return (
    <DropdownMenu>
      <DropdownMenu.Trigger>
        <IconButton
          data-ts-chart-type-selector=""
          icon={<ChartTypeIcon type={value} size={16} />}
          label="Chart type"
          variant="ghost"
          size="sm"
        />
      </DropdownMenu.Trigger>
      <DropdownMenu.Content align="start" style={{ minWidth: 260 }}>
        {favoriteEntries.length > 0 && (
          <>
            <DropdownMenu.Label>Favorites</DropdownMenu.Label>
            {favoriteEntries.map((entry) => (
              <DropdownMenu.Item
                key={`fav-${entry.type}`}
                data-ts-chart-type-option=""
                {...(value === entry.type ? { 'data-selected': '' } : {})}
                onSelect={() => handleSelect(entry.type)}
              >
                <div style={itemContentStyle}>
                  <ChartTypeIcon type={entry.type} size={16} />
                  <span style={itemLabelStyle}>{entry.label}</span>
                  <Star
                    size={12}
                    data-ts-chart-type-star=""
                    data-favorite=""
                    fill="currentColor"
                    onClick={(e) => handleFavoriteClick(e, entry.type)}
                    aria-label={`Remove ${entry.label} from favorites`}
                  />
                </div>
              </DropdownMenu.Item>
            ))}
            <DropdownMenu.Separator />
          </>
        )}
        {CHART_TYPE_GROUPS.map((group, gi) => (
          <div key={group.label}>
            {gi > 0 && <DropdownMenu.Separator />}
            <DropdownMenu.Label>{group.label}</DropdownMenu.Label>
            {group.items.map((entry) => (
              <DropdownMenu.Item
                key={entry.type}
                data-ts-chart-type-option=""
                {...(value === entry.type ? { 'data-selected': '' } : {})}
                onSelect={() => handleSelect(entry.type)}
              >
                <div style={itemContentStyle}>
                  <ChartTypeIcon type={entry.type} size={16} />
                  <span style={itemLabelStyle}>{entry.label}</span>
                  {onFavoriteToggle !== undefined && (
                    <Star
                      size={12}
                      data-ts-chart-type-star=""
                      {...(isFavorite(entry.type) ? { 'data-favorite': '' } : {})}
                      fill={isFavorite(entry.type) ? 'currentColor' : 'none'}
                      onClick={(e) => handleFavoriteClick(e, entry.type)}
                      aria-label={
                        isFavorite(entry.type)
                          ? `Remove ${entry.label} from favorites`
                          : `Add ${entry.label} to favorites`
                      }
                    />
                  )}
                </div>
              </DropdownMenu.Item>
            ))}
          </div>
        ))}
      </DropdownMenu.Content>
    </DropdownMenu>
  );
}

ChartTypeSelector.displayName = 'ChartTypeSelector';
