import { forwardRef, type CSSProperties, type ReactNode, type ElementRef, type ComponentPropsWithoutRef } from 'react';
import { Tooltip as TooltipPrimitive } from 'radix-ui';

/* -------------------------------------------------------------------------- */
/*  Tooltip                                                                   */
/*  Compact informational popup on hover/focus.                               */
/*  Wraps Radix Tooltip — uses --ts-tooltip-* tokens.                         */
/* -------------------------------------------------------------------------- */

type TooltipSide = 'top' | 'bottom' | 'left' | 'right';

interface TooltipProps {
  /** Tooltip content body. */
  content: ReactNode;
  /** Optional keyboard shortcut displayed in lighter text. */
  shortcut?: string;
  /** Preferred side of the trigger to render on. */
  side?: TooltipSide;
  /** Delay in ms before showing the tooltip. */
  delayDuration?: number;
  /** Trigger element. */
  children: ReactNode;
}

/* ----- Styles ------------------------------------------------------------ */

const contentStyle: CSSProperties = {
  background: 'var(--ts-tooltip-bg)',
  color: 'var(--ts-tooltip-text)',
  border: '1px solid var(--ts-tooltip-border)',
  borderRadius: 'var(--ts-tooltip-radius)',
  padding: 'var(--ts-tooltip-padding-y) var(--ts-tooltip-padding-x)',
  fontSize: 'var(--ts-tooltip-font-size)',
  boxShadow: 'var(--ts-tooltip-shadow)',
  maxWidth: 'var(--ts-tooltip-max-width)',
  lineHeight: 1.4,
  display: 'inline-flex',
  alignItems: 'center',
  gap: '8px',
  userSelect: 'none',
  zIndex: 50,
  boxSizing: 'border-box',
  fontFamily: 'inherit',
  animationDuration: '150ms',
  animationTimingFunction: 'ease-out',
};

const shortcutStyle: CSSProperties = {
  color: 'var(--ts-tooltip-shortcut-text)',
  fontSize: 'var(--ts-tooltip-font-size)',
  fontFamily: 'inherit',
  marginLeft: '4px',
  whiteSpace: 'nowrap',
};

const arrowStyle: CSSProperties = {
  fill: 'var(--ts-tooltip-bg)',
};

/* ----- Style injection for animations ------------------------------------ */

const TOOLTIP_STYLE_ID = 'ts-tooltip-styles';

function ensureTooltipStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(TOOLTIP_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = TOOLTIP_STYLE_ID;
  sheet.textContent = `
    @keyframes ts-tooltip-fade-in {
      from { opacity: 0; transform: scale(0.96); }
      to { opacity: 1; transform: scale(1); }
    }
    @keyframes ts-tooltip-fade-out {
      from { opacity: 1; transform: scale(1); }
      to { opacity: 0; transform: scale(0.96); }
    }
    [data-ts-tooltip-content][data-state="delayed-open"] {
      animation: ts-tooltip-fade-in 150ms ease-out;
    }
    [data-ts-tooltip-content][data-state="closed"] {
      animation: ts-tooltip-fade-out 100ms ease-in;
    }
    @media (prefers-reduced-motion: reduce) {
      [data-ts-tooltip-content][data-state="delayed-open"],
      [data-ts-tooltip-content][data-state="closed"] {
        animation: none;
      }
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureTooltipStyles();
}

/* ----- Tooltip.Content inner wrapper ------------------------------------- */

type TooltipContentProps = ComponentPropsWithoutRef<typeof TooltipPrimitive.Content>;

const TooltipContent = forwardRef<ElementRef<typeof TooltipPrimitive.Content>, TooltipContentProps>(
  ({ style, children, ...props }, ref) => (
    <TooltipPrimitive.Portal>
      <TooltipPrimitive.Content
        ref={ref}
        data-ts-tooltip-content=""
        sideOffset={4}
        style={{ ...contentStyle, ...style }}
        {...props}
      >
        {children}
        <TooltipPrimitive.Arrow width={8} height={4} style={arrowStyle} />
      </TooltipPrimitive.Content>
    </TooltipPrimitive.Portal>
  ),
);
TooltipContent.displayName = 'Tooltip.Content';

/* ----- Main Tooltip export ----------------------------------------------- */

export function Tooltip({
  content,
  shortcut,
  side = 'top',
  delayDuration = 400,
  children,
}: TooltipProps): React.JSX.Element {
  return (
    <TooltipPrimitive.Provider delayDuration={delayDuration}>
      <TooltipPrimitive.Root>
        <TooltipPrimitive.Trigger asChild>
          {children}
        </TooltipPrimitive.Trigger>
        <TooltipContent side={side}>
          <span>{content}</span>
          {shortcut ? <kbd style={shortcutStyle}>{shortcut}</kbd> : null}
        </TooltipContent>
      </TooltipPrimitive.Root>
    </TooltipPrimitive.Provider>
  );
}

Tooltip.displayName = 'Tooltip';
