import { type CSSProperties } from 'react';
import { Dialog } from '../../primitives';

/* -------------------------------------------------------------------------- */
/*  KeyboardShortcutOverlay                                                   */
/*  Modal dialog listing app-specific keyboard shortcuts grouped by category. */
/*  Does NOT show Desk system shortcuts — only app-local shortcuts.           */
/*  Uses --ts-shortcut-* tokens.                                              */
/* -------------------------------------------------------------------------- */

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-shortcut-overlay-styles';

function ensureShortcutOverlayStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-shortcut-overlay] [data-ts-shortcut-categories] {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: var(--ts-space-5);
    }
    @container ts-app (max-width: 500px) {
      [data-ts-shortcut-overlay] [data-ts-shortcut-categories] {
        grid-template-columns: 1fr;
      }
    }
    @media (max-width: 500px) {
      [data-ts-shortcut-overlay] [data-ts-shortcut-categories] {
        grid-template-columns: 1fr;
      }
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureShortcutOverlayStyles();
}

/* ----- Types ------------------------------------------------------------- */

export interface ShortcutEntry {
  /** Action name. */
  action: string;
  /** Key combination strings (e.g., ["Ctrl", "S"] or ["Cmd", "K"]). */
  keys: string[];
  /** Optional description. */
  description?: string;
}

export interface ShortcutCategory {
  /** Category name (e.g., "Navigation", "Drawing", "Trading"). */
  label: string;
  /** Shortcuts in this category. */
  shortcuts: ShortcutEntry[];
}

export interface KeyboardShortcutOverlayProps {
  /** Whether the overlay is open. */
  open: boolean;
  /** Called when the overlay open state changes. */
  onOpenChange: (open: boolean) => void;
  /** Shortcut categories to display. */
  categories: ShortcutCategory[];
  /** App name shown in the title (e.g., "Chart Shortcuts"). */
  appName: string;
  /** Note text shown at the bottom (e.g., about Desk system shortcuts). */
  footerNote?: string;
}

/* ----- Styles ------------------------------------------------------------ */

const dialogStyle: CSSProperties = {
  maxWidth: 'var(--ts-shortcut-overlay-max-width)',
};

const categoryTitleStyle: CSSProperties = {
  margin: 0,
  marginBottom: 'var(--ts-space-2)',
  fontSize: 'var(--ts-shortcut-category-title-font-size)',
  fontWeight: 'var(--ts-shortcut-category-title-font-weight)' as unknown as number,
  color: 'var(--ts-shortcut-category-title-text)',
  textTransform: 'uppercase',
  letterSpacing: '0.05em',
  lineHeight: 1.4,
};

const shortcutListStyle: CSSProperties = {
  listStyle: 'none',
  margin: 0,
  padding: 0,
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-1)',
};

const shortcutRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  gap: 'var(--ts-space-2)',
  padding: '4px 0',
};

const actionTextStyle: CSSProperties = {
  fontSize: 'var(--ts-shortcut-action-font-size)',
  color: 'var(--ts-shortcut-action-text)',
  lineHeight: 1.4,
};

const keysContainerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: '4px',
  flexShrink: 0,
};

const kbdStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  minWidth: '20px',
  height: '22px',
  padding: 'var(--ts-shortcut-key-padding)',
  background: 'var(--ts-shortcut-key-bg)',
  border: '1px solid var(--ts-shortcut-key-border)',
  borderRadius: 'var(--ts-shortcut-key-radius)',
  fontFamily: 'var(--ts-shortcut-key-font)',
  fontSize: 'var(--ts-shortcut-key-font-size)',
  color: 'var(--ts-shortcut-key-text)',
  lineHeight: 1,
  boxSizing: 'border-box',
};

const separatorStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  lineHeight: 1,
};

const footerNoteStyle: CSSProperties = {
  marginTop: 'var(--ts-space-4)',
  paddingTop: 'var(--ts-space-3)',
  borderTop: '1px solid var(--ts-border-subtle)',
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-tertiary)',
  lineHeight: 1.5,
};

const contentBodyStyle: CSSProperties = {
  marginTop: 'var(--ts-space-4)',
};

/* ----- Component --------------------------------------------------------- */

export function KeyboardShortcutOverlay({
  open,
  onOpenChange,
  categories,
  appName,
  footerNote,
}: KeyboardShortcutOverlayProps): React.JSX.Element {
  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <Dialog.Content style={dialogStyle}>
        <div data-ts-shortcut-overlay="">
          <Dialog.Title>{appName} Keyboard Shortcuts</Dialog.Title>
          <Dialog.Description style={{ position: 'absolute', width: 1, height: 1, overflow: 'hidden', clip: 'rect(0, 0, 0, 0)', whiteSpace: 'nowrap' }}>
            Reference card for keyboard shortcuts available in the {appName} app.
          </Dialog.Description>
          <div style={contentBodyStyle}>
            <div data-ts-shortcut-categories="">
              {categories.map((category) => (
                <div key={category.label} data-ts-shortcut-category="">
                  <h3 style={categoryTitleStyle}>{category.label}</h3>
                  <ul style={shortcutListStyle}>
                    {category.shortcuts.map((shortcut) => (
                      <li key={shortcut.action} style={shortcutRowStyle}>
                        <span style={actionTextStyle}>{shortcut.action}</span>
                        <span style={keysContainerStyle}>
                          {shortcut.keys.map((key, keyIdx) => (
                            <span key={keyIdx} style={{ display: 'inline-flex', alignItems: 'center', gap: '4px' }}>
                              {keyIdx > 0 ? (
                                <span style={separatorStyle}>+</span>
                              ) : null}
                              <kbd data-ts-shortcut-key="" style={kbdStyle}>
                                {key}
                              </kbd>
                            </span>
                          ))}
                        </span>
                      </li>
                    ))}
                  </ul>
                </div>
              ))}
            </div>
            {footerNote !== undefined ? (
              <p style={footerNoteStyle}>{footerNote}</p>
            ) : null}
          </div>
        </div>
      </Dialog.Content>
    </Dialog>
  );
}

KeyboardShortcutOverlay.displayName = 'KeyboardShortcutOverlay';
