import {
  useCallback,
  type CSSProperties,
} from 'react';
import { Tabs, NumberInput, Select, Checkbox, Button, Slider } from '../primitives';
import { ColorPicker } from './ColorPicker';
import { LineStylePicker, type LineStyle } from './LineStylePicker';
import { LineWidthPicker } from './LineWidthPicker';

/* -------------------------------------------------------------------------- */
/*  IndicatorSettingsPanel                                                    */
/*  Tabbed panel for configuring indicator parameters, styles, and visibility. */
/*  Uses --ts-settings-panel-*, --ts-tab-* tokens.                            */
/* -------------------------------------------------------------------------- */

export interface IndicatorParameter {
  /** Parameter identifier. */
  id: string;
  /** Display label (e.g., "Length", "Source", "Smoothing Type"). */
  label: string;
  /** Parameter type determining the input control. */
  type: 'number' | 'select' | 'checkbox' | 'color';
  /** Current value. */
  value: number | string | boolean;
  /** Options for select type. */
  options?: Array<{ value: string; label: string }>;
  /** Min value for number type. */
  min?: number;
  /** Max value for number type. */
  max?: number;
  /** Step value for number type. */
  step?: number;
}

export interface IndicatorStyleConfig {
  /** Style property identifier. */
  id: string;
  /** Display label (e.g., "Line", "Histogram", "Fill Area"). */
  label: string;
  /** Whether this plot is visible. */
  visible: boolean;
  /** Plot color. */
  color: string;
  /** Line width (for line plots). */
  lineWidth?: number;
  /** Line style (for line plots). */
  lineStyle?: 'solid' | 'dashed' | 'dotted' | 'dash-dot';
  /** Plot type. */
  plotType?: 'line' | 'histogram' | 'area' | 'columns' | 'circles' | 'step-line' | 'cross';
}

export interface IndicatorVisibilityConfig {
  /** Timeframe range label. */
  label: string;
  /** Whether visible in this range. */
  visible: boolean;
}

export interface IndicatorSettingsPanelProps {
  /** Indicator display name. */
  indicatorName: string;
  /** Parameters for the Inputs tab. */
  parameters: IndicatorParameter[];
  /** Style configuration for the Style tab. */
  styles: IndicatorStyleConfig[];
  /** Visibility configuration for the Visibility tab. */
  visibility: IndicatorVisibilityConfig[];
  /** Called when a parameter value changes. */
  onParameterChange: (parameterId: string, value: number | string | boolean) => void;
  /** Called when a style property changes. */
  onStyleChange: (styleId: string, property: string, value: string | number | boolean) => void;
  /** Called when a visibility setting changes. */
  onVisibilityChange: (index: number, visible: boolean) => void;
  /** Called when Apply/Ok is clicked. */
  onApply: () => void;
  /** Called when Cancel is clicked. */
  onCancel: () => void;
  /** Called when Reset to defaults is clicked. */
  onReset?: () => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-indicator-settings-styles';

function ensureIndicatorSettingsStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-indicator-settings] [data-ts-indicator-settings-row]:hover {
      background: oklch(0.50 0.005 260 / 0.04);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureIndicatorSettingsStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const panelStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  width: 'var(--ts-settings-panel-width)',
  background: 'var(--ts-settings-panel-bg)',
  border: '1px solid var(--ts-settings-panel-border)',
  borderRadius: 'var(--ts-radius-md)',
  boxShadow: 'var(--ts-settings-panel-shadow)',
  overflow: 'hidden',
  fontFamily: 'inherit',
};

const headerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-settings-panel-header-height)',
  padding: '0 var(--ts-space-4)',
  borderBottom: '1px solid var(--ts-settings-panel-header-border)',
  background: 'var(--ts-settings-panel-header-bg)',
};

const headerTitleStyle: CSSProperties = {
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  fontSize: 'var(--ts-font-md)',
  color: 'var(--ts-text-primary)',
  fontFamily: 'inherit',
  margin: 0,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const tabBarStyle: CSSProperties = {
  padding: '0 var(--ts-space-3)',
  borderBottom: '1px solid var(--ts-border-subtle)',
};

const contentStyle: CSSProperties = {
  flex: 1,
  overflowY: 'auto',
  padding: 'var(--ts-space-3)',
  scrollbarWidth: 'thin',
};

const formRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  gap: 'var(--ts-space-3)',
  padding: 'var(--ts-space-2) var(--ts-space-1)',
  borderRadius: 'var(--ts-radius-sm)',
  transition: 'background 100ms',
};

const formLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-secondary)',
  fontFamily: 'inherit',
  whiteSpace: 'nowrap',
  flexShrink: 0,
  minWidth: 80,
};

const formControlStyle: CSSProperties = {
  flex: 1,
  minWidth: 0,
  maxWidth: 140,
};

const styleRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  padding: 'var(--ts-space-2) var(--ts-space-1)',
  borderRadius: 'var(--ts-radius-sm)',
  transition: 'background 100ms',
};

const styleLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-primary)',
  fontFamily: 'inherit',
  flex: 1,
  minWidth: 0,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const visibilityRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-3)',
  padding: 'var(--ts-space-2) var(--ts-space-1)',
};

const footerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'flex-end',
  gap: 'var(--ts-space-2)',
  padding: 'var(--ts-space-3) var(--ts-space-4)',
  borderTop: '1px solid var(--ts-border-subtle)',
};

const resetButtonStyle: CSSProperties = {
  marginRight: 'auto',
};

const PLOT_TYPE_OPTIONS = [
  { value: 'line', label: 'Line' },
  { value: 'histogram', label: 'Histogram' },
  { value: 'area', label: 'Area' },
  { value: 'columns', label: 'Columns' },
  { value: 'circles', label: 'Circles' },
  { value: 'step-line', label: 'Step Line' },
  { value: 'cross', label: 'Cross' },
];

/* ----- Component --------------------------------------------------------- */

export function IndicatorSettingsPanel({
  indicatorName,
  parameters,
  styles,
  visibility,
  onParameterChange,
  onStyleChange,
  onVisibilityChange,
  onApply,
  onCancel,
  onReset,
}: IndicatorSettingsPanelProps): React.JSX.Element {

  const renderParameterControl = useCallback((param: IndicatorParameter) => {
    switch (param.type) {
      case 'number':
        return (
          <div style={formControlStyle}>
            <NumberInput
              value={param.value as number}
              onChange={(v) => onParameterChange(param.id, v)}
              min={param.min}
              max={param.max}
              step={param.step}
              size="sm"
              label={param.label}
            />
          </div>
        );
      case 'select':
        return (
          <div style={formControlStyle}>
            <Select
              options={param.options ?? []}
              value={param.value as string}
              onValueChange={(v) => onParameterChange(param.id, v)}
              size="sm"
              label={param.label}
            />
          </div>
        );
      case 'checkbox':
        return (
          <Checkbox
            checked={param.value as boolean}
            onCheckedChange={(v) => onParameterChange(param.id, v as boolean)}
          />
        );
      case 'color':
        return (
          <ColorPicker
            value={param.value as string}
            onValueChange={(v) => onParameterChange(param.id, v)}
            side="left"
          />
        );
      default:
        return null;
    }
  }, [onParameterChange]);

  return (
    <div data-ts-indicator-settings="" style={panelStyle}>
      {/* Header */}
      <div style={headerStyle}>
        <span style={headerTitleStyle}>{indicatorName}</span>
      </div>

      {/* Tab bar */}
      <Tabs defaultValue="inputs">
        <div style={tabBarStyle}>
          <Tabs.List>
            <Tabs.Trigger value="inputs">Inputs</Tabs.Trigger>
            <Tabs.Trigger value="style">Style</Tabs.Trigger>
            <Tabs.Trigger value="visibility">Visibility</Tabs.Trigger>
          </Tabs.List>
        </div>

        {/* Inputs tab */}
        <Tabs.Content value="inputs">
          <div style={contentStyle}>
            {parameters.map((param) => (
              <div
                key={param.id}
                style={formRowStyle}
                data-ts-indicator-settings-row=""
              >
                <span style={formLabelStyle}>{param.label}</span>
                {renderParameterControl(param)}
              </div>
            ))}
          </div>
        </Tabs.Content>

        {/* Style tab */}
        <Tabs.Content value="style">
          <div style={contentStyle}>
            {styles.map((s) => (
              <div key={s.id} style={styleRowStyle} data-ts-indicator-settings-row="">
                <Checkbox
                  checked={s.visible}
                  onCheckedChange={(v) => onStyleChange(s.id, 'visible', v as boolean)}
                />
                <span style={styleLabelStyle}>{s.label}</span>
                <ColorPicker
                  value={s.color}
                  onValueChange={(v) => onStyleChange(s.id, 'color', v)}
                  side="left"
                />
                {s.lineWidth !== undefined && (
                  <LineWidthPicker
                    value={s.lineWidth}
                    onValueChange={(v) => onStyleChange(s.id, 'lineWidth', v)}
                  />
                )}
                {s.lineStyle !== undefined && (
                  <LineStylePicker
                    value={s.lineStyle}
                    onValueChange={(v) => onStyleChange(s.id, 'lineStyle', v)}
                  />
                )}
                {s.plotType !== undefined && (
                  <div style={{ minWidth: 90 }}>
                    <Select
                      options={PLOT_TYPE_OPTIONS}
                      value={s.plotType}
                      onValueChange={(v) => onStyleChange(s.id, 'plotType', v)}
                      size="sm"
                      label="Plot type"
                    />
                  </div>
                )}
              </div>
            ))}
          </div>
        </Tabs.Content>

        {/* Visibility tab */}
        <Tabs.Content value="visibility">
          <div style={contentStyle}>
            {visibility.map((vis, i) => (
              <div key={vis.label} style={visibilityRowStyle} data-ts-indicator-settings-row="">
                <Checkbox
                  checked={vis.visible}
                  onCheckedChange={(v) => onVisibilityChange(i, v as boolean)}
                  label={vis.label}
                />
              </div>
            ))}
          </div>
        </Tabs.Content>
      </Tabs>

      {/* Footer */}
      <div style={footerStyle}>
        {onReset ? (
          <Button variant="ghost" size="sm" onClick={onReset} style={resetButtonStyle}>
            Reset
          </Button>
        ) : null}
        <Button variant="secondary" size="sm" onClick={onCancel}>
          Cancel
        </Button>
        <Button variant="primary" size="sm" onClick={onApply}>
          Apply
        </Button>
      </div>
    </div>
  );
}

IndicatorSettingsPanel.displayName = 'IndicatorSettingsPanel';
