import type { CSSProperties } from 'react';
import { formatPrice } from '../financial/format-number';

/* -------------------------------------------------------------------------- */
/*  SpreadDisplay                                                              */
/*  Shows mid-price, spread value, spread %, and optional bid/ask imbalance.   */
/*  Uses --ts-spread-* and --ts-depth-* tokens.                                */
/* -------------------------------------------------------------------------- */

export interface SpreadDisplayProps {
  /** Current bid price (highest buy order). */
  bidPrice: number;
  /** Current ask price (lowest sell order). */
  askPrice: number;
  /** Price decimal precision. */
  precision?: number;
  /** Total bid volume in visible book. */
  bidVolume?: number;
  /** Total ask volume in visible book. */
  askVolume?: number;
  /** Whether to show the imbalance indicator bar. */
  showImbalance?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const SPREAD_STYLE_ID = 'ts-spread-display-styles';

function ensureSpreadDisplayStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(SPREAD_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = SPREAD_STYLE_ID;
  sheet.textContent = `
    [data-ts-spread-display] {
      font-variant-numeric: tabular-nums;
    }
    [data-ts-spread-display] [data-ts-spread-value] {
      transition: color 0.2s ease-out;
    }
    [data-ts-spread-display] [data-ts-imbalance-bar] > div {
      transition: width 0.3s ease-out;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureSpreadDisplayStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rootStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  gap: 'var(--ts-space-3)',
  height: 'var(--ts-spread-height)',
  background: 'var(--ts-spread-bg)',
  padding: '0 var(--ts-space-2)',
  fontVariantNumeric: 'tabular-nums',
  boxSizing: 'border-box',
};

const midPriceStyle: CSSProperties = {
  color: 'var(--ts-depth-mid-price-text)',
  fontSize: 'var(--ts-spread-mid-font-size)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  fontFamily: 'var(--ts-font-data)',
};

const spreadValueStyle: CSSProperties = {
  color: 'var(--ts-depth-spread-text)',
  fontSize: 'var(--ts-spread-value-font-size)',
  fontFamily: 'var(--ts-font-data)',
};

const imbalanceContainerStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: '2px',
  width: '100%',
  padding: '0 var(--ts-space-2)',
  boxSizing: 'border-box',
};

const imbalanceBarStyle: CSSProperties = {
  display: 'flex',
  width: '100%',
  height: 'var(--ts-spread-imbalance-height)',
  borderRadius: '2px',
  overflow: 'hidden',
};

const imbalanceLabelStyle: CSSProperties = {
  display: 'flex',
  justifyContent: 'center',
  fontSize: 'var(--ts-spread-value-font-size)',
  color: 'var(--ts-text-tertiary)',
  fontFamily: 'var(--ts-font-data)',
  fontVariantNumeric: 'tabular-nums',
};

/* ----- Component --------------------------------------------------------- */

const awaitingStyle: CSSProperties = {
  color: 'var(--ts-text-tertiary)',
  fontSize: 'var(--ts-spread-value-font-size)',
  fontFamily: 'var(--ts-font-data)',
  fontStyle: 'italic',
};

export function SpreadDisplay({
  bidPrice,
  askPrice,
  precision = 2,
  bidVolume,
  askVolume,
  showImbalance = false,
}: SpreadDisplayProps): React.JSX.Element {
  const hasBothPrices = bidPrice > 0 && askPrice > 0;
  const hasAnyPrice = bidPrice > 0 || askPrice > 0;

  // Show best available data — don't flash "Awaiting" when one side is temporarily empty
  const midPrice = hasBothPrices
    ? (bidPrice + askPrice) / 2
    : bidPrice > 0 ? bidPrice : askPrice > 0 ? askPrice : 0;
  const spread = hasBothPrices ? askPrice - bidPrice : 0;
  const spreadPercent = hasBothPrices && midPrice > 0 ? (spread / midPrice) * 100 : 0;

  const hasBothVolumes =
    hasBothPrices &&
    bidVolume !== undefined &&
    askVolume !== undefined &&
    bidVolume + askVolume > 0;
  const bidProportion = hasBothVolumes
    ? (bidVolume as number) / ((bidVolume as number) + (askVolume as number))
    : 0.5;

  const bidRatio = hasBothVolumes
    ? (bidVolume as number) / (askVolume as number)
    : 1;
  const ratioLabel =
    bidRatio >= 1
      ? `${bidRatio.toFixed(2)} : 1`
      : `1 : ${(1 / bidRatio).toFixed(2)}`;

  return (
    <div data-ts-spread-display="" data-testid="spread-display">
      <div style={rootStyle}>
        {hasAnyPrice ? (
          <>
            <span style={midPriceStyle} data-testid="spread-mid-price" data-ts-spread-value="">
              {formatPrice(midPrice, precision)}
            </span>
            <span style={spreadValueStyle} data-testid="spread-value" data-ts-spread-value="">
              {formatPrice(spread, precision)}
            </span>
            <span style={spreadValueStyle} data-testid="spread-percent" data-ts-spread-value="">
              {spreadPercent.toFixed(3)}%
            </span>
          </>
        ) : (
          <span style={awaitingStyle} data-testid="spread-awaiting">
            Awaiting data
          </span>
        )}
      </div>
      {showImbalance && hasBothVolumes && (
        <div style={imbalanceContainerStyle} data-testid="imbalance-section">
          <div data-ts-imbalance-bar="" style={imbalanceBarStyle}>
            <div
              style={{
                width: `${(bidProportion * 100).toFixed(2)}%`,
                background: 'var(--ts-depth-bid-bar)',
                opacity: 0.7,
              }}
              data-testid="imbalance-bid"
            />
            <div
              style={{
                width: `${((1 - bidProportion) * 100).toFixed(2)}%`,
                background: 'var(--ts-depth-ask-bar)',
                opacity: 0.7,
              }}
              data-testid="imbalance-ask"
            />
          </div>
          <span style={imbalanceLabelStyle} data-testid="imbalance-ratio">
            {ratioLabel}
          </span>
        </div>
      )}
    </div>
  );
}

SpreadDisplay.displayName = 'SpreadDisplay';
