import type { CSSProperties } from 'react';
import { Badge } from '../../primitives';

/* -------------------------------------------------------------------------- */
/*  AlertStatusBadge                                                          */
/*  Status indicator for alerts: active (green), triggered (amber),           */
/*  expired (gray), disabled (faded gray). Composes Phase 0 Badge.            */
/*  Uses --ts-status-* tokens.                                                */
/* -------------------------------------------------------------------------- */

export type AlertBadgeStatus = 'active' | 'triggered' | 'expired' | 'disabled';

export interface AlertStatusBadgeProps {
  /** Alert status to display. */
  status: AlertBadgeStatus;
  /** Whether to show the text label alongside the dot. Default true. */
  showLabel?: boolean;
  /** Size variant. Default 'default'. */
  size?: 'sm' | 'default';
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-alert-status-badge-styles';

function ensureAlertStatusBadgeStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    @keyframes ts-alert-dot-pulse {
      0%, 100% { opacity: 1; }
      50% { opacity: 0.5; }
    }
    [data-ts-alert-status-badge][data-status="active"] [data-ts-alert-dot] {
      animation: ts-alert-dot-pulse 2s ease-in-out infinite;
    }
    @media (prefers-reduced-motion: reduce) {
      [data-ts-alert-status-badge][data-status="active"] [data-ts-alert-dot] {
        animation: none;
      }
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureAlertStatusBadgeStyles();
}

/* ----- Status config ----------------------------------------------------- */

const STATUS_CONFIG: Record<AlertBadgeStatus, { color: string; label: string; variant: 'success' | 'warning' | 'default' }> = {
  active: { color: 'var(--ts-status-success)', label: 'Active', variant: 'success' },
  triggered: { color: 'var(--ts-status-warning)', label: 'Triggered', variant: 'warning' },
  expired: { color: 'var(--ts-text-tertiary)', label: 'Expired', variant: 'default' },
  disabled: { color: 'var(--ts-text-tertiary)', label: 'Disabled', variant: 'default' },
};

const SIZE_MAP = {
  sm: { dot: 6, fontSize: 'var(--ts-font-xs)' },
  default: { dot: 8, fontSize: 'var(--ts-font-sm)' },
} as const;

/* ----- Styles ------------------------------------------------------------ */

const wrapperStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
};

const labelStyle: CSSProperties = {
  fontFamily: 'inherit',
  lineHeight: 1,
};

/* ----- Component --------------------------------------------------------- */

export function AlertStatusBadge({
  status,
  showLabel = true,
  size = 'default',
}: AlertStatusBadgeProps): React.JSX.Element {
  const config = STATUS_CONFIG[status];
  const sizeConfig = SIZE_MAP[size];
  const isDisabled = status === 'disabled';

  const dotStyle: CSSProperties = {
    width: sizeConfig.dot,
    height: sizeConfig.dot,
    borderRadius: '50%',
    background: config.color,
    flexShrink: 0,
    opacity: isDisabled ? 0.5 : 1,
  };

  if (!showLabel) {
    return (
      <span
        data-ts-alert-status-badge=""
        data-status={status}
        style={wrapperStyle}
        aria-label={config.label}
        role="status"
      >
        <span data-ts-alert-dot="" style={dotStyle} aria-hidden="true" />
      </span>
    );
  }

  return (
    <span
      data-ts-alert-status-badge=""
      data-status={status}
      style={wrapperStyle}
      aria-label={config.label}
      role="status"
    >
      <Badge variant={config.variant}>
        <span style={{ display: 'inline-flex', alignItems: 'center', gap: 'var(--ts-space-1)' }}>
          <span data-ts-alert-dot="" style={dotStyle} aria-hidden="true" />
          <span style={{ ...labelStyle, fontSize: sizeConfig.fontSize }}>{config.label}</span>
        </span>
      </Badge>
    </span>
  );
}

AlertStatusBadge.displayName = 'AlertStatusBadge';
