import { forwardRef, useCallback, type CSSProperties } from 'react';
import { Pencil } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  StayInDrawingMode                                                         */
/*  Toggle button for persistent drawing mode on the chart toolbar.           */
/*  Uses --ts-button-ghost-*, --ts-accent-* tokens.                           */
/* -------------------------------------------------------------------------- */

export interface StayInDrawingModeProps {
  /** Whether stay-in-drawing-mode is enabled. */
  enabled: boolean;
  /** Called when the toggle changes. */
  onEnabledChange: (enabled: boolean) => void;
}

/* ----- Style injection for hover/focus states ----------------------------- */

const STAY_DRAWING_STYLE_ID = 'ts-stay-in-drawing-styles';

function ensureStayInDrawingModeStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STAY_DRAWING_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STAY_DRAWING_STYLE_ID;
  sheet.textContent = `
    [data-ts-stay-in-drawing]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-stay-in-drawing]:not([data-active]):hover {
      background: var(--ts-button-ghost-bg-hover);
      color: var(--ts-button-ghost-text-hover);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureStayInDrawingModeStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const baseStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-icon-button-size-sm)',
  height: 'var(--ts-icon-button-size-sm)',
  borderRadius: 'var(--ts-button-radius)',
  cursor: 'pointer',
  flexShrink: 0,
  boxSizing: 'border-box',
  transition: 'background 150ms, color 150ms',
};

function getStyle(isActive: boolean): CSSProperties {
  return {
    ...baseStyle,
    background: isActive ? 'var(--ts-accent-subtle)' : 'var(--ts-button-ghost-bg)',
    color: isActive ? 'var(--ts-accent-default)' : 'var(--ts-button-ghost-text)',
    border: '1px solid var(--ts-button-ghost-border)',
  };
}

const LABEL = 'Stay in drawing mode';

export const StayInDrawingMode = forwardRef<HTMLButtonElement, StayInDrawingModeProps>(
  function StayInDrawingMode({ enabled, onEnabledChange }, ref) {
    const handleClick = useCallback(() => {
      onEnabledChange(!enabled);
    }, [enabled, onEnabledChange]);

    return (
      <button
        ref={ref}
        type="button"
        data-ts-stay-in-drawing=""
        {...(enabled ? { 'data-active': '' } : {})}
        style={getStyle(enabled)}
        aria-label={LABEL}
        aria-pressed={enabled}
        title={LABEL}
        onClick={handleClick}
      >
        <Pencil size={16} />
      </button>
    );
  },
);

StayInDrawingMode.displayName = 'StayInDrawingMode';
